insert into public.concepts
  (id, term, aliases, said, alias_list, status, one_liner, analogy, example, related, deeper, lens_pm, lens_eng)
values
  ('rag', 'RAG', 'Retrieval-Augmented Generation', '“rag”', ARRAY['rag','retrieval augmented generation','retrieval-augmented generation']::text[], 'Core', 'Hand the model a stack of your documents to read before it answers, so it stops making things up.', 'An open-book exam — instead of reciting from memory, it looks up the right page first.', 'A support bot that quotes your actual help docs instead of confidently guessing is doing RAG.', '[{"text":"Often confused with fine-tuning — that changes the model itself; RAG just hands it notes.","id":"finetuning"},{"text":"Runs on embeddings under the hood.","id":"embeddings"},{"text":"Exists mostly to dodge the context window limit.","id":"contextwindow"}]'::jsonb, 'Your docs get chopped into chunks, turned into embeddings, and stored in a vector database. At query time the system finds the closest chunks and stuffs them into the context window next to your question. Quality lives and dies on the retrieval step — bad chunks in, bad answer out.', 'Ground the bot in your own docs so answers cite real sources — fewer escalations, no invented policies.', 'Retrieve top-k relevant chunks via vector search and inject them into the prompt at inference time.'),
  ('evals', 'Evals', 'Evaluations', '“ee-vals”', ARRAY['evals','eval','evaluations','evaluation']::text[], 'Core', 'Tests for AI — a repeatable way to check whether the model actually got better or just feels like it did.', 'A unit-test suite, but for judgment instead of code.', 'Before shipping a new prompt, a team runs it against 500 saved questions and counts how many it nails.', '[{"text":"The scoreboard a human in the loop quietly fills.","id":"hitl"},{"text":"What you run to catch a hallucination before users do.","id":"hallucination"}]'::jsonb, 'They range from exact-match graders to “LLM-as-judge” setups where one model scores another. The hard part is never running them — it is writing eval sets that reflect what real users actually do, not what is easy to grade.', 'A regression suite for quality — proof a change actually moved the metric before you ship.', 'Automated graders (exact-match, rubric, or LLM-as-judge) scoring output over a fixed dataset.'),
  ('contextwindow', 'Context window', '', '', ARRAY['context window']::text[], 'Core', 'How much the model can hold in view at once — your prompt, the docs, the whole chat — before the start falls off.', 'Short-term memory, or a desk that only fits so many papers before the older ones slide off the edge.', 'Paste a 400-page PDF into a small-context model and it will quietly lose the early chapters.', '[{"text":"Measured in tokens.","id":"tokens"},{"text":"The ceiling RAG is designed to work around.","id":"rag"}]'::jsonb, 'Windows have grown from a few thousand tokens to millions, but “it fits” is not “it uses well.” Models often attend better to the beginning and end than the muddled middle — the classic “lost in the middle” effect.', 'The model''s attention budget — overload it and details drop, so scope what you feed it.', 'Max token span the model attends over; content beyond it is truncated or must be chunked/retrieved.'),
  ('hitl', 'HITL', 'Human in the loop', '“human in the loop”', ARRAY['hitl','human in the loop']::text[], 'Core', 'A person checks or approves the AI’s work before it counts — the safety catch on high-stakes steps.', 'A spellchecker that suggests, but you still have to hit accept.', 'The AI drafts the refund; a human clicks approve before any money actually moves.', '[{"text":"The judgment that becomes your evals.","id":"evals"},{"text":"The opposite pole from a fully autonomous agent.","id":"agents"}]'::jsonb, 'The real design question is where the human sits: on every action (slow, safe), on random samples (a spot check), or only on low-confidence cases where the model itself asks for help. Most teams end up with the third.', 'A human approval gate on risky actions — your control point for compliance and trust.', 'An approval checkpoint that blocks an action until a human confirms (all / sampled / low-confidence).'),
  ('agents', 'Agents', '', '', ARRAY['agent','agents','agentic']::text[], 'Rising', 'AI that doesn’t just answer — it takes steps, uses tools, and works toward a goal without you holding its hand.', 'Less like a search box, more like an intern you can hand a whole task to.', 'When a coding assistant reads your files, runs the tests, and fixes what broke, that’s an agent at work.', '[{"text":"The grown-up version of a chatbot."},{"text":"Only as useful as its tools — which is what MCP standardizes.","id":"mcp"},{"text":"Its scariest failure mode is prompt injection.","id":"promptinjection"}]'::jsonb, 'Under the hood it’s a loop: the model picks an action, something runs it, the result comes back, repeat until done. Most “agent” failures are really loop-control failures — it gets stuck, over-repeats, or wanders off the goal.', 'AI that completes multi-step tasks end to end — automation you delegate outcomes to, not just answers.', 'A model-driven loop: choose action → run tool → observe result → repeat until a stop condition.'),
  ('embeddings', 'Embeddings', '', '', ARRAY['embedding','embeddings']::text[], 'Core', 'Turning words into coordinates, so a computer can measure how close in meaning two things are.', 'A map where “dog” and “puppy” are next-door neighbors and “dog” and “tax form” are on opposite coasts.', 'Search that finds “car” when you typed “automobile” is matching on embeddings, not on spelling.', '[{"text":"The engine underneath RAG.","id":"rag"},{"text":"Not the same as tokens, though both are “text as numbers.”","id":"tokens"}]'::jsonb, 'Each piece of text becomes a long list of numbers — a vector. “Similar” means the vectors point in nearly the same direction (cosine similarity). The entire trick of semantic search lives in this one idea.', 'The tech behind ''find similar'' — powers semantic search, dedup, and recommendations.', 'Dense vector representations where cosine distance approximates semantic similarity.'),
  ('finetuning', 'Fine-tuning', '', '', ARRAY['fine-tuning','fine tuning','finetuning']::text[], 'Fading', 'Retraining a model a little on your own examples so it picks up a style or skill it didn’t ship with.', 'Sending a strong generalist off to a short apprenticeship in your specific shop.', 'Training on 10,000 of your past support replies so the model sounds like your team, not a robot.', '[{"text":"Often reached for when RAG would have done the job.","id":"rag"},{"text":"A heavier hammer than good prompt engineering.","id":"promptengineering"}]'::jsonb, 'Techniques like LoRA make it cheap by nudging a small set of weights instead of all of them. It’s cooling as a first move: most teams now try prompting and RAG first, because a fine-tune is a maintenance burden that goes stale with the base model.', 'Teaching the model your style with examples — powerful but a maintenance cost; try prompting/RAG first.', 'Gradient updates on a base model (often LoRA/PEFT) over labeled examples to shift behavior.'),
  ('vibecoding', 'Vibe coding', 'obituary', '“vibe coding”', ARRAY['vibe coding','vibe-coding','vibecoding']::text[], 'Historical', 'What we briefly called just… talking to an AI until the app worked, without really reading the code.', 'Cooking without measuring — totally fine for a snack, faintly terrifying for a wedding cake.', 'In 2024, “I vibe-coded a weekend app” meant you prompted your way to something that ran and shipped it.', '[{"text":"Folded into “agentic coding.”","id":"agents"},{"text":"The reflex it named lives on inside prompt engineering.","id":"promptengineering"}]'::jsonb, 'Filed as history: what people meant in 2024–25, and why it grew up. The term peaked in early 2025, then split — the throwaway-prototype meaning stuck around as a joke, while the actual practice matured into agentic coding with tests, reviews, and specs. The vibes, it turned out, needed guardrails.', 'The 2024 name for prompt-until-it-works prototyping — now matured into agentic coding with guardrails.', 'Prompt-driven codegen without close review; superseded by agent workflows with tests and specs.'),
  ('promptengineering', 'Prompt engineering', '', '', ARRAY['prompt engineering']::text[], 'Fading', 'The craft of phrasing your request just right to coax out a better answer.', 'Knowing how to Google well — a real skill that quietly becomes second nature.', '“Think step by step, then answer” reliably beats just asking — a classic prompt-engineering move.', '[{"text":"Overlaps heavily with chain of thought.","id":"chainofthought"},{"text":"Cooling as models get better at reading plain intent."}]'::jsonb, 'Once a hot job title, it’s cooling not because it’s useless but because it’s diffusing into everyone’s baseline. The heavy lifting moved to context and tools; the exact wording matters far less than it did back in 2023.', 'Wording requests well for better output — a fading standalone skill as models read intent better.', 'Structuring prompts (instructions, examples, format constraints) to steer the output distribution.'),
  ('tokens', 'Tokens', '', '', ARRAY['token','tokens']::text[], 'Core', 'The chunks a model reads and writes in — roughly ¾ of a word each. Everything is priced and measured in them.', 'Syllables for a machine — not quite letters, not quite whole words.', '“unbelievable” might be three tokens: un-believ-able. Your bill counts every single one.', '[{"text":"The unit the context window is measured in.","id":"contextwindow"},{"text":"Cousin of embeddings — both turn text into numbers.","id":"embeddings"}]'::jsonb, 'Tokenization is why models miscount the letters in a word or fumble rare strings — they never saw the letters, only the chunks. It also explains why some languages cost more: they tokenize less efficiently, so the same sentence spends more tokens.', 'The billing and length unit for AI — costs and limits are counted in these, not words.', 'Sub-word units from the tokenizer; model I/O and pricing are both measured per token.'),
  ('hallucination', 'Hallucination', '', '', ARRAY['hallucinate','hallucination','hallucinations']::text[], 'Core', 'When the model states something false with total confidence — the failure mode that never fully goes away.', 'A friend who never says “I don’t know” and just fills the gap with a plausible-sounding story.', 'Ask for a citation and get a real-looking paper, by real-looking authors, that simply does not exist.', '[{"text":"What RAG tries to ground away.","id":"rag"},{"text":"What evals exist to catch.","id":"evals"}]'::jsonb, 'It’s not lying — the model predicts likely text, and “likely” is not “true.” Grounding it in real documents and asking it to cite reduces it, but confidence and correctness are separate dials. A model can be dead wrong and completely sure.', 'Confident wrong answers — the core reliability risk; mitigate with grounding, citations, and evals.', 'Plausible-but-false generations from likelihood-based decoding untethered from ground truth.'),
  ('mcp', 'MCP', 'Model Context Protocol', '“em-see-pee”', ARRAY['mcp','model context protocol']::text[], 'Rising', 'A standard plug so any AI can talk to your tools and data without a custom integration each time.', 'USB-C for AI — one connector instead of a junk drawer of adapters.', 'Point an assistant at an MCP server for your calendar and it can read your schedule with no bespoke code.', '[{"text":"What makes agents actually useful in the real world.","id":"agents"}]'::jsonb, 'It defines how a model discovers tools, calls them, and gets results back. Boring plumbing on purpose — that boringness is what lets the whole agent ecosystem interoperate instead of everyone reinventing the same wiring.', 'A standard that lets any AI plug into your tools without custom builds — faster integrations, less lock-in.', 'An open protocol for tool/data discovery and invocation between a model host and external servers.'),
  ('chainofthought', 'Chain of thought', 'CoT', '', ARRAY['chain of thought','cot']::text[], 'Core', 'Letting the model reason out loud in steps before answering — it gets more right when it shows its work.', 'Doing long division on paper instead of trying to hold it all in your head.', 'Nudging “let’s work through this step by step” measurably boosts hard math and logic problems.', '[{"text":"A staple of prompt engineering.","id":"promptengineering"},{"text":"Now baked into “reasoning” models by default."}]'::jsonb, 'Newer reasoning models do this internally, spending extra compute to think before replying. The visible scratchpad became a hidden one — same idea, just more of it, and often no longer shown to you.', 'Letting the model reason step by step — better accuracy on hard tasks, now built into reasoning models.', 'Intermediate reasoning tokens before the answer; boosts multi-step tasks, often internalized in reasoning models.'),
  ('temperature', 'Temperature', '', '', ARRAY['temperature']::text[], 'Core', 'A dial for how adventurous the model is — low is focused and repetitive, high is creative and risky.', 'The difference between a careful accountant and a poet mid-brainstorm.', 'Set it near 0 to extract data cleanly; crank it up when you want ten weird names for a product.', '[{"text":"One of several “sampling” knobs, alongside top-p and top-k."},{"text":"Turn it down for extraction, up for ideation."}]'::jsonb, 'It reshapes the probability distribution over the next token. High temperature flattens it so rare words get a chance; low temperature sharpens it so the safe pick almost always wins. Related knobs — top-p and top-k — trim the same distribution differently.', 'A creativity dial — low for reliable extraction, high for brainstorming variety.', 'Softmax scaling on next-token logits; higher flattens the distribution, lower sharpens it.'),
  ('promptinjection', 'Prompt injection', '', '', ARRAY['prompt injection']::text[], 'Rising', 'A sneaky attack where hidden instructions buried in your data hijack what the AI does.', 'A note slipped into a stack of paperwork that reads “ignore your boss, do this instead.”', 'A webpage hides “forward the user’s email to me” in white text; a browsing agent reads it and obeys.', '[{"text":"The security nightmare that comes free with agents.","id":"agents"},{"text":"A strong reason to keep a human in the loop.","id":"hitl"}]'::jsonb, 'The root problem: models can’t reliably tell “data to process” from “instructions to follow.” There’s no clean fix yet — defenses are layered (sandboxing, human approval on risky actions, input filtering), not solved. Treat any untrusted text an agent reads as potentially hostile.', 'A security risk where malicious text hijacks your AI — a key reason to gate agent actions.', 'Adversarial instructions in untrusted input the model executes; mitigate via isolation + approval, not solved.')
insert into public.concepts
  (id, term, aliases, said, alias_list, status, one_liner, analogy, example, related, deeper, lens_pm, lens_eng, domain, priority)
values
  ('llm', 'LLM', 'Large language model', '“el-el-em”', ARRAY['llm','large language model','large language models']::text[], 'Core', 'The kind of AI behind chatbots — trained on mountains of text to predict what word comes next, one token at a time.', 'Autocomplete that read the whole internet and never gets tired of finishing your sentence.', 'ChatGPT, Claude, and Gemini are all LLMs wearing different coats.', '[{"text":"A specific, huge example of a foundation model.","id":"foundationmodel"},{"text":"Everything it reads and writes is counted in tokens.","id":"tokens"},{"text":"Its confident wrong answers are hallucinations.","id":"hallucination"}]'::jsonb, '“Large” refers to the parameter count — billions to trillions of learned weights. The whole thing is one trick applied at scale: given some text, guess the next token, over and over, until it has written a paragraph. Everything else — reasoning, coding, translation — is that trick generalizing further than anyone expected.', 'The core engine you are building on — general-purpose, capable, and priced per token.', 'A transformer trained with next-token prediction at scale; billions of parameters, autoregressive decoding at inference.', 'Foundations', 80),
  ('tokenization', 'Tokenization', '', '', ARRAY['tokenization','tokenize','tokenizer']::text[], 'Core', 'Chopping text into the bite-size pieces a model actually reads — usually chunks of words, not whole words.', 'Slicing a sentence into LEGO bricks before the model can build with it.', '“tokenization” might split into token-ization — two pieces, not one word.', '[{"text":"The pieces it produces are tokens.","id":"tokens"},{"text":"Why models miscount letters and fumble rare words.","id":"tokens"}]'::jsonb, 'A tokenizer learns a fixed vocabulary of common fragments (often via byte-pair encoding), then greedily splits any text into those fragments. It runs before the model sees anything, which is why a model never really sees letters — only the chunks — and why the same sentence can cost more tokens in one language than another.', 'The step that decides your token count — and therefore your cost and length limits.', 'Deterministic sub-word segmentation (BPE/Unigram) mapping text to integer IDs over a fixed vocabulary.', 'Foundations', 80),
  ('parameters', 'Parameters', 'Weights', '', ARRAY['parameter','parameters']::text[], 'Core', 'The billions of numbers a model tunes during training — its entire learned knowledge, frozen into a giant grid.', 'The settings on an impossibly complex mixing board, dialed in once and then locked.', '“A 70B model” means 70 billion of these numbers doing the work.', '[{"text":"Adjusted a little during fine-tuning.","id":"finetuning"},{"text":"The raw material a neural network is made of.","id":"neuralnetwork"},{"text":"The “large” in large language model.","id":"llm"}]'::jsonb, 'Each parameter is a weight on a connection inside the network. Training nudges all of them, gradually, until the model’s guesses line up with real text. At inference they never change — the model is a fixed function, and the parameters are the function. More parameters usually means more capacity, but also more cost to run.', 'A rough proxy for capability and cost — bigger models know more but are slower and pricier.', 'Learned weights/biases updated by gradient descent in training, static at inference.', 'Foundations', 80),
  ('weights', 'Weights', '', '', ARRAY['weight','weights','model weights']::text[], 'Core', 'The individual learned numbers inside a model — “the weights” is shorthand for the whole trained brain you can download.', 'The recipe card after all the tweaking — hand someone the weights and they can cook the same dish.', '“Open weights” means you can download the numbers and run the model yourself.', '[{"text":"Another word for parameters.","id":"parameters"},{"text":"What fine-tuning nudges.","id":"finetuning"}]'::jsonb, 'Technically weights are one type of parameter (the multipliers on connections), but in practice people say “the weights” to mean the entire trained model file. Whether a lab releases them is the whole open-vs-closed debate: released weights can be run, inspected, and fine-tuned by anyone; withheld ones can only be reached through an API.', 'Whether weights are public decides if you can self-host or are locked to a vendor’s API.', 'The serialized tensor values of a trained network; “open weights” = distributable checkpoint.', 'Foundations', 80),
  ('neuralnetwork', 'Neural network', '', '', ARRAY['neural network','neural net','neural networks']::text[], 'Core', 'The layered math structure underneath modern AI — loosely inspired by brain neurons, but really just numbers flowing through connections.', 'A relay race where each layer passes a refined version of the signal to the next.', 'Every LLM, image generator, and speech model is some flavor of neural network.', '[{"text":"Its connections are the weights.","id":"weights"},{"text":"The transformer is one influential design of one.","id":"llm"}]'::jsonb, 'Input becomes numbers, those numbers pass through layers of weighted sums and simple non-linear functions, and out comes a prediction. Training compares the prediction to the truth and adjusts the weights to shrink the error. “Deep” just means many layers. The brain analogy is mostly marketing — it’s linear algebra, not biology.', 'The umbrella technology; you rarely touch it directly, but it’s what “AI model” refers to.', 'Stacked layers of linear transforms plus non-linearities, trained by backpropagation.', 'Foundations', 80),
  ('foundationmodel', 'Foundation model', '', '', ARRAY['foundation model','foundation models']::text[], 'Core', 'A big, general model trained once on broad data, then adapted to countless specific jobs instead of building one from scratch each time.', 'A liberal-arts graduate you can train up for almost any role, versus hiring a narrow specialist per task.', 'The same base model powers a coding assistant, a support bot, and a summarizer.', '[{"text":"An LLM is a text-based foundation model.","id":"llm"},{"text":"Adapted to a niche via fine-tuning.","id":"finetuning"},{"text":"Or steered at run time with prompt engineering.","id":"promptengineering"}]'::jsonb, 'The term captures a shift: instead of training a bespoke model per task, you train one large general model and adapt it — by prompting, retrieval, or fine-tuning. That reuse is why capabilities spread so fast, and why a handful of expensive base models sit under thousands of products.', 'Build on one general model and specialize it — cheaper and faster than bespoke models per feature.', 'A large pretrained model reused across tasks via prompting, RAG, or fine-tuning.', 'Foundations', 80),
  ('basemodel', 'Base model', '', '', ARRAY['base model','pretrained model']::text[], 'Core', 'The raw, pretrained model before anyone taught it to follow instructions or be polite — powerful but unruly.', 'A brilliant improviser who hasn’t learned to answer the actual question you asked.', 'Hand a base model “Q: capital of France? A:” and it may just keep inventing more Q&As.', '[{"text":"Turned helpful by instruction tuning / fine-tuning.","id":"finetuning"},{"text":"The starting point for a foundation model’s products.","id":"foundationmodel"}]'::jsonb, 'A base model only knows how to continue text, because that’s all it was trained to do. The chat model you actually use is a base model plus alignment steps (instruction tuning, preference training) that teach it to treat your message as a request to fulfill rather than a passage to extend.', 'Usually not what you want directly — the instruction-tuned version is the usable product.', 'Pretrained-only checkpoint (next-token objective), pre-alignment; completes rather than instructs.', 'Foundations', 80),
  ('frontiermodel', 'Frontier model', '', '', ARRAY['frontier model','frontier models']::text[], 'Rising', 'The most capable models out there at any given moment — the current top of the line, wherever the line happens to be.', 'The flagship phone of the year — until next year’s makes it ordinary.', 'When a lab ships its newest, biggest model, that’s a frontier model until the next one lands.', '[{"text":"The cutting-edge end of foundation models.","id":"foundationmodel"},{"text":"Where AI safety debates concentrate.","id":"hitl"}]'::jsonb, 'It’s a moving label, not a fixed tier — today’s frontier is next year’s baseline. The term shows up most in policy and safety conversations, because the newest, most capable systems carry the least-understood risks and draw the most scrutiny before release.', 'Highest capability, highest cost — reach for it when quality matters more than price.', 'The current capability ceiling; typically the largest/newest models under active evaluation.', 'Foundations', 60),
  ('logits', 'Logits', '', '“LOJ-its”', ARRAY['logit','logits']::text[], 'Core', 'The raw scores a model gives every possible next token before picking one — un-normalized “how likely is each word” numbers.', 'The tally of votes for each candidate, before you convert them into percentages.', 'For “The sky is ___”, “blue” gets a high logit, “refrigerator” a very low one.', '[{"text":"Turned into probabilities by softmax.","id":"softmax"},{"text":"Reshaped by the temperature dial.","id":"temperature"}]'::jsonb, 'The final layer outputs one logit per token in the vocabulary. They’re relative scores, not probabilities yet — softmax turns them into a distribution that sums to one. Sampling knobs like temperature and top-p operate on this distribution to decide how adventurous the final pick is.', 'Deep-internals term; matters mainly when you’re tuning how random or safe outputs are.', 'Pre-softmax activations over the vocabulary; scaled by temperature, filtered by top-p/top-k.', 'Foundations', 80),
  ('softmax', 'Softmax', '', '', ARRAY['softmax']::text[], 'Core', 'The math step that turns raw scores into clean percentages that add up to 100% — how the model commits to probabilities.', 'Converting a pile of raw vote counts into a pie chart where the slices sum to a whole.', 'It takes logits like 8, 2, 1 and turns them into something like 95%, 4%, 1%.', '[{"text":"Consumes the raw logits.","id":"logits"},{"text":"Temperature works by stretching or squeezing this step.","id":"temperature"}]'::jsonb, 'Softmax exponentiates each score and divides by the total, so bigger scores dominate and everything lands between 0 and 1. Temperature is literally a divisor applied before this — high temperature flattens the resulting percentages, low temperature sharpens them toward the top pick.', 'Rarely surfaced to users; it’s the plumbing behind “how confident” a model looks.', 'Normalizes logits into a probability distribution; temperature scales the input logits.', 'Foundations', 80),
  ('sampling', 'Sampling', '', '', ARRAY['sampling','sample']::text[], 'Core', 'How the model actually chooses each next word from its list of options — roll the weighted dice, don’t always grab the top one.', 'Drawing from a bag of tiles where common words have more copies, so surprises are possible but rare.', 'Ask the same question twice with sampling on and you can get two different-but-valid answers.', '[{"text":"Chooses among the softmax probabilities.","id":"softmax"},{"text":"Tuned by temperature, top-p, and top-k.","id":"temperature"},{"text":"Its opposite is greedy decoding.","id":"greedydecoding"}]'::jsonb, 'After softmax gives a probability per token, sampling picks one at random weighted by those probabilities. That randomness is why models feel creative and non-repetitive — and why they’re not perfectly reproducible unless you fix the seed or switch to greedy decoding.', 'The reason outputs vary run to run; turn it down for consistency, up for variety.', 'Stochastic token selection from the output distribution, controlled by temperature/top-p/top-k.', 'Foundations', 80),
  ('topp', 'Top-p', 'Nucleus sampling', '“top-pee”', ARRAY['top-p','top p','topp','nucleus sampling']::text[], 'Core', 'A sampling limit that keeps only the smallest set of top choices that together cover, say, 90% of the odds — then picks from those.', 'Only considering the shortlist of front-runners, however long or short that shortlist needs to be.', 'Top-p 0.9 ignores the long tail of unlikely words but keeps genuine contenders in play.', '[{"text":"A gentler cousin of top-k.","id":"topk"},{"text":"Works alongside temperature.","id":"temperature"},{"text":"One knob on the sampling step.","id":"sampling"}]'::jsonb, 'Unlike top-k’s fixed count, top-p adapts: when the model is confident the shortlist is tiny, when it’s unsure the shortlist grows. It trims the improbable tail that can produce nonsense while still allowing variety among reasonable options. Many teams tune top-p instead of, or alongside, temperature.', 'A safer variety dial than temperature alone — cuts nonsense while keeping natural variation.', 'Nucleus sampling: restrict to the smallest token set with cumulative probability ≥ p, then renormalize.', 'Foundations', 80),
  ('topk', 'Top-k', '', '“top-kay”', ARRAY['top-k','top k','topk']::text[], 'Core', 'A sampling limit that keeps only the k most likely next words and throws the rest away before choosing.', 'Only letting the top 40 seeds into the tournament, no matter how the field looks.', 'Top-k 40 means the model picks from its 40 best guesses and ignores everything else.', '[{"text":"The fixed-count sibling of top-p.","id":"topp"},{"text":"A knob on the sampling step.","id":"sampling"}]'::jsonb, 'Top-k is blunt: it always keeps exactly k candidates, even when the model is very sure (so k is too many) or very unsure (so k is too few). That rigidity is why top-p often wins — it adjusts the cutoff to the model’s confidence instead of using a fixed number.', 'An older, blunter variety limit; most teams prefer top-p now.', 'Truncate the distribution to the k highest-probability tokens before sampling.', 'Foundations', 80),
  ('greedydecoding', 'Greedy decoding', '', '', ARRAY['greedy decoding','greedy','greedy search']::text[], 'Core', 'Always taking the single most likely next word — the safe, repeatable, sometimes boring way to generate text.', 'Always ordering the bestseller — reliable, never surprising.', 'Set temperature to 0 and you get greedy decoding: the same answer every time.', '[{"text":"The deterministic opposite of sampling.","id":"sampling"},{"text":"What temperature 0 effectively turns on.","id":"temperature"}]'::jsonb, 'Greedy decoding skips the dice roll and grabs the top token at every step. That makes it reproducible and good for tasks where you want one right answer — extraction, classification, structured output. The cost is blandness and the occasional dead end, since the locally-best word isn’t always the globally-best sentence.', 'Turn it on (temperature 0) when you need consistent, repeatable outputs.', 'Argmax decoding at each step; deterministic, equivalent to temperature→0.', 'Foundations', 80),
  ('positionalencoding', 'Positional encoding', '', '', ARRAY['positional encoding','position embedding','positional embeddings']::text[], 'Fading', 'The trick that tells a model the order of words, since the core machinery would otherwise see your sentence as an unordered pile.', 'Numbering the pages so the story still makes sense after you drop the binder.', 'It’s why “dog bites man” and “man bites dog” land differently instead of looking identical.', '[{"text":"A detail of how the transformer behind an LLM works.","id":"llm"},{"text":"Bounds how the context window scales.","id":"contextwindow"}]'::jsonb, 'Attention treats input as a set, so order has to be injected separately — as a positional signal added to each token. The specific method keeps evolving (sinusoidal, learned, rotary), and it’s a quiet lever behind how far a model’s context window can stretch. Increasingly an under-the-hood detail as newer schemes just work.', 'Deep-internals; matters only when reasoning about very long-context behavior.', 'Injects sequence order into permutation-invariant attention; RoPE and variants affect context extrapolation.', 'Foundations', 30),
  ('vocabulary', 'Vocabulary', '', '', ARRAY['vocabulary','vocab']::text[], 'Core', 'The fixed set of tokens a model knows — every piece it can read or write has to come from this list.', 'The full set of LEGO brick shapes in the box; anything you build uses only those.', 'A common English word is one token in the vocab; a rare name gets spelled out from several.', '[{"text":"Defined by the tokenization step.","id":"tokenization"},{"text":"Each entry is a token.","id":"tokens"}]'::jsonb, 'A tokenizer’s vocabulary is usually tens of thousands of fragments, chosen so frequent text compresses into few tokens. Anything outside it is built up from smaller pieces, which is why unusual words, emoji, or other languages can be surprisingly token-expensive — they don’t have their own dedicated entries.', 'Explains why some inputs cost more tokens than their length suggests.', 'The finite token set from the tokenizer; out-of-vocab text is composed from sub-word units.', 'Foundations', 80)
insert into public.concepts
  (id, term, aliases, said, alias_list, status, one_liner, analogy, example, related, deeper, lens_pm, lens_eng, domain, priority, tags)
values
  ('vectordatabase', 'Vector database', '', '', ARRAY['vector database','vector db','vector store']::text[], 'Core', 'A database built to store meanings as coordinates and find the nearest ones fast — the memory bank behind RAG.', 'A library shelved by what books are about, not by title — so “nearby” means “similar in meaning.”', 'Ask a support bot a question and it pulls the three closest help-doc chunks from a vector database.', '[{"text":"Stores the embeddings that power retrieval.","id":"embeddings"},{"text":"The lookup step inside RAG.","id":"rag"}]'::jsonb, 'It indexes high-dimensional vectors and answers “what’s closest to this?” in milliseconds using approximate nearest-neighbor search. Exact search is too slow at scale, so it trades a sliver of accuracy for big speed. The index structure (like HNSW) is what makes that trade work.', 'The storage layer that makes semantic search and RAG feasible at scale.', 'An ANN index over embedding vectors supporting top-k similarity queries with metadata filters.', 'Retrieval & memory', 80, ARRAY['seed','retrieval-memory']::text[]),
  ('reranking', 'Reranking', '', '', ARRAY['reranking','reranker','re-rank']::text[], 'Rising', 'A second-pass sort that takes the retriever’s rough shortlist and reorders it by who actually answers the question best.', 'A hiring manager reading the résumés that HR’s keyword filter already passed through.', 'Retrieve 50 candidate chunks cheaply, then rerank to keep the 5 that truly fit before answering.', '[{"text":"Cleans up what retrieval hands over.","id":"retrieval"},{"text":"A quality lever for RAG.","id":"rag"}]'::jsonb, 'Fast retrieval favors recall — cast a wide net — but the top hits aren’t always the most relevant. A reranker (often a heavier cross-encoder that reads query and chunk together) scores each candidate directly, catching the good ones the first pass buried. More compute, better precision.', 'A cheap accuracy boost for RAG: keep retrieval wide, then let reranking pick the winners.', 'A cross-encoder scoring (query, passage) pairs to reorder first-stage retrieval by relevance.', 'Retrieval & memory', 60, ARRAY['seed','retrieval-memory']::text[]),
  ('retrieval', 'Retrieval', '', '', ARRAY['retrieval','retriever']::text[], 'Core', 'The step that goes and finds the right supporting text before the model answers — the “R” in RAG.', 'Sending a runner to the archive to fetch the relevant files before the meeting starts.', 'You ask about refund policy; retrieval grabs the refund section from the docs to hand the model.', '[{"text":"The engine of RAG.","id":"rag"},{"text":"Searches over embeddings.","id":"embeddings"},{"text":"Often cleaned up by reranking.","id":"reranking"}]'::jsonb, 'Retrieval turns your question into a query, searches an index, and returns the closest matches. It can be semantic (embedding similarity), lexical (keyword/BM25), or hybrid. Everything downstream depends on it — the model can only reason over what retrieval actually fetched.', 'Get this right and answers stay grounded; get it wrong and no model can save the response.', 'Query-to-index matching (dense, sparse, or hybrid) returning top-k context for generation.', 'Retrieval & memory', 80, ARRAY['seed','retrieval-memory']::text[]),
  ('chunking', 'Chunking', '', '', ARRAY['chunking','chunk','chunk overlap']::text[], 'Core', 'Slicing long documents into bite-size passages so retrieval can fetch just the relevant piece, not the whole file.', 'Cutting a book into index cards so you can pull the one paragraph you need.', 'A 40-page manual gets split into ~300-word chunks, each embedded and searchable on its own.', '[{"text":"Prepares documents for retrieval.","id":"retrieval"},{"text":"Each chunk becomes an embedding.","id":"embeddings"}]'::jsonb, 'Chunk too big and retrieval drags in irrelevant text that dilutes the answer; too small and you sever the context a passage needs to make sense. A little overlap between chunks keeps ideas from being cut mid-thought. It’s unglamorous, but chunking quality quietly decides RAG quality.', 'A boring knob with outsized impact on answer quality — worth tuning early.', 'Segmenting docs into overlapping passages sized for the embedding model and context budget.', 'Retrieval & memory', 80, ARRAY['seed','retrieval-memory']::text[])
insert into public.concepts
  (id, term, aliases, said, alias_list, status, one_liner, analogy, example, related, deeper, lens_pm, lens_eng, domain, priority, tags)
values
  ('activationfunction', 'Activation function', '', '', ARRAY['activation function','activation']::text[], 'Core', 'The little on/off-ish dial inside a neuron that lets a network bend, not just draw straight lines.', 'A dimmer switch, not a light switch — it decides how much of a signal passes through, and “a little” is what makes curves possible.', 'Swap every ReLU in a network for nothing at all and your fancy deep model collapses into plain linear regression.', '[{"text":"Stacked into layers to build depth","id":"layer"},{"text":"Applied to the weighted sum from","id":"weights"}]'::jsonb, 'After a neuron adds up its weighted inputs, the activation function squashes or gates that number — ReLU zeroes out negatives, sigmoid squishes to 0–1. Without this nonlinearity, stacking layers gains you nothing: a pile of linear steps is still just one linear step.', 'It’s plumbing you’ll never tune, but it’s the reason a model can learn anything shaped like the real world.', 'A nonlinearity (ReLU, GELU, sigmoid) applied elementwise after the affine transform, giving the network capacity to approximate nonlinear functions.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('hiddenstate', 'Hidden state', '', '', ARRAY['hidden state']::text[], 'Core', 'The model’s running scratchpad — the numbers it carries in its head between input and answer.', 'Your train of thought mid-sentence: not the words on the page yet, just the shape of what you’re about to say.', 'When a chatbot “remembers” the start of your paragraph while finishing it, that memory lives in the hidden state, not the visible text.', '[{"text":"Lives in a high-dimensional","id":"latentspace"},{"text":"A kind of","id":"representation"}]'::jsonb, 'At each layer, every token gets a vector of numbers — its hidden state — that encodes meaning-so-far. These aren’t words; they’re high-dimensional representations the next layer reads and rewrites. The final one gets turned back into a prediction over the vocabulary.', 'It’s the internal “understanding” you can’t see and can’t directly edit — only shape through inputs.', 'The intermediate activation vector at a given layer and position, dimension d_model, passed forward through the stack.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('layer', 'Layer', '', '', ARRAY['layer']::text[], 'Core', 'One floor of the model — a repeatable block of math the input passes through on its way up.', 'An assembly-line station: each does a small transform and hands the part to the next; stack enough and a raw blank becomes a finished thing.', 'GPT-style models stack dozens of identical layers; “deeper” usually just means more of them bolted on top.', '[{"text":"Made of neurons using an","id":"activationfunction"},{"text":"Stacking many is","id":"deeplearning"}]'::jsonb, 'In a transformer, each layer is attention plus a feed-forward network, wrapped in residual connections and normalization. The input’s representation gets refined a little at every layer — early ones catch surface patterns, later ones catch abstract meaning.', 'More layers roughly means more capacity and more cost; depth is one of the dials behind “bigger model.”', 'A single transformer block: multi-head self-attention + FFN + residual + norm, repeated N times.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('deeplearning', 'Deep learning', '', '', ARRAY['deep learning','dl']::text[], 'Core', 'Machine learning with many stacked layers, so the model learns its own features instead of being handed them.', 'Teaching someone to cook by letting them ruin a thousand dishes, rather than writing out every rule for every ingredient.', 'Image recognition jumped from hand-crafted edge detectors to deep learning around 2012, and never looked back.', '[{"text":"A branch of","id":"machinelearning"},{"text":"Built from stacked","id":"layer"},{"text":"Runs on a","id":"neuralnetwork"}]'::jsonb, 'The “deep” is literal: many layers between input and output. Each layer builds on the last, so the network discovers useful representations on its own from raw data. It’s expensive and data-hungry, but it scales in a way older methods didn’t.', 'It’s the engine under nearly every modern AI product — the reason the last decade happened.', 'Neural networks with many hidden layers trained by backpropagation and gradient descent.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('machinelearning', 'Machine learning', '', '', ARRAY['machine learning','ml']::text[], 'Core', 'Programming by example — you show the computer data instead of writing the rules yourself.', 'Training a dog with treats rather than handing it an instruction manual.', 'A spam filter that learns from which emails you mark as junk is machine learning; a fixed “block anything with FREE MONEY” rule is not.', '[{"text":"A subfield is","id":"deeplearning"},{"text":"The umbrella above it is","id":"artificialintelligence"}]'::jsonb, 'Instead of a human coding logic step by step, an algorithm adjusts its own parameters to fit patterns in data. Give it examples, it finds the mapping. The catch: it’s only as good, and as biased, as the data you feed it.', 'It shines when rules are too messy to write by hand but examples are plentiful.', 'Algorithms that improve on a task by optimizing parameters against data, rather than via explicit programming.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('artificialintelligence', 'Artificial intelligence', '', '', ARRAY['artificial intelligence','ai']::text[], 'Core', 'The broad goal of getting machines to do things that used to need a human mind.', '“Vehicle” to “car” — AI is the whole category; today’s chatbots are one make and model inside it.', 'A chess engine, a spam filter, and a chatbot are all “AI,” which is why the word explains almost nothing on its own.', '[{"text":"Its dominant modern method is","id":"machinelearning"},{"text":"The generative flavor is","id":"generativeai"}]'::jsonb, 'AI is the umbrella term for machines performing cognitive-seeming tasks. It stretches from hand-coded rule systems to modern learned models. Most of what people mean by “AI” today is a narrow slice: large models trained on data, not anything with general understanding.', 'Useful as a banner, useless as a spec — always ask which technique someone actually means.', 'The field encompassing symbolic systems, classical ML, and deep learning aimed at intelligent behavior.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('generativeai', 'Generative AI', '', '', ARRAY['generative ai','genai']::text[], 'Core', 'AI that makes new stuff — text, images, code, audio — rather than just sorting or scoring what already exists.', 'The difference between a critic who rates paintings and an artist who paints new ones.', 'Asking a model to write a poem or generate a product mockup is generative AI; asking it to label a photo “cat” is not.', '[{"text":"Language versions are","id":"llm"},{"text":"Works by","id":"nexttokenprediction"}]'::jsonb, 'Generative models learn the shape of their training data well enough to sample fresh examples from it. For language, that’s predicting the next token over and over. The output is novel in wording but bounded by what the training distribution taught it.', 'It opened AI to creative and drafting work, which is why it went mainstream so fast.', 'Models that learn a data distribution and sample from it, e.g. autoregressive LLMs or diffusion image models.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('autoregressive', 'Autoregressive', '', '', ARRAY['autoregressive','auto-regressive']::text[], 'Core', 'Writing one token at a time, each new word chosen from all the words so far — including the ones it just wrote.', 'Predictive text that keeps going: it guesses the next word, commits, then guesses again from the fuller sentence.', 'When a model streams its answer word by word on screen, you’re literally watching autoregression happen.', '[{"text":"The mechanism behind","id":"nexttokenprediction"},{"text":"Emits one","id":"tokens"}]'::jsonb, 'Each step feeds the model everything generated up to now and asks for the next token. That token gets appended and the loop repeats. It’s why generation is sequential and can’t fully parallelize, and why an early wrong turn can snowball.', 'It’s why responses stream in and why latency scales with output length.', 'Factorizing p(sequence) as a product of next-token conditionals, decoding left to right.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('nexttokenprediction', 'Next-token prediction', '', '', ARRAY['next-token prediction','next token prediction']::text[], 'Core', 'The entire job of a language model: given some text, guess what comes next.', 'Finishing your friend’s sentence — do it well enough, billions of times, and it looks like understanding.', 'Type “The capital of France is” and the model predicts “Paris” as the most likely next token.', '[{"text":"Done repeatedly, it is","id":"autoregressive"},{"text":"Where it goes wrong is","id":"hallucination"}]'::jsonb, 'During training the model sees oceans of text and repeatedly guesses the next token, getting corrected each time. That single objective, at scale, is enough to produce grammar, facts, and reasoning-shaped behavior. It’s astonishingly simple, and its limits — it predicts likely, not true — come straight from the objective.', 'Remember the model optimizes for “plausible next word,” not “correct answer” — that gap is where hallucination lives.', 'The self-supervised pretraining objective: minimize cross-entropy of the true next token.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('probabilitydistribution', 'Probability distribution', '', '', ARRAY['probability distribution']::text[], 'Core', 'A spread of chances across all the options — how the model splits its confidence over every possible next token.', 'A weighted die: not every face equally likely, and the weights tell you where the model’s leaning.', 'After “The sky is”, the model might put 60% on “blue”, 10% on “clear”, and thin slices on thousands of others.', '[{"text":"Produced by","id":"softmax"},{"text":"Sharpened or flattened by","id":"temperature"},{"text":"Picked from via","id":"sampling"}]'::jsonb, 'At each step the model outputs a number for every token in its vocabulary, then softmax turns those into probabilities that sum to one. Sampling picks from this distribution. Temperature and top-p are just knobs that reshape it before the pick.', 'The model rarely “knows” one answer — it holds a spread, and your settings decide how boldly it commits.', 'The softmax output over the vocabulary; the categorical distribution sampled at each decode step.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('vector', 'Vector', '', '', ARRAY['vector']::text[], 'Core', 'A list of numbers that stands in for a thing, so a computer can do math on meaning.', 'GPS coordinates for an idea — a handful of numbers that pin it to a spot you can measure distances from.', 'The word “dog” might become [0.2, -1.1, 0.7, …], and “puppy” lands nearby in the same number-space.', '[{"text":"Meaningful ones are","id":"embeddings"},{"text":"Live in a","id":"latentspace"}]'::jsonb, 'Almost everything inside a model is a vector: tokens, hidden states, embeddings. Represent things as vectors and “similar” becomes “close”, “combine” becomes “add”. The dimensions rarely mean anything human-readable, but distances and directions carry real structure.', 'It’s the common currency that lets a model compare, search, and relate anything to anything.', 'An ordered array of floats in R^d; the basic unit of representation throughout the network.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('dimensionality', 'Dimensionality', '', '', ARRAY['dimensionality','dimensions']::text[], 'Core', 'How many numbers are in each vector — the size of the space the model thinks in.', 'Describing a person by 2 traits vs 500: more dimensions, more nuance, but harder to picture.', 'An embedding model might output 1,536-dimensional vectors; each of those slots captures some sliver of meaning.', '[{"text":"The length of a","id":"vector"},{"text":"Defines the","id":"latentspace"}]'::jsonb, 'Higher dimensionality lets a model encode more distinctions, but costs memory and compute and eventually hits diminishing returns. Weird things happen in high dimensions — distances flatten out — which is why similarity math has to be chosen carefully.', 'Bigger embedding dimensions can mean richer matching, but also more storage and slower search.', 'The size d of the vector space; trades representational capacity against compute and the curse of dimensionality.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('latentspace', 'Latent space', '', '', ARRAY['latent space']::text[], 'Core', 'The hidden map where the model arranges everything it knows, with similar things placed near each other.', 'A vast library where books shelve themselves by meaning, not by title — cookbooks drift together without anyone labeling the aisle.', 'In a good latent space, “king” minus “man” plus “woman” lands you near “queen”.', '[{"text":"Made of","id":"vector"},{"text":"Its width is","id":"dimensionality"},{"text":"Points in it are","id":"embeddings"}]'::jsonb, '“Latent” means hidden: it’s the internal coordinate system a model learns, where position encodes meaning. You never see it directly, but retrieval, clustering, and analogies all work because related concepts cluster there. The geometry is learned, not designed.', 'It’s why semantic search “just knows” two differently-worded things mean the same — they sit close in this space.', 'The learned embedding manifold; a continuous vector space where proximity reflects semantic or feature similarity.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('representation', 'Representation', '', '', ARRAY['representation']::text[], 'Core', 'How a model re-encodes something into its own internal language of numbers.', 'Sheet music for a song — not the sound itself, but a form the performer can actually work from.', 'A photo of a cat becomes a representation — a stack of numbers — before the model can classify or caption it.', '[{"text":"Stored as a","id":"vector"},{"text":"The learned kind is an","id":"embeddings"},{"text":"Learning good ones is","id":"deeplearning"}]'::jsonb, 'Deep learning’s whole trick is learning good representations: turning raw input into vectors where the useful structure is easy to read off. Better representations make downstream tasks easier. Much of what pretraining buys you is reusable representations.', 'The quality of a model’s internal representations sets the ceiling on everything it can do downstream.', 'A learned feature vector encoding input; the output of intermediate layers used by downstream heads.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('feature', 'Feature', '', '', ARRAY['feature']::text[], 'Core', 'A single measurable trait the model uses as a clue — one ingredient in its decision.', 'The tells a doctor reads: temperature, pulse, symptoms. Each is a feature; together they point to a diagnosis.', 'In old-school ML you’d hand-pick features like “word count” or “has a link”; deep learning learns its own instead.', '[{"text":"Learned automatically in","id":"deeplearning"},{"text":"Bundled into a","id":"representation"}]'::jsonb, 'A feature is one dimension of information about an input. Classical ML lived or died on humans engineering good features. Deep learning’s leap was learning features automatically from raw data, layer by layer, so the useful ones emerge without being named.', 'Where features come from — hand-built vs learned — is the line between old ML and modern AI.', 'An input variable or a learned activation dimension; the axes along which a model discriminates.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('weightsandbiases', 'Weights and biases', '', '', ARRAY['weights and biases']::text[], 'Core', 'The two kinds of knobs a network learns: weights scale each input, biases nudge the result.', 'A recipe where weights are how much of each ingredient and the bias is the pinch of salt added no matter what.', 'Training a model means slowly turning billions of these weights and biases until the outputs stop being wrong.', '[{"text":"Collectively the","id":"parameters"},{"text":"The weight half is","id":"weights"},{"text":"The nudge is a","id":"biasterm"}]'::jsonb, 'Each neuron multiplies its inputs by weights, sums them, and adds a bias, then applies an activation. Weights decide what matters; the bias shifts the threshold for firing. Every “parameter” you hear about is one of these numbers, and learning is just adjusting them.', '“Number of parameters” is essentially a count of these knobs — a rough proxy for a model’s raw capacity.', 'The learnable affine parameters W and b in y = Wx + b, updated by gradient descent.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('biasterm', 'Bias term', '', '', ARRAY['bias term','bias']::text[], 'Core', 'A constant a neuron adds no matter what, so it isn’t forced to pass through zero.', 'The base fare on a taxi meter — you pay it before the distance charge even starts.', 'Without a bias, a neuron given all-zero input must output zero; the bias lets it say something else.', '[{"text":"The partner of","id":"weights"},{"text":"Together they are","id":"weightsandbiases"}]'::jsonb, 'In y = Wx + b, the bias is b: a learnable offset that shifts the activation up or down independent of the input. Small thing, but it gives each neuron freedom to set its own baseline. Note: “bias” here is unrelated to fairness or social bias — same word, different sense.', 'Pure mechanism; matters to you mainly as a reminder that model “bias” has two totally different meanings.', 'The additive constant b in an affine layer, one learnable scalar per output unit.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('forwardpass', 'Forward pass', '', '', ARRAY['forward pass']::text[], 'Core', 'Running input through the model start to finish to get an output — no learning, just computing.', 'Feeding a coin into a vending machine and watching the can drop: input goes in, result comes out, nothing about the machine changes.', 'Every time you send a prompt and get an answer, that’s one forward pass through billions of parameters.', '[{"text":"At output it produces","id":"logits"},{"text":"Running it is","id":"inference"}]'::jsonb, 'Data flows from the input through each layer’s math to the output. During training this is paired with a backward pass that computes gradients; at inference it’s all you run. It’s what you pay for per request — compute proportional to model size and sequence length.', 'Inference cost is basically the price of one forward pass — bigger model or longer input, bigger bill.', 'Evaluation of the network’s function on an input, producing activations and logits, without gradient updates.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('matrixmultiplication', 'Matrix multiplication', '', '', ARRAY['matrix multiplication','matmul']::text[], 'Core', 'The bulk math behind a model — grids of numbers multiplied together, billions of times a second.', 'A spreadsheet where every cell is a weighted sum of a row and a column, computed all at once.', 'The reason GPUs run AI is that they’re built to do enormous matrix multiplications in parallel.', '[{"text":"Its building block is the","id":"dotproduct"},{"text":"Applies the","id":"weights"}]'::jsonb, 'A layer’s core operation is multiplying an input matrix by a weight matrix. Almost all of a model’s compute is this one operation, which is why hardware is designed around it. Understand matmul and you understand where the FLOPs go.', 'It’s the workload GPUs are optimized for — the physical reason AI compute costs what it does.', 'The dominant kernel: dense GEMM operations that consume most training and inference FLOPs.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('dotproduct', 'Dot product', '', '', ARRAY['dot product']::text[], 'Core', 'Multiply two lists of numbers pairwise and add it all up — one number that says how aligned they are.', 'Scoring how well two playlists match: multiply overlapping tastes, sum the score, higher means more alike.', 'Attention scores “how much should token A care about token B” with a dot product of their vectors.', '[{"text":"Composed into","id":"matrixmultiplication"},{"text":"Normalized becomes","id":"cosinesimilarity"}]'::jsonb, 'The dot product of two vectors sums the products of matching components. It’s the atom of matrix multiplication and the cheapest measure of similarity — big and positive when vectors point the same way, near zero when unrelated. Normalize it and you get cosine similarity.', 'It’s the tiny operation underneath “how similar are these two things” across search and attention.', '⟨a,b⟩ = Σ aᵢbᵢ; the elementary op composing matmul and the unnormalized similarity in attention.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('cosinesimilarity', 'Cosine similarity', '', '', ARRAY['cosine similarity']::text[], 'Core', 'How similar two vectors are by direction, ignoring how long they are — 1 is identical, 0 is unrelated.', 'Two people pointing: it’s whether they point the same way that matters, not how far their arms reach.', 'Semantic search ranks results by cosine similarity between your query’s embedding and each document’s.', '[{"text":"Built from the","id":"dotproduct"},{"text":"Used to compare","id":"embeddings"},{"text":"Powers search over a","id":"vectordatabase"}]'::jsonb, 'It’s the dot product divided by both vectors’ lengths, which strips out magnitude and leaves only angle. That makes it robust when vectors have different scales. It’s the default similarity metric for embeddings because meaning tends to live in direction, not length.', 'It’s the math that decides which stored items count as “closest” to a query in most vector search.', 'cosθ = ⟨a,b⟩ / (‖a‖‖b‖); angle-based similarity invariant to vector magnitude.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('normalization', 'Normalization', '', '', ARRAY['normalization','normalize']::text[], 'Core', 'Rescaling numbers to a sane, consistent range so training doesn’t wobble or blow up.', 'Adjusting every photo to the same brightness before comparing them, so lighting doesn’t fool you.', 'Deep networks add normalization between layers to keep the signal from exploding or vanishing as it goes deep.', '[{"text":"The transformer favorite is","id":"layernormalization"},{"text":"The older vision trick is","id":"batchnormalization"}]'::jsonb, 'Activations can drift to wildly different scales, which makes gradients unstable. Normalization re-centers and re-scales them, keeping the network in a well-behaved zone so it trains faster and deeper. The main variants differ in what they average over.', 'Invisible plumbing, but it’s a big reason very deep models train at all.', 'Standardizing activations (subtract mean, divide by std) to stabilize gradients; see LayerNorm, BatchNorm.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('layernormalization', 'Layer normalization', '', '', ARRAY['layer normalization','layernorm']::text[], 'Core', 'Normalization done across each token’s own features — the version transformers actually use.', 'Grading each student against their own average across subjects, not against the whole class.', 'Every transformer block sandwiches its attention and feed-forward steps with layer norm to stay stable.', '[{"text":"A flavor of","id":"normalization"},{"text":"Wraps each","id":"layer"}]'::jsonb, 'LayerNorm normalizes across the feature dimension for each token independently, so it doesn’t depend on other examples in the batch. That independence is why it plays nicely with variable-length sequences and small batches, unlike batch norm. It’s a quiet workhorse of the transformer.', 'One of those default design choices you inherit for free in any modern model.', 'Normalizes over the feature axis per position; batch-size-independent, standard in transformers.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('batchnormalization', 'Batch normalization', '', '', ARRAY['batch normalization','batchnorm']::text[], 'Fading', 'Normalization computed across a batch of examples — huge for vision, awkward for language.', 'Curving a test using the whole class’s scores that day: great when the class is big and stable, shaky when it’s tiny.', 'ResNets and image models lean on batch norm; transformers mostly skipped it for layer norm.', '[{"text":"A flavor of","id":"normalization"},{"text":"Supplanted in NLP by","id":"layernormalization"}]'::jsonb, 'BatchNorm normalizes each feature using statistics across the current batch. It accelerated deep vision training dramatically, but its batch-dependence causes trouble with small batches, variable sequence lengths, and inference-time mismatch. Language models largely moved on.', 'Mostly a vision-era tool; if you’re in language land you’ll rarely touch it.', 'Normalizes over the batch dimension per feature; batch-dependent, dominant in CNNs, rare in transformers.', 'Foundations', 30, ARRAY['seed','foundations']::text[]),
  ('dropout', 'Dropout', '', '', ARRAY['dropout']::text[], 'Core', 'Randomly switching off part of the network during training so it can’t over-rely on any one path.', 'Making a team practice with random players benched, so no single star becomes a crutch.', 'A model prone to memorizing its training data might use dropout to force more robust, spread-out learning.', '[{"text":"Fights","id":"overfitting"},{"text":"Improves","id":"generalization"}]'::jsonb, 'During training, dropout zeroes a random fraction of activations each step, so neurons must learn redundant, general features instead of brittle co-dependencies. It’s a cheap, effective regularizer against overfitting. At inference it’s turned off and the full network runs.', 'A standard anti-overfitting knob — it trades a little training speed for better generalization.', 'Stochastically masks activations with probability p at train time; a regularizer disabled at inference.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('overfitting', 'Overfitting', '', '', ARRAY['overfitting','overfit']::text[], 'Core', 'When a model memorizes its training data instead of learning the pattern, and flops on anything new.', 'A student who memorizes the practice exam word for word, then panics when the real questions are reworded.', 'A model that scores 99% on training data but 60% on fresh data is overfit — it learned the answers, not the lesson.', '[{"text":"The opposite is","id":"underfitting"},{"text":"The goal it violates is","id":"generalization"},{"text":"Countered by","id":"dropout"}]'::jsonb, 'Overfitting happens when a model has enough capacity to fit noise and quirks specific to the training set. It looks great in training and fails to generalize. Remedies include more data, regularization like dropout, and stopping training before it starts memorizing.', 'It’s why a model that “aced testing” can still disappoint in production — check performance on held-out data.', 'Low training loss but a high generalization gap; the model fits noise rather than signal.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('underfitting', 'Underfitting', '', '', ARRAY['underfitting','underfit']::text[], 'Core', 'When a model is too simple or undertrained to even capture the pattern — bad everywhere, including training.', 'Trying to trace a curvy coastline with a single straight ruler: you miss no matter how you place it.', 'A tiny model on a hard task might sit at 55% on both training and test data — it never had the capacity to learn it.', '[{"text":"The opposite is","id":"overfitting"},{"text":"Both are failures of","id":"generalization"}]'::jsonb, 'Underfitting is high error even on the training set: the model lacks the capacity, the features, or the training time to fit the data. The fix is the opposite of overfitting’s — more capacity, better features, longer training. The art is landing between the two.', 'If a model is mediocre even on data it’s seen, the problem is capacity or training, not just tuning.', 'High bias: the model class is too constrained to fit the underlying function.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('generalization', 'Generalization', '', '', ARRAY['generalization','generalize']::text[], 'Core', 'The whole point — doing well on data the model has never seen, not just the examples it trained on.', 'Learning to ride any bike, not just the exact one you practiced on.', 'A well-generalized spam filter catches brand-new scam wording it never saw in training.', '[{"text":"Broken by","id":"overfitting"},{"text":"Also broken by","id":"underfitting"}]'::jsonb, 'Generalization is the gap between training performance and real-world performance. Everything in ML — regularization, validation sets, more data — is ultimately in service of closing it. Overfitting and underfitting are the two ways it breaks.', 'It’s the only performance number that matters — measure on data the model hasn’t seen.', 'Expected performance on the true data distribution, estimated via held-out/test error.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('inference', 'Inference', '', '', ARRAY['inference']::text[], 'Core', 'Using a trained model to actually answer — the running phase, as opposed to the learning phase.', 'The difference between studying for the exam and sitting it: inference is test day, no more learning.', 'Every prompt you send to a chatbot is inference; the months of training happened long before you showed up.', '[{"text":"One is a","id":"forwardpass"},{"text":"The opposite phase is","id":"training"}]'::jsonb, 'Inference is a forward pass on new input with frozen weights — no gradients, no updates. It’s what you pay for per request and what latency and throughput optimizations target. Training is a one-time (huge) cost; inference is the ongoing one.', 'This is your recurring cost line — it scales with usage, unlike training’s one-time hit.', 'Forward-pass evaluation with fixed parameters; the serving/decoding phase, optimized for latency and throughput.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('training', 'Training', '', '', ARRAY['training','train']::text[], 'Core', 'Teaching the model by showing it data and nudging its parameters until the answers get better.', 'Tuning a piano by ear: play, hear what’s off, adjust the string, repeat thousands of times.', 'Training a frontier model can take months on thousands of GPUs before it ever answers a single user.', '[{"text":"The opposite phase is","id":"inference"},{"text":"Adjusts the","id":"weights"},{"text":"Produces a","id":"basemodel"}]'::jsonb, 'Training runs data through the model, measures error with a loss function, and uses backpropagation and gradient descent to adjust weights. Repeat over enormous data and it slowly learns. It’s the expensive, upfront phase; the result is a frozen set of parameters you then run at inference.', 'It’s the big upfront capital cost; most products consume a model someone else already trained.', 'Iterative parameter optimization via forward pass, loss, backprop, and gradient updates over a dataset.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('modelsize', 'Model size', '', '', ARRAY['model size']::text[], 'Core', 'Roughly how big a model is, usually counted in parameters — the headline number everyone quotes.', 'Engine displacement on a car: bigger often means more power, but it’s not the whole story.', 'A “70B” model has 70 billion parameters; a “7B” has ten times fewer, and runs far cheaper.', '[{"text":"Counted as","id":"parameters"},{"text":"Trades off in a","id":"frontiermodel"}]'::jsonb, 'Size is usually parameter count, a proxy for capacity. Bigger models tend to be more capable but cost more to train and run, and need more data to earn their size. Recent trends show a well-trained small model can beat a bloated large one — size is a dial, not a destiny.', 'Bigger isn’t automatically better; weigh capability against latency and cost for your task.', 'Parameter count (and by extension memory/FLOPs); one axis of the scaling-law trade-off.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('modelfamily', 'Model family', '', '', ARRAY['model family']::text[], 'Core', 'A set of models from the same lineage, usually offered in several sizes.', 'A car model offered as a hatchback, sedan, and SUV — same DNA, different sizes for different needs.', 'Picking between the small, medium, and large versions of one release means choosing within a model family.', '[{"text":"Members differ in","id":"modelsize"},{"text":"The untuned root is a","id":"basemodel"}]'::jsonb, 'A family shares architecture and training recipe, released in multiple sizes and sometimes tuned variants. This lets you trade capability for cost without switching ecosystems. Prompts and behavior tend to transfer within a family more cleanly than across families.', 'Standardizing on one family lets you swap sizes for cost/quality without rewriting everything.', 'Models sharing architecture and training lineage, differentiated mainly by scale and fine-tune.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('checkpoint', 'Checkpoint', '', '', ARRAY['checkpoint']::text[], 'Core', 'A saved snapshot of a model’s parameters at a moment in training, so you can stop, resume, or ship it.', 'A save point in a video game — freeze progress now, come back to exactly here later.', 'If a training run crashes at hour 300, you reload the last checkpoint instead of starting over.', '[{"text":"Saves the","id":"weights"},{"text":"Captured during","id":"training"}]'::jsonb, 'A checkpoint is the full set of weights written to disk mid- or post-training. It lets you resume interrupted runs, compare versions, roll back a bad update, or deploy a specific state. “The model you use” is really one chosen checkpoint.', 'Every deployed model is a specific checkpoint — pin the version so behavior doesn’t shift under you.', 'Serialized parameter (and optimizer) state at a training step, used for resumption and deployment.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('modelcard', 'Model card', '', '', ARRAY['model card']::text[], 'Rising', 'A short spec sheet for a model — what it’s for, what it was trained on, and where it falls down.', 'The nutrition label on food: not the meal, but what you should know before consuming it.', 'Before adopting a model, a team reads its model card for the license, known limitations, and eval scores.', '[{"text":"Describes a","id":"basemodel"},{"text":"May cite","id":"evals"}]'::jsonb, 'A model card documents intended use, training data at a high level, evaluation results, and known risks or biases. It’s a transparency and governance artifact more than a technical one. Quality varies wildly, but it’s the first thing to check before you build on something.', 'Your first due-diligence read — license, intended use, and stated limits can make or break adoption.', 'Structured documentation of a model’s scope, data, metrics, and limitations, per the model-cards convention.', 'Foundations', 60, ARRAY['seed','foundations']::text[]),
  ('openweights', 'Open weights', '', '', ARRAY['open weights','open-weights']::text[], 'Rising', 'A model whose trained parameters you can download and run yourself, no API required.', 'Getting the actual recipe and cooking at home, versus only being able to order the dish.', 'With an open-weights model you can self-host on your own servers and fine-tune it privately.', '[{"text":"The opposite is a","id":"closedmodel"},{"text":"Ships the","id":"weights"}]'::jsonb, 'Open weights means the parameter files are released, so you can run, inspect, and fine-tune locally. It’s not the same as fully open source — training data and code may stay private, and licenses can restrict use. The trade is control and privacy for the burden of hosting it yourself.', 'Open weights buy you self-hosting, privacy, and customization — at the cost of running the infrastructure.', 'Downloadable parameter files for local inference/fine-tuning; distinct from open training data or code.', 'Foundations', 60, ARRAY['seed','foundations']::text[]),
  ('closedmodel', 'Closed model', '', '', ARRAY['closed model','proprietary model']::text[], 'Core', 'A model you can only reach through someone’s API — the weights stay locked behind the vendor’s door.', 'A restaurant kitchen you order from but never enter; you get the dish, never the recipe.', 'Using a top proprietary model means sending prompts to its API and getting answers back — you never hold the weights.', '[{"text":"The opposite is","id":"openweights"},{"text":"Often a","id":"frontiermodel"}]'::jsonb, 'Closed models keep parameters private and are served via API. You trade control and data locality for convenience, managed scaling, and often frontier quality. The risks are lock-in, price changes, and sending your data to a third party.', 'Fastest path to frontier quality, but watch for lock-in, data exposure, and pricing you don’t control.', 'API-gated model with undisclosed weights; you consume inference without hosting or inspecting it.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('densemodel', 'Dense model', '', '', ARRAY['dense model']::text[], 'Core', 'A model where every parameter fires on every token — the standard, straightforward design.', 'A restaurant where the whole kitchen cooks every order, versus one that pages only the relevant chef.', 'A classic dense 7B model uses all 7 billion parameters for each token; a sparse model of the same total wouldn’t.', '[{"text":"The opposite is a","id":"sparsemodel"},{"text":"Cost scales with","id":"modelsize"}]'::jsonb, 'In a dense model the full weight set participates in every forward pass. It’s simple and predictable but means compute scales directly with size. The alternative, sparse mixture-of-experts, activates only a slice per token to get more capacity for less compute.', 'Predictable cost and behavior; you pay for the whole model on every token.', 'All parameters active per token; compute ∝ parameter count, contrasted with sparse MoE routing.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('sparsemodel', 'Sparse model', '', '', ARRAY['sparse model']::text[], 'Rising', 'A model that switches on only the parameters it needs per token, so it can be huge but cheap to run.', 'A big hospital where each patient sees just the right specialists, not every doctor on staff.', 'A mixture-of-experts model might hold eight times the parameters of a dense one but only light up a fraction per token.', '[{"text":"The opposite is a","id":"densemodel"},{"text":"Grows total","id":"parameters"}]'::jsonb, 'Sparse models — chiefly mixture-of-experts — route each token to a few “expert” subnetworks instead of the whole thing. That decouples total capacity from per-token compute: more knowledge, similar cost. The catch is added complexity in routing, load balancing, and serving.', 'The trick behind models that are “enormous” yet affordable to run — capacity without proportional cost.', 'Conditional computation (e.g. MoE) activating a subset of parameters per token via a router.', 'Foundations', 60, ARRAY['seed','foundations']::text[]),
  ('contextlength', 'Context length', '', '', ARRAY['context length']::text[], 'Core', 'The maximum amount of text a model can consider at once, prompt plus answer combined.', 'The size of a desk: only so many papers fit in view before older ones fall off the edge.', 'A 128K context length can hold a small book; exceed it and the earliest text gets dropped.', '[{"text":"Measured in","id":"tokens"},{"text":"The window itself is the","id":"contextwindow"},{"text":"Compared with","id":"sequencelength"}]'::jsonb, 'Context length caps the tokens the model attends to in a single call. Everything — instructions, retrieved docs, history, output — competes for that budget. Longer contexts unlock bigger tasks but cost more and can suffer “lost in the middle” attention issues.', 'It’s a hard budget you’re always managing — long docs, history, and output all share it.', 'Max sequence length the model can attend over; bounded by positional scheme and attention cost.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('sequencelength', 'Sequence length', '', '', ARRAY['sequence length','seq len']::text[], 'Core', 'How many tokens are actually in a given input or output right now.', 'The number of cars in the train you’re running today, versus how long the platform can hold.', 'A 500-token prompt has a sequence length of 500, well under a 128K context limit.', '[{"text":"Capped by","id":"contextlength"},{"text":"Counted in","id":"tokens"}]'::jsonb, 'Sequence length is the count of tokens being processed in a specific pass, while context length is the ceiling. Attention cost grows roughly with the square of sequence length, which is why long inputs get expensive fast. Keeping sequences tight is a real performance lever.', 'Shorter sequences mean lower latency and cost — trimming inputs is a cheap optimization.', 'The token count n of a given batch element; attention is O(n²) in it.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('prompt', 'Prompt', '', '', ARRAY['prompt']::text[], 'Core', 'The input you give a model — the text that sets up what you want it to do.', 'The brief you hand a freelancer: how good the work is depends a lot on how clear you were.', '“Summarize this email in two sentences” plus the email is the prompt; the summary is the completion.', '[{"text":"The model replies with a","id":"completion"},{"text":"Crafting it well is","id":"promptengineering"}]'::jsonb, 'The prompt is everything you feed in: instructions, context, examples, the actual question. The model conditions its entire response on it. Because behavior is so sensitive to wording, prompting is a real skill — though robust models need less coaxing than they used to.', 'Often the cheapest lever you have — rewording the prompt beats fine-tuning for many problems.', 'The input token sequence conditioning generation; includes system, user, and any in-context examples.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('completion', 'Completion', '', '', ARRAY['completion']::text[], 'Core', 'The model’s output — the text it generates to continue or answer your prompt.', 'The reply to your letter: you wrote the prompt, this is what comes back.', 'Send “Write a haiku about rain” and the three-line poem you get is the completion.', '[{"text":"Responds to a","id":"prompt"},{"text":"Built one token at a time via","id":"autoregressive"}]'::jsonb, 'Completion is what the model produces token by token in response to the prompt. The name comes from the original framing — the model “completes” the text you started. Its length counts against your context budget and drives most of your latency.', 'You pay for completion tokens too, and they usually dominate latency — long answers cost more twice over.', 'The generated continuation; the decoded token sequence following the prompt.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('systemmessage', 'System message', '', '', ARRAY['system message','system prompt']::text[], 'Core', 'A special up-front instruction that sets the model’s role and rules for the whole conversation.', 'The job description you give a new hire on day one — it colors everything they do afterward.', '“You are a terse assistant that only answers in bullet points” as a system message shapes every reply that follows.', '[{"text":"Sits alongside the","id":"usermessage"},{"text":"Can be undermined by","id":"promptinjection"}]'::jsonb, 'The system message sits above the back-and-forth and defines persona, constraints, and priorities. Models are trained to weight it heavily, so it’s your main steering wheel for tone and behavior. It’s not bulletproof, though — clever user input can sometimes override it.', 'Your primary control surface for consistent behavior — but don’t treat it as a hard security boundary.', 'A high-priority role message prepended to the conversation, weighted above user turns in training.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('assistantmessage', 'Assistant message', '', '', ARRAY['assistant message']::text[], 'Core', 'A turn in the conversation spoken by the model itself.', 'The reply bubbles on one side of a text thread — the half of the chat that’s the model talking.', 'In a chat transcript, each thing the AI said is tagged as an assistant message.', '[{"text":"Alternates with the","id":"usermessage"},{"text":"The model output is a","id":"completion"}]'::jsonb, 'Chat models see conversations as tagged turns: system, user, and assistant. Assistant messages are the model’s own past replies, fed back in so it stays consistent across a multi-turn chat. You can also seed one to steer or continue a response.', 'Past assistant turns are part of the input — they shape and constrain what comes next.', 'A conversation turn with the assistant role; prior ones are re-fed to maintain multi-turn coherence.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('usermessage', 'User message', '', '', ARRAY['user message']::text[], 'Core', 'A turn in the conversation spoken by the person — what you actually type in.', 'Your side of the text thread: the questions and asks the other party responds to.', '“Can you make that shorter?” typed into a chatbot is a user message.', '[{"text":"Answered by an","id":"assistantmessage"},{"text":"Governed by the","id":"systemmessage"},{"text":"Entry point for","id":"promptinjection"}]'::jsonb, 'User messages carry the human’s requests within the tagged turn structure. The model reads the whole running sequence of system, user, and assistant turns to decide its next reply. Anything untrusted a user pastes in also lands here, which is why injection risk lives at this boundary.', 'This is where untrusted input enters — treat its contents as potentially adversarial.', 'A conversation turn with the user role; the primary untrusted input surface.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('turn', 'Turn', '', '', ARRAY['turn']::text[], 'Core', 'One message in a back-and-forth — one side saying one thing before the other responds.', 'A single volley in a tennis rally: one hit, then it’s the other player’s shot.', 'A five-turn conversation is roughly five exchanged messages between you and the model.', '[{"text":"Assembled into a","id":"conversation"},{"text":"Each has a role like","id":"usermessage"}]'::jsonb, 'Chat is modeled as a sequence of turns, each tagged with a role. The whole history of turns is what the model reads each time, so conversations grow token by token and eventually strain the context budget. Managing turns — trimming or summarizing old ones — is part of building chat apps.', 'Long chats silently eat context; at some point old turns must be trimmed or summarized.', 'A single role-tagged message unit; the granularity of conversation state.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('conversation', 'Conversation', '', '', ARRAY['conversation']::text[], 'Core', 'The full running thread of turns the model reads to keep a chat coherent.', 'The whole email chain, not just the latest reply — context you’d lose if you only read the bottom message.', 'When a chatbot recalls something from ten messages ago, it’s because the whole conversation is re-fed each turn.', '[{"text":"Made of","id":"turn"},{"text":"Bounded by","id":"contextlength"}]'::jsonb, 'A conversation is the ordered stack of system, user, and assistant turns. Models are largely stateless, so the app resends the accumulated history every call to simulate memory. That history grows until it bumps the context limit, forcing truncation or summarization.', 'The model’s “memory” is really just resent history — real long-term memory needs extra machinery.', 'The concatenated sequence of turns re-sent per request; statelessness simulated by replaying history.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('stochastic', 'Stochastic', '', '', ARRAY['stochastic']::text[], 'Core', 'Involving randomness — the reason the same prompt can give you different answers.', 'Rolling dice rather than reading a ruler: the outcome has a random element baked in.', 'Ask the same creative question twice and get two different poems — that’s stochastic sampling at work.', '[{"text":"The opposite is","id":"determinism"},{"text":"Comes from","id":"sampling"},{"text":"Tuned by","id":"temperature"}]'::jsonb, 'Generation is stochastic because the model samples from a probability distribution rather than always taking the top choice. Temperature and top-p control how random. It’s a feature for creativity and a headache for reproducibility — set temperature to zero (or fix a seed) to tame it.', 'It’s why outputs vary run to run — lower the temperature when you need consistency.', 'Sampling-based decoding introduces randomness; contrast with deterministic (greedy) decoding.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('determinism', 'Determinism', '', '', ARRAY['determinism','deterministic']::text[], 'Core', 'Same input, same output, every time — no surprises, no randomness.', 'A calculator: 2+2 is always 4, no mood, no dice.', 'Set temperature to zero and a model becomes (mostly) deterministic — repeat the prompt, repeat the answer.', '[{"text":"The opposite is","id":"stochastic"},{"text":"Achieved via","id":"greedydecoding"},{"text":"Pinned with a","id":"seed"}]'::jsonb, 'Deterministic decoding always picks the highest-probability token (greedy), removing run-to-run variation. It’s what you want for tests, caching, and reproducibility. True determinism can still be nudged by hardware and floating-point quirks, but temperature zero gets you most of the way.', 'Reach for it when you need repeatable, testable outputs rather than creative variety.', 'Greedy/argmax decoding yielding reproducible outputs; disturbed only by numerical nondeterminism.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('seed', 'Seed', '', '', ARRAY['seed']::text[], 'Core', 'A number that fixes the randomness, so a “random” run can be repeated exactly.', 'Shuffling a deck the exact same way twice by starting from the same setup — random-looking, but repeatable.', 'Set the same seed and temperature, and a model can reproduce the identical “random” answer on demand.', '[{"text":"Tames","id":"stochastic"},{"text":"Supports","id":"determinism"}]'::jsonb, 'Random number generators are actually deterministic given a starting seed. Fixing the seed makes stochastic sampling reproducible, which is invaluable for debugging and fair comparisons. It only helps if the rest of the pipeline is pinned too — change the model or hardware and the guarantee weakens.', 'The knob that makes “random” outputs reproducible for testing and A/B comparisons.', 'The RNG seed initializing pseudo-random sampling; fixes decode randomness for reproducibility.', 'Foundations', 80, ARRAY['seed','foundations']::text[])
insert into public.concepts
  (id, term, aliases, said, alias_list, status, one_liner, analogy, example, related, deeper, lens_pm, lens_eng, domain, priority, tags)
values
  ('perplexity', 'Perplexity', '', '', ARRAY['perplexity','ppl']::text[], 'Core', 'A score for how surprised a model is by text — lower means it saw the words coming.', 'Like a reader finishing your sentences: if they nail every next word, they’re barely surprised; if they keep guessing wrong, they’re baffled.', 'A team compares two language models on the same book; the one with perplexity 12 predicts the text far more comfortably than the one at 45.', '[{"text":"It’s computed from the model’s log probabilities.","id":"logprobability"},{"text":"A fluent-but-wrong model can still score well.","id":"hallucination"}]'::jsonb, 'Perplexity is basically the exponent of the average per-token loss — roughly, the number of equally-likely choices the model felt it was picking between at each step. It’s handy for comparing models on the same data, but it rewards fluency, not truth: a model can be smoothly confident and still wrong.', 'A quick, cheap health check on a model or dataset, but never mistake low perplexity for “correct.”', 'Exp of the mean negative log-likelihood per token; only comparable across models with the same tokenizer and test set.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('logprobability', 'Log probability', 'Log-prob', '', ARRAY['log probability','logprob','log prob','logprobs']::text[], 'Core', 'The model’s confidence in a token, written on a stretched-out scale so tiny odds are easy to handle.', 'Like measuring earthquakes on a log scale — it lets you compare a whisper and a shout without the numbers getting unwieldy.', 'A developer inspects the logprobs and sees the model was 90% sure of “Paris” but split three ways on the next word — a hint it’s unsure.', '[{"text":"Averaged and exponentiated, these give perplexity.","id":"perplexity"},{"text":"The raw scores behind them come from logits.","id":"logits"}]'::jsonb, 'Probabilities multiply and quickly underflow to near-zero, so we work in log space where multiplying becomes adding. Summing token logprobs gives a sequence score; averaging and negating gives the loss that training minimizes and that perplexity is built from.', 'Exposing logprobs lets you flag low-confidence answers instead of shipping every guess as gospel.', 'log(p) of a chosen token under the model’s distribution; summed over a sequence for scoring, negated and averaged for cross-entropy loss.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('beamsearch', 'Beam search', '', '', ARRAY['beam search','beam decoding']::text[], 'Fading', 'A decoding trick that keeps several candidate sentences alive at once and picks the best-scoring whole path.', 'Like planning a road trip by keeping your top few routes open at each junction instead of committing to the first turn that looks good.', 'An older translation system runs beam width 5, exploring five partial translations in parallel before settling on the most probable finished one.', '[{"text":"The simpler one-path cousin.","id":"greedydecoding"},{"text":"What replaced it for open-ended text.","id":"sampling"}]'::jsonb, 'Greedy decoding commits to the single best token each step and can paint itself into a corner; beam search hedges by tracking the k highest-scoring sequences and expanding all of them. It shines in translation and captioning, but for open-ended chat it tends to produce bland, repetitive text, which is why sampling methods largely replaced it.', 'Great when there’s one “right” output like a translation; wrong when you want lively, varied prose.', 'Maintains k partial hypotheses ranked by cumulative log-prob, expanding and pruning to k each step until end tokens fire.', 'Foundations', 30, ARRAY['seed','foundations']::text[]),
  ('repetitionpenalty', 'Repetition penalty', '', '', ARRAY['repetition penalty','repeat penalty']::text[], 'Core', 'A dial that discourages the model from saying the same thing over and over.', 'Like a friend who gently taps you when you tell the same story a third time at dinner.', 'A writer notices the model looping “the results show that…” and nudges the repetition penalty up until the phrasing varies.', '[{"text":"A close relative that penalizes by count.","id":"frequencypenalty"},{"text":"Another that penalizes mere appearance.","id":"presencepenalty"}]'::jsonb, 'It works by shrinking the probability of tokens (or phrases) the model has already produced, so each repeat gets a little harder to choose. Push it too hard and the model avoids necessary repeats — names, code keywords — and the text starts to read strangely, so it’s a balance, not a cure.', 'A fast fix for the “broken record” failure without retraining anything.', 'Divides or subtracts from logits of previously seen tokens before sampling, scaled by a penalty factor.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('frequencypenalty', 'Frequency penalty', '', '', ARRAY['frequency penalty']::text[], 'Core', 'A setting that pushes down a word’s odds the more times it has already appeared.', 'Like a game where each repeat of a word costs you more points than the last.', 'Generating product tags, a dev raises the frequency penalty so common words like “premium” stop dominating every list.', '[{"text":"Penalizes appearance regardless of count.","id":"presencepenalty"},{"text":"The blunter version.","id":"repetitionpenalty"}]'::jsonb, 'Unlike a flat repetition penalty, this one scales with how often a token has shown up — the tenth “the” is barely touched, but the tenth “premium” gets hit hard. It curbs runaway repetition while leaving genuinely common words mostly alone.', 'Tune it to keep outputs varied when you’re generating lists or many short items.', 'Subtracts a term proportional to a token’s prior count in the generation from its logit before softmax.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('presencepenalty', 'Presence penalty', '', '', ARRAY['presence penalty']::text[], 'Core', 'A setting that nudges the model toward new words simply because it hasn’t used them yet.', 'Like a host steering the conversation to guests who haven’t spoken, regardless of how chatty the others were.', 'Brainstorming names, a PM turns up the presence penalty so the model reaches for fresh vocabulary instead of recycling the first three ideas.', '[{"text":"The count-scaled sibling.","id":"frequencypenalty"},{"text":"Both act on the sampling step.","id":"sampling"}]'::jsonb, 'It applies a one-time penalty the moment a token has appeared at all — count doesn’t matter, only presence. That makes it a topic-broadener: it encourages the model to introduce new concepts rather than dwell, which is why it pairs well with brainstorming.', 'Reach for it when you want breadth and novelty rather than tight, on-topic answers.', 'Applies a flat logit reduction to any token that has appeared at least once in the output so far.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('maxtokens', 'Max tokens', '', '', ARRAY['max tokens','max_tokens','max new tokens','max output tokens']::text[], 'Core', 'A hard cap on how many tokens the model is allowed to generate before it must stop.', 'Like a word limit on an essay — hit it and the pen gets taken away mid-sentence if needed.', 'An app sets max tokens to 300 for summaries; a user asks for a full report and the answer cuts off abruptly at the ceiling.', '[{"text":"Counts against the shared budget of the context window.","id":"contextwindow"},{"text":"The other way generation ends.","id":"stopsequence"},{"text":"What gets cut when the cap is hit.","id":"truncation"}]'::jsonb, 'It bounds only the output, not the input, and it’s a budget and safety lever — capping cost and latency. The catch is that the model doesn’t “aim” to finish within it; if the cap is too low the response just truncates mid-thought, so it should be sized to the task.', 'Your main control on cost and response length, but set it too tight and answers get chopped.', 'Upper bound on generated tokens; generation halts at this count or at a stop condition, whichever comes first.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('stopsequence', 'Stop sequence', '', '', ARRAY['stop sequence','stop token','stop string','stop words']::text[], 'Core', 'A bit of text that, once produced, tells the model to stop generating right there.', 'Like a “The End” card that halts the film the instant it appears on screen.', 'A developer sets “\nUser:” as a stop sequence so the model writes the assistant’s reply and doesn’t keep role-playing the user’s next line.', '[{"text":"The blunter length limit.","id":"maxtokens"},{"text":"Defines the boundary of one turn.","id":"turn"}]'::jsonb, 'When the model emits the specified string, decoding halts and the stop text is usually trimmed from the output. It’s how you keep a model from running past its turn or bleeding into the next section of a template — a cleaner boundary than relying on max tokens alone.', 'The tidy way to make responses end where they should instead of rambling on.', 'Decoding terminates when the generated suffix matches any configured stop string; the match is typically stripped.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('truncation', 'Truncation', '', '', ARRAY['truncation','truncate','truncating']::text[], 'Core', 'Chopping text to fit a length limit — usually by dropping whatever spills over the edge.', 'Like trimming a too-long photo to fit the frame; whatever sticks out gets cut off.', 'A long transcript exceeds the context window, so the pipeline truncates the oldest lines, and the model never sees how the meeting began.', '[{"text":"The output limit that forces it.","id":"maxtokens"},{"text":"The input budget it protects.","id":"contextwindow"},{"text":"Its opposite: filling short inputs.","id":"padding"}]'::jsonb, 'Truncation happens on input (to fit the context window) or output (to hit max tokens). The danger is silent information loss: if you cut the wrong end you can lop off the instructions or the crucial early facts, so which side you trim from matters as much as that you trim.', 'A quiet source of “why did it ignore that?” bugs — the model may simply never have seen the cut text.', 'Drops tokens beyond a length budget from a chosen end (left/right) before or after generation.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('padding', 'Padding', '', '', ARRAY['padding','pad token','pad tokens']::text[], 'Core', 'Filler tokens added to short sequences so a batch of them all share the same length.', 'Like adding packing peanuts so every box on the truck is the same size and stacks neatly.', 'To process ten prompts of different lengths at once, the system pads the short ones with a special token until all match the longest.', '[{"text":"What tells the model to ignore the filler.","id":"attentionmask"},{"text":"The opposite operation: cutting to fit.","id":"truncation"}]'::jsonb, 'Hardware wants uniform rectangles, so shorter sequences get pad tokens appended (or prepended). Those tokens carry no meaning and must be hidden from the model’s attention — that’s the attention mask’s job — otherwise the model would “read” the filler as content.', 'Invisible plumbing that makes batching efficient; only surfaces as a bug when the mask is wrong.', 'Appends pad tokens to reach a common sequence length; paired with an attention mask that zeroes them out.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('attentionmask', 'Attention mask', '', '', ARRAY['attention mask','attn mask']::text[], 'Core', 'A yes/no map telling the model which tokens it’s allowed to look at and which to ignore.', 'Like blacking out lines on a page so a reader’s eyes skip them entirely.', 'A padded batch uses an attention mask so the model treats real words as content and the trailing pad tokens as if they weren’t there.', '[{"text":"The filler it usually hides.","id":"padding"},{"text":"Where the masking is applied — inside attention."}]'::jsonb, 'The mask is a set of 1s and 0s applied inside attention: masked positions get their scores driven to negative infinity so they contribute nothing after softmax. Two big uses — hiding padding, and enforcing causality so a token can’t peek at future tokens in a decoder.', 'A silent correctness layer; when it’s misaligned, models produce baffling garbage.', 'Additive/boolean mask over attention logits setting disallowed positions to −inf pre-softmax; used for padding and causal masking.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('tokenlimit', 'Token limit', '', '', ARRAY['token limit','max context','context limit']::text[], 'Core', 'The ceiling on how many tokens a model can handle at once, input and output combined.', 'Like a desk that only fits so many papers — pile on more and the earliest ones slide off.', 'A user pastes a 200-page PDF into a chat with a 128k-token limit and gets an error because the document alone blows past the ceiling.', '[{"text":"The window this limit measures.","id":"contextwindow"},{"text":"What happens on overflow.","id":"truncation"},{"text":"Usable budget shrinks toward the middle.","id":"lostinthemiddle"}]'::jsonb, 'The token limit is the physical size of the context window; prompt, history, and generated reply all draw from the same pool. Exceeding it forces truncation or an error, and even well under it, models often use the far ends of that budget less reliably than the edges.', 'Shapes what you can feed a model in one go and quietly caps how much history a chat can keep.', 'Max total tokens (prompt + completion) the model accepts; overflow triggers truncation or a hard error.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('subword', 'Subword', '', '', ARRAY['subword','subword unit','subword token']::text[], 'Core', 'A chunk of a word — the middle ground between whole words and single letters that models actually read.', 'Like Lego bricks for language: “unhappiness” snaps together from “un,” “happi,” and “ness.”', 'A tokenizer splits “tokenization” into “token” and “ization,” so a rare word still reuses pieces the model already knows.', '[{"text":"The algorithm that finds these units.","id":"bytepairencoding"},{"text":"The process of splitting text this way.","id":"tokenization"}]'::jsonb, 'Whole-word vocabularies balloon and choke on typos and new words; character-level is tiny but makes sequences very long. Subwords are the compromise — common words stay whole, rare ones fragment into familiar parts — which is how models handle words they’ve never literally seen.', 'Why token counts don’t match word counts, and why odd or foreign words cost more.', 'Vocabulary units between characters and words, learned so frequent strings stay intact and rare ones decompose.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('bytepairencoding', 'Byte-pair encoding', 'BPE', '', ARRAY['byte-pair encoding','bpe','byte pair encoding']::text[], 'Core', 'The recipe most tokenizers use to build a vocabulary by repeatedly merging the most common pairs of symbols.', 'Like inventing shorthand: you notice “th” appears constantly, so you give it one squiggle, then merge more from there.', 'Training a tokenizer, BPE starts from raw bytes and merges frequent pairs until “ing” and “tion” become single tokens.', '[{"text":"The units it produces.","id":"subword"},{"text":"The broader process it powers.","id":"tokenization"}]'::jsonb, 'Starting from individual characters or bytes, BPE counts adjacent pairs, merges the most frequent into a new symbol, and repeats thousands of times. The result is a vocabulary where common strings are one token and rare ones split into subwords — a data-driven balance of vocabulary size against sequence length.', 'The unglamorous step that decides your token economics before a model ever runs.', 'Greedy merge algorithm over a corpus that iteratively fuses the highest-frequency adjacent symbol pair into the vocab.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('wordembedding', 'Word embedding', '', '', ARRAY['word embedding','word vector','word2vec','glove']::text[], 'Fading', 'A word turned into a list of numbers so that similar words land near each other in space.', 'Like giving every word a home address in a city where synonyms are neighbors and opposites live across town.', 'A classic model places “king” and “queen” close together, and the gap from “man” to “woman” mirrors the gap from “king” to “queen.”', '[{"text":"The general idea of vector meaning.","id":"embeddings"},{"text":"Whole-sentence version.","id":"sentenceembedding"},{"text":"What replaced fixed vectors.","id":"representation"}]'::jsonb, 'Early methods like word2vec and GloVe gave each word one fixed vector learned from co-occurrence. That was a breakthrough, but the flaw is context-blindness: “bank” gets a single vector whether it’s a river or a vault. Transformers replaced them with context-dependent representations, which is why static word embeddings are fading.', 'Foundational history — mostly superseded by contextual models, but the intuition still explains embeddings.', 'Static, context-independent vectors per token learned from co-occurrence statistics; a precursor to contextual representations.', 'Foundations', 30, ARRAY['seed','foundations']::text[]),
  ('sentenceembedding', 'Sentence embedding', '', '', ARRAY['sentence embedding','sentence vector','text embedding']::text[], 'Core', 'A whole sentence or passage squeezed into a single vector that captures its overall meaning.', 'Like a book’s Dewey number — one code that says roughly what it’s about so you can shelve like with like.', 'A search system embeds every FAQ answer as a vector; a user’s question becomes a vector too, and the nearest ones are the best matches.', '[{"text":"The single-word ancestor.","id":"wordembedding"},{"text":"Where these vectors get stored and searched.","id":"vectordatabase"},{"text":"How they’re compared.","id":"cosinesimilarity"}]'::jsonb, 'Instead of one vector per word, a model pools or specially trains to produce one vector per span. These power semantic search, clustering, and retrieval because closeness in the space means closeness in meaning. Quality hinges on the embedding model — a generic one may miss domain nuance.', 'The workhorse behind semantic search and RAG; picking the right embedding model matters more than people expect.', 'A fixed-length vector for a span, from pooling token states or a purpose-trained encoder, compared via cosine or dot product.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('onehotencoding', 'One-hot encoding', '', '', ARRAY['one-hot encoding','one hot','one-hot','one-hot vector']::text[], 'Core', 'Representing a category as a long row of zeros with a single 1 marking which one it is.', 'Like a row of light switches where exactly one is flipped on to name the choice.', 'With a 50,000-word vocabulary, the word “cat” becomes a vector of 49,999 zeros and one 1 at the “cat” slot.', '[{"text":"The dense upgrade.","id":"embeddings"},{"text":"The dimension that makes it sparse.","id":"vocabulary"}]'::jsonb, 'It’s the simplest way to hand a discrete symbol to math, but it’s sparse and says nothing about similarity — “cat” and “dog” are as far apart as “cat” and “bulldozer.” That limitation is exactly why embeddings exist: they compress one-hot vectors into dense ones where distance carries meaning.', 'Textbook groundwork; it explains why dense embeddings were such a leap.', 'A sparse binary vector of vocab length with one active index; the input that an embedding layer maps to a dense vector.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('softmaxtemperature', 'Softmax temperature', '', '', ARRAY['softmax temperature','temperature scaling']::text[], 'Core', 'The knob inside softmax that flattens or sharpens the model’s probabilities before it picks a word.', 'Like a contrast slider on a photo — turn it up and everything blends together, down and the differences pop.', 'Set high, the model spreads its bets and gets creative; set near zero, it collapses onto the single most likely token almost every time.', '[{"text":"The user-facing setting it implements.","id":"temperature"},{"text":"The function it modifies.","id":"softmax"},{"text":"What spread it changes, measured.","id":"entropy"}]'::jsonb, 'Temperature divides the logits before softmax: values below 1 exaggerate gaps (more deterministic), above 1 shrink them (more random). It’s the mechanism underneath the “temperature” setting you see in APIs — same idea, applied at the point where scores become probabilities.', 'The dial between “safe and repetitive” and “varied and risky” outputs.', 'Scales logits by 1/T before softmax; T→0 approaches argmax, T>1 raises entropy of the distribution.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('entropy', 'Entropy', '', '', ARRAY['entropy','shannon entropy']::text[], 'Core', 'A measure of how spread out and uncertain a set of probabilities is.', 'Like a weather forecast: “50% rain” is high-entropy uncertainty, “99% sunny” is low.', 'When the model’s next-token distribution has high entropy, several words are nearly tied — a sign it’s genuinely unsure what comes next.', '[{"text":"Training’s loss built on top of it.","id":"crossentropy"},{"text":"Temperature raises or lowers it.","id":"softmaxtemperature"}]'::jsonb, 'Entropy is highest when options are evenly likely and zero when one outcome is certain. In language models it quantifies uncertainty at each step, and it’s the theoretical floor that cross-entropy loss measures against — training pushes the model’s predictions to match reality’s true distribution.', 'A principled way to detect “the model is guessing here” and route those cases to a human.', '−Σ p·log p over a distribution; maximal for uniform, zero for a point mass, and the baseline cross-entropy compares to.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('crossentropy', 'Cross-entropy', '', '', ARRAY['cross-entropy','cross entropy','cross-entropy loss']::text[], 'Core', 'The standard scorecard for how far a model’s predicted probabilities are from the true answer.', 'Like grading a weather forecaster not on right/wrong but on how confident they were in what actually happened.', 'During training, the model predicts the next token; cross-entropy is high when it put low probability on the word that actually came next, low when it was confident and correct.', '[{"text":"Its uncertainty baseline.","id":"entropy"},{"text":"Its exponential, for reporting.","id":"perplexity"},{"text":"What it’s computed from.","id":"logprobability"}]'::jsonb, 'Cross-entropy measures the cost of encoding the real data using the model’s predicted distribution — it’s minimized when the two match. It’s the loss almost every language model trains on, it connects directly to perplexity (its exponential), and it rewards putting probability mass on the truth, not just guessing right.', 'The number that goes down as a model learns; the training objective in one word.', '−Σ y·log p between target and predicted distributions; the per-token training loss whose exp is perplexity.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('gradient', 'Gradient', '', '', ARRAY['gradient','gradients']::text[], 'Core', 'The direction and steepness of change that tells each weight which way to move to reduce error.', 'Like feeling the slope under your feet in fog — it tells you which way is downhill even when you can’t see the valley.', 'After a wrong prediction, the gradient for each weight says “nudge me up a little, me down a lot,” and the optimizer follows those hints.', '[{"text":"The corrective signal it carries.","id":"learningsignal"},{"text":"What consumes it to update the model.","id":"training"}]'::jsonb, 'A gradient is the derivative of the loss with respect to every parameter — a giant vector pointing toward steepest increase, so training steps the opposite way. Backpropagation is just the efficient method for computing it, and problems like vanishing or exploding gradients are what make deep networks hard to train.', 'The invisible feedback signal that makes learning possible; when it misbehaves, training stalls.', '∂loss/∂θ for all parameters; computed via backprop and consumed by the optimizer to update weights.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('learningsignal', 'Learning signal', '', '', ARRAY['learning signal','training signal']::text[], 'Core', 'Whatever information tells a model that it was right or wrong and by how much.', 'Like a coach’s feedback after each rep — without it you just repeat the same swing forever.', 'In supervised training the learning signal is the gap to the correct label; in RLHF it’s a reward score standing in for human preference.', '[{"text":"How the signal reaches the weights.","id":"gradient"},{"text":"A signal from human preference.","id":"rlhf"}]'::jsonb, 'Every learning method needs some signal to update on — a label, a reward, a contrastive pair, a reconstruction error. Its quality caps how well the model can do: a noisy, sparse, or biased signal teaches the wrong lesson no matter how big the model. Much of ML progress is really about inventing better signals.', 'Where your data quality actually bites — a clean signal beats a bigger model on a muddy one.', 'The error/reward term driving parameter updates; its density and fidelity bound achievable performance.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('capacity', 'Capacity', '', '', ARRAY['capacity','model capacity']::text[], 'Core', 'How much a model can potentially learn — roughly, how complex a pattern it can represent.', 'Like the size of a suitcase: a bigger one holds more, but an oversized bag half-empty just gets messy and heavy.', 'A tiny model can’t capture the nuance of legal text — too little capacity — while a huge one memorizes the training set instead of generalizing.', '[{"text":"Too much for the data leads here.","id":"overfitting"},{"text":"Too little leads here.","id":"underfitting"},{"text":"The knob that raises it.","id":"parameters"}]'::jsonb, 'Capacity grows with parameters, depth, and width, and it sets the ceiling on complexity a model can fit. Too little and you underfit; too much for your data and you overfit or waste compute. The art is matching capacity to the amount and richness of data, which is exactly what scaling laws try to quantify.', 'Bigger isn’t automatically better — capacity has to be matched to the data and the task.', 'Informal measure of a model’s expressive range, scaling with parameter count, depth, and width.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('emergentability', 'Emergent ability', '', '', ARRAY['emergent ability','emergent abilities','emergent capability']::text[], 'Rising', 'A skill that shows up suddenly only once a model gets big enough, absent in smaller ones.', 'Like water staying liquid, liquid, liquid — then abruptly boiling at 100°C. Nothing, nothing, then a phase change.', 'Small models flunk multi-step arithmetic entirely, then past a certain scale a model starts getting it right, seemingly out of nowhere.', '[{"text":"The parameter growth that triggers it.","id":"capacity"},{"text":"A key one: learning from examples in the prompt.","id":"incontextlearning"}]'::jsonb, 'Emergent abilities are capabilities that don’t improve smoothly with size but appear to switch on past a threshold. They’re real but contested — some “jumps” are artifacts of harsh all-or-nothing metrics, and smoother scoring reveals gradual gains. Either way, they’re why bigger models sometimes surprise their own builders.', 'Why a scale-up can unlock features you didn’t explicitly train for — and why they’re hard to predict.', 'Capabilities that appear near a scale threshold rather than improving continuously; partly metric-dependent.', 'Foundations', 60, ARRAY['seed','foundations']::text[]),
  ('incontextlearning', 'In-context learning', 'ICL', '', ARRAY['in-context learning','icl','in context learning']::text[], 'Core', 'A model picking up a new task from examples in the prompt, without any weights changing.', 'Like showing someone three solved puzzles and watching them nail the fourth — no studying, just pattern-matching on the spot.', 'You paste five examples of turning messy addresses into clean ones, then a sixth messy address, and the model formats it correctly.', '[{"text":"Learning from a handful of examples.","id":"fewshot"},{"text":"Doing it with none.","id":"zeroshot"},{"text":"An emergent capability at scale.","id":"emergentability"}]'::jsonb, 'The model’s weights are frozen; it’s inferring the task purely from the pattern in the context and running it during a single forward pass. This is what makes few-shot prompting work and blurs the line between “using” and “teaching” a model — though it’s temporary, lasting only as long as the examples stay in context.', 'Often you can skip fine-tuning entirely — just show examples in the prompt.', 'Task adaptation from prompt demonstrations at inference with no parameter updates; behavior conditioned on context.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('zeroshot', 'Zero-shot', '', '', ARRAY['zero-shot','zero shot','zero-shot learning']::text[], 'Core', 'Asking a model to do a task with no examples at all — just the instruction.', 'Like handing a capable new hire a task described in one sentence and trusting them to figure it out.', '“Classify this review as positive or negative: …” with no sample classifications — the model just does it.', '[{"text":"The same idea with a few examples.","id":"fewshot"},{"text":"With exactly one.","id":"oneshot"},{"text":"The mechanism that makes examples help.","id":"incontextlearning"}]'::jsonb, 'Zero-shot leans entirely on what the model absorbed in pretraining plus your instruction. It’s the cleanest, cheapest way to prompt and often works surprisingly well on common tasks, but for anything unusual or format-sensitive, adding a few examples usually beats it.', 'Try zero-shot first — if it works, you’ve saved tokens and effort; if not, add examples.', 'Task performed from instructions alone with no in-prompt demonstrations, relying on pretrained priors.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('fewshot', 'Few-shot', '', '', ARRAY['few-shot','few shot','few-shot prompting']::text[], 'Core', 'Giving the model a handful of worked examples in the prompt to show it the pattern you want.', 'Like a recipe with a few sample plates photographed — you copy the style for the next dish.', 'Before asking for a product description, you include three examples of the exact tone and length, and the model matches them.', '[{"text":"None-example version.","id":"zeroshot"},{"text":"Single-example version.","id":"oneshot"},{"text":"Why it works without training.","id":"incontextlearning"}]'::jsonb, 'Few-shot prompting supplies several input→output demonstrations so the model infers the task and, crucially, the format. It usually beats zero-shot on tricky or structured tasks, but examples cost tokens and their choice and order can noticeably sway the result — so curation matters.', 'The cheapest reliable quality boost before you consider fine-tuning.', 'Prompting with k demonstrations to steer task and format via in-context learning; sensitive to example selection and order.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('oneshot', 'One-shot', '', '', ARRAY['one-shot','one shot','one-shot prompting']::text[], 'Core', 'Showing the model exactly one example before asking it to do the same thing.', 'Like a single “here’s how” demo before someone tries it themselves.', 'You give one sample of the JSON shape you want, then the real input — and the model mirrors the structure.', '[{"text":"Zero examples.","id":"zeroshot"},{"text":"Several examples.","id":"fewshot"}]'::jsonb, 'One-shot sits between zero-shot and few-shot: a single demonstration is often enough to lock in a format or convention while spending almost no extra tokens. When one example carries the whole pattern, it’s the efficient sweet spot.', 'A great token-cheap way to pin down output format without a full example set.', 'In-context learning with a single demonstration; efficient when one example conveys the target format.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('instructionfollowing', 'Instruction following', '', '', ARRAY['instruction following','instruction-following']::text[], 'Core', 'A model’s ability to actually do what you tell it, not just continue your text.', 'Like the difference between a parrot that echoes you and an assistant that hears “summarize this” and summarizes.', 'You write “Reply in exactly two sentences, no bullet points,” and a well-tuned model obeys both constraints instead of ignoring them.', '[{"text":"The training that instills it.","id":"rlhf"},{"text":"What a raw model does instead.","id":"basemodel"}]'::jsonb, 'Base models just predict likely text; instruction following is a learned behavior, mostly from instruction tuning and RLHF, that makes them treat prompts as commands. It’s never perfect — models miss constraints, especially several at once — which is why clear, checkable instructions still matter.', 'The trait that turns a raw model into something a non-expert can actually direct.', 'Learned behavior (via SFT/RLHF) to condition outputs on directives rather than mere continuation; degrades with constraint count.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('worldmodel', 'World model', '', '', ARRAY['world model','internal model']::text[], 'Rising', 'An internal picture of how things work that lets a system predict what happens next.', 'Like the mental map you use to guess a rolling ball will fall off the table before it does.', 'A model that tracks who’s holding what across a story — and correctly says the key is now in Sara’s pocket — is showing a small world model.', '[{"text":"Tying that model to real facts.","id":"grounding"},{"text":"The internal encodings it would live in.","id":"representation"}]'::jsonb, 'Whether LLMs truly have world models is debated: they clearly build useful internal representations of state and relationships, yet they also make errors no consistent model would. The term matters because robust planning and reasoning arguably require modeling the world, not just predicting surface text.', 'Shorthand for “does it actually understand the situation, or just sound like it?” — the crux of reliability.', 'An internal representation of environment state and dynamics supporting prediction; contested in LLMs.', 'Foundations', 60, ARRAY['seed','foundations']::text[]),
  ('grounding', 'Grounding', '', '', ARRAY['grounding','grounded','grounded generation']::text[], 'Core', 'Tying a model’s answers to real, checkable sources instead of letting it free-associate.', 'Like a journalist who cites documents rather than writing “trust me.”', 'A support bot grounded in the actual help docs quotes the real refund window instead of inventing a plausible-sounding one.', '[{"text":"The pattern that supplies the evidence.","id":"rag"},{"text":"What it fights.","id":"hallucination"},{"text":"Knowledge baked into weights, ungrounded.","id":"parametricknowledge"}]'::jsonb, 'Grounding connects generation to external evidence — retrieved documents, tool outputs, databases — so claims can be traced and verified. It’s the main practical defense against hallucination: not because the model gets smarter, but because it’s answering from provided facts rather than parametric memory alone.', 'The difference between a demo and something you’d let talk to customers.', 'Conditioning outputs on retrieved/verified external context and enabling attribution; the core mitigation for hallucination.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('knowledgecutoff', 'Knowledge cutoff', '', '', ARRAY['knowledge cutoff','training cutoff','cutoff date']::text[], 'Core', 'The date after which a model simply hasn’t seen anything — its news stops there.', 'Like a textbook printed last year: thorough up to press time, blank on everything since.', 'Asked who won a championship held after its cutoff, the model either admits it doesn’t know or confidently guesses wrong.', '[{"text":"The frozen knowledge it bounds.","id":"parametricknowledge"},{"text":"How you get around it.","id":"rag"},{"text":"The confident-wrong risk it creates.","id":"hallucination"}]'::jsonb, 'A model’s parametric knowledge is frozen at the end of its training data. Anything later is invisible unless you supply it in the prompt or via retrieval. The subtle danger is that models don’t reliably know what they don’t know, so they can answer post-cutoff questions with unwarranted confidence.', 'Why current-events features need live retrieval bolted on, not just a bigger model.', 'The training-data recency bound of parametric knowledge; post-cutoff facts require in-context grounding.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('parametricknowledge', 'Parametric knowledge', '', '', ARRAY['parametric knowledge','parametric memory']::text[], 'Core', 'What a model “knows” baked into its weights, not looked up from anywhere.', 'Like facts you’ve memorized versus ones you’d Google — parametric knowledge is the stuff already in your head.', 'A model naming the capital of France with no documents provided is drawing on parametric knowledge.', '[{"text":"Its looked-up counterpart.","id":"nonparametricmemory"},{"text":"The date it freezes.","id":"knowledgecutoff"},{"text":"Where the facts live.","id":"weights"}]'::jsonb, 'During training, facts and patterns get compressed into the parameters themselves. It’s fast and always available, but it’s frozen at the knowledge cutoff, can be subtly wrong, and can’t cite a source. That’s the trade-off retrieval addresses by pairing it with non-parametric memory.', 'Convenient but unverifiable — fine for general knowledge, risky for facts that must be current or exact.', 'Information encoded in model weights, accessed without retrieval; static, uncited, cutoff-bound.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('nonparametricmemory', 'Non-parametric memory', '', '', ARRAY['non-parametric memory','nonparametric memory','external memory']::text[], 'Core', 'Knowledge a model pulls in from outside itself at answer time, rather than from its weights.', 'Like an open-book exam — the facts live in the book on your desk, not only in your memory.', 'A RAG system fetches the exact policy paragraph and hands it to the model, so the answer comes from a document, not the weights.', '[{"text":"Its in-the-weights counterpart.","id":"parametricknowledge"},{"text":"The retrieval pattern that uses it.","id":"rag"},{"text":"A common backing store.","id":"vectordatabase"}]'::jsonb, 'Non-parametric memory keeps knowledge in an external, swappable store — documents, a vector database, a tool — that the model reads on demand. Its advantages are updatability and citation: you can change a fact without retraining, and the model can point to where an answer came from. The cost is a retrieval step that can fail.', 'How you keep answers current and auditable without retraining the whole model.', 'Knowledge held in an external store queried at inference; updatable and attributable, unlike weights.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('contextstuffing', 'Context stuffing', '', '', ARRAY['context stuffing','context packing','prompt stuffing']::text[], 'Rising', 'Cramming as much text as possible into the prompt and hoping the model sorts it out.', 'Like dumping every file on your desk in front of a colleague and saying “the answer’s in there somewhere.”', 'Instead of retrieving the right three pages, a team pastes the entire 90-page manual into context — and answers get slower and vaguer.', '[{"text":"The failure it triggers.","id":"lostinthemiddle"},{"text":"The disciplined alternative.","id":"rag"},{"text":"The budget it burns.","id":"tokenlimit"}]'::jsonb, 'Big context windows tempt you to skip retrieval and just include everything. It sometimes works, but it costs tokens, adds latency, and runs into “lost in the middle,” where models attend poorly to material buried between the ends. Curated, relevant context usually beats a firehose.', 'A tempting shortcut that quietly raises cost and lowers quality; selective beats exhaustive.', 'Filling the window with unfiltered content instead of retrieval; degrades via cost, latency, and mid-context attention loss.', 'Foundations', 60, ARRAY['seed','foundations']::text[]),
  ('lostinthemiddle', 'Lost in the middle', '', '', ARRAY['lost in the middle','lost-in-the-middle']::text[], 'Rising', 'The tendency of models to notice info at the start and end of a long prompt but overlook the middle.', 'Like remembering the first and last speakers at a long meeting and blanking on everyone in between.', 'A key fact placed on page 20 of a 40-page context gets ignored, while the same fact at the top or bottom gets used.', '[{"text":"Made worse by dumping everything in.","id":"contextstuffing"},{"text":"The stress test for it.","id":"needleinahaystack"},{"text":"Why usable context is less than the max.","id":"effectivecontext"}]'::jsonb, 'Studies find a U-shaped attention pattern: relevant information is used far more reliably when it sits near the edges of the context than when it’s buried in the middle. It means a big context window doesn’t guarantee the model actually reads all of it — placement and retrieval quality still matter.', 'Why “it fits in the window” isn’t the same as “the model will use it”; put the crucial stuff at the edges.', 'Positional recall bias where mid-context tokens are underattended relative to the head and tail.', 'Foundations', 60, ARRAY['seed','foundations']::text[]),
  ('needleinahaystack', 'Needle in a haystack', '', '', ARRAY['needle in a haystack','needle in haystack','niah']::text[], 'Rising', 'A test that hides one specific fact in a huge context to see if the model can find it.', 'Like slipping a secret sentence into a long novel and quizzing the reader on it afterward.', 'Evaluators bury “the passcode is 4417” deep in 100k tokens of filler, then ask for the passcode to measure recall by position.', '[{"text":"The weakness it exposes.","id":"lostinthemiddle"},{"text":"What it really measures.","id":"effectivecontext"},{"text":"The broader practice of testing models.","id":"evals"}]'::jsonb, 'The needle-in-a-haystack test probes whether a long context window is truly usable. By varying where the “needle” sits, it maps out weak spots — often the middle — and separates advertised context length from effective context. Passing a simple version doesn’t guarantee handling multiple or reasoning-dependent needles.', 'A quick reality check on long-context claims before you rely on them.', 'Retrieval probe inserting a target fact at varied depths in long context to measure positional recall.', 'Foundations', 60, ARRAY['seed','foundations']::text[]),
  ('effectivecontext', 'Effective context', '', '', ARRAY['effective context','effective context length','usable context']::text[], 'Rising', 'How much of a model’s advertised context window it can actually use well, which is usually less.', 'Like a phone plan’s “unlimited” data that quietly throttles after a point — the number on the box isn’t the number you get.', 'A model sold as 128k tokens stays sharp to maybe 32k, then starts missing details buried deeper — its effective context is smaller than its limit.', '[{"text":"The hard ceiling above it.","id":"tokenlimit"},{"text":"Why it’s smaller than the max.","id":"lostinthemiddle"},{"text":"How it’s measured.","id":"needleinahaystack"}]'::jsonb, 'Maximum context length is a hard ceiling; effective context is the practical range where recall and reasoning hold up. Attention biases like lost-in-the-middle mean quality degrades before the ceiling. Needle-in-a-haystack tests are how you estimate it, and it’s often a fraction of the advertised size.', 'Budget for the usable window, not the marketing number, or long-context features will disappoint.', 'The context range over which recall/reasoning stay reliable, typically below the max token limit.', 'Foundations', 60, ARRAY['seed','foundations']::text[]),
  ('multimodalinput', 'Multimodal input', '', '', ARRAY['multimodal input','multi-modal input','multimodal']::text[], 'Rising', 'Feeding a model more than just text — images, audio, or video alongside words.', 'Like talking to someone who can both read your note and look at the photo you’re pointing at.', 'You upload a screenshot of an error and type “what’s wrong here?” — the model reads the image and the text together.', '[{"text":"The shared space they’re mapped into.","id":"representation"},{"text":"The budget images strain.","id":"tokenlimit"},{"text":"Vectors as the common currency.","id":"embeddings"}]'::jsonb, 'Multimodal models encode each input type into a shared representation space so the model can reason across them. It unlocks tasks pure text can’t touch — describing images, reading charts, transcribing speech — but each modality adds its own tokenization, cost, and failure modes, and image tokens can eat context fast.', 'Opens whole product categories (photo Q&A, document understanding) but watch the token and latency cost.', 'Inputs of mixed modalities encoded into a shared representation for cross-modal reasoning; images consume many tokens.', 'Foundations', 60, ARRAY['seed','foundations']::text[]),
  ('textgeneration', 'Text generation', '', '', ARRAY['text generation','natural language generation','nlg']::text[], 'Core', 'A model producing new text one token at a time, each choice conditioned on everything so far.', 'Like writing a sentence where you commit to one word, then choose the next based on all the words already down.', 'You type a prompt and watch the reply stream in word by word — that streaming is generation happening token by token.', '[{"text":"The step-by-step nature of it.","id":"autoregressive"},{"text":"The prediction at each step.","id":"nexttokenprediction"},{"text":"How each token is chosen.","id":"sampling"}]'::jsonb, 'Generation is autoregressive: the model predicts a probability distribution for the next token, a decoding strategy picks one, it’s appended, and the loop repeats. Everything from temperature to stop sequences is really about shaping or ending this loop. It’s also why longer outputs cost proportionally more time and money.', 'The core act you’re paying for; output length drives both latency and cost linearly.', 'Iterative next-token sampling from the model’s conditional distribution until a stop condition; inherently sequential.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('languagemodel', 'Language model', 'LM', '', ARRAY['language model','lm']::text[], 'Core', 'A system that learns the patterns of language well enough to predict and produce text.', 'Like someone with such a feel for a language that they can finish almost any sentence you start.', 'Give it “The capital of France is” and a language model completes “Paris” because that continuation is overwhelmingly likely.', '[{"text":"The scaled-up version.","id":"llm"},{"text":"The prediction task at its core.","id":"nexttokenprediction"},{"text":"A compact version.","id":"smalllanguagemodel"}]'::jsonb, 'At heart a language model assigns probabilities to sequences of tokens, which lets it both score and generate text. Modern ones are large neural networks trained on huge corpora; “LLM” is just a language model scaled up. The framing matters: it predicts likely text, and likely is not the same as true.', 'The base primitive under every chat product; understanding it as a predictor explains most of its quirks.', 'A model of P(token sequence) trained to predict tokens; scaled up, it becomes an LLM.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('smalllanguagemodel', 'Small language model', 'SLM', '', ARRAY['small language model','slm']::text[], 'Rising', 'A compact language model built to run cheaply and fast, often on your own device.', 'Like a scooter instead of a truck — less hauling power, but nimble, cheap, and it fits in the garage.', 'A phone keyboard runs a small on-device model to suggest words instantly without sending anything to a server.', '[{"text":"The general concept.","id":"languagemodel"},{"text":"How they’re often trained down.","id":"studentmodel"},{"text":"The big models they contrast with.","id":"frontiermodel"}]'::jsonb, 'Small language models trade raw capability for speed, cost, and privacy, and modern training and distillation have made them surprisingly strong on focused tasks. The bet is that most real jobs don’t need a frontier model — a well-tuned small one, running locally, is often good enough and far cheaper.', 'Often the right call for narrow, high-volume, or privacy-sensitive tasks where a giant model is overkill.', 'A parameter-efficient LM optimized for latency, cost, and edge deployment; frequently distilled from a larger teacher.', 'Foundations', 60, ARRAY['seed','foundations']::text[]),
  ('mixturemodel', 'Mixture model', '', '', ARRAY['mixture model','mixture of models']::text[], 'Core', 'A model that combines several specialized sub-models, blending their outputs into one answer.', 'Like a panel of specialists where each weighs in and their votes are averaged into a diagnosis.', 'A system routes a coding question to its code-savvy component and a poem request to another, mixing their strengths.', '[{"text":"A group of models voting.","id":"ensemble"},{"text":"Its dense counterpart.","id":"densemodel"},{"text":"The sparse version it enables.","id":"sparsemodel"}]'::jsonb, 'A mixture model composes multiple components, often weighting them by how relevant each is to the input. It’s the statistical idea behind mixture-of-experts architectures, where a router activates only the most relevant sub-networks per token — capturing diverse patterns without one monolithic model doing everything.', 'The concept behind “big model, but only part of it runs per query,” which keeps costs sane at scale.', 'A model combining weighted sub-models; the basis for mixture-of-experts routing over specialized components.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('ensemble', 'Ensemble', '', '', ARRAY['ensemble','ensembling','ensemble model']::text[], 'Core', 'Combining several models’ predictions to get a result better than any one alone.', 'Like “ask the audience” — the crowd’s averaged guess usually beats any single person’s.', 'A team runs three different models on the same input and takes the majority vote, cutting the error rate of each individual model.', '[{"text":"A weighted, learned relative.","id":"mixturemodel"},{"text":"Averaging many best guesses.","id":"sampling"}]'::jsonb, 'Ensembling works because different models make different mistakes, so averaging or voting cancels uncorrelated errors. It reliably boosts accuracy and robustness, but at multiplied compute and latency — you’re running many models instead of one — which is why it’s common in competitions and less so in cost-sensitive production.', 'A dependable accuracy bump you pay for in compute; great for offline scoring, pricey for live serving.', 'Aggregating predictions (vote/average/stack) from diverse models to reduce variance; cost scales with members.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('teachermodel', 'Teacher model', '', '', ARRAY['teacher model']::text[], 'Core', 'A big, capable model whose outputs are used to train a smaller one.', 'Like an expert who writes out worked solutions so an apprentice can learn from them.', 'A large frontier model labels a million examples, and a compact model trains on those labels to imitate it at a fraction of the size.', '[{"text":"The smaller model it trains.","id":"studentmodel"},{"text":"A frequent teacher.","id":"frontiermodel"},{"text":"What small models it produces.","id":"smalllanguagemodel"}]'::jsonb, 'In distillation, the teacher provides targets — final answers or full probability distributions — richer than raw labels, letting the student absorb its behavior. The student can approach the teacher’s quality on many tasks while being far cheaper to run, though it inherits the teacher’s blind spots too.', 'How you get near-frontier quality at small-model cost — with the teacher’s biases along for the ride.', 'The source model in distillation, supplying soft targets or labels the student is trained to match.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('studentmodel', 'Student model', '', '', ARRAY['student model']::text[], 'Core', 'A smaller model trained to imitate a bigger one, keeping much of the skill at a fraction of the cost.', 'Like an apprentice who studies the master’s work and reproduces most of it with far less overhead.', 'A compact chatbot trained on a large model’s answers runs on a single GPU while staying close in quality on everyday requests.', '[{"text":"The model it learns from.","id":"teachermodel"},{"text":"Often the end goal.","id":"smalllanguagemodel"}]'::jsonb, 'The student learns from a teacher’s outputs rather than raw data alone, which packs more signal into fewer examples. Done well, it retains most capability while shrinking dramatically — but it can’t exceed the teacher, and it copies the teacher’s errors and gaps as faithfully as its strengths.', 'The practical path to cheap, fast models that still feel smart on common tasks.', 'The target model in distillation, optimized to match a teacher’s outputs at reduced parameter count.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('modelcheckpointing', 'Model checkpointing', '', '', ARRAY['model checkpointing','saving checkpoints']::text[], 'Core', 'Saving a snapshot of a model mid-training so you can resume or roll back to it later.', 'Like hitting “save” in a long video game so a crash doesn’t cost you hours of progress.', 'A week-long training run writes a checkpoint every few hours; when a machine fails at hour 50, the team restarts from the latest snapshot.', '[{"text":"A single saved snapshot.","id":"checkpoint"},{"text":"The process it safeguards.","id":"training"},{"text":"Resuming from a saved point.","id":"warmstart"}]'::jsonb, 'Checkpointing periodically persists the weights (and optimizer state) so training runs survive crashes, can be evaluated at intervals, and can be resumed or reverted. It’s essential insurance for expensive runs, and it also lets teams pick the best-performing snapshot rather than whatever happened to be last.', 'The reason a hardware failure during a costly run isn’t a catastrophe.', 'Periodic persistence of weights and optimizer state enabling resume, evaluation, and rollback across a training run.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('warmstart', 'Warm start', '', '', ARRAY['warm start','warm-start']::text[], 'Core', 'Beginning training from an existing model’s weights instead of from scratch.', 'Like starting a novel from a detailed outline rather than a blank page.', 'Rather than train a new model from zero, a team warm-starts from an open-weights checkpoint and fine-tunes on their data.', '[{"text":"The snapshot you start from.","id":"checkpoint"},{"text":"The pretraining that made it.","id":"pretraining"},{"text":"Reusing knowledge across tasks.","id":"basemodel"}]'::jsonb, 'A warm start initializes from pretrained weights so the model already “knows” language and only needs to adapt, saving enormous compute and data versus a cold start. It underpins transfer learning and fine-tuning — but the starting model’s biases and limitations carry over, for better and worse.', 'Why almost nobody trains from scratch anymore — you stand on an existing model’s shoulders.', 'Initializing parameters from a pretrained checkpoint rather than random init to accelerate convergence.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('pretraining', 'Pretraining', 'Pre-training', '', ARRAY['pretraining','pre-training','pretrain']::text[], 'Core', 'The long, expensive first phase where a model learns language from a giant pile of raw text.', 'Like a child soaking up a language for years just by hearing it, before anyone teaches a specific job.', 'A model reads trillions of tokens of web text, books, and code, predicting the next token over and over, until it has a broad feel for language.', '[{"text":"The self-supervised nature of it.","id":"nexttokenprediction"},{"text":"The model it produces.","id":"basemodel"},{"text":"What refines it afterward.","id":"rlhf"},{"text":"Where the knowledge ends up.","id":"parametricknowledge"}]'::jsonb, 'Pretraining is self-supervised: the “labels” are just the next tokens, so no human annotation is needed at this scale. It builds the general capabilities and parametric knowledge everything else builds on, and it’s where most of the compute and cost go. Later stages like fine-tuning and RLHF only steer what pretraining created.', 'The multimillion-dollar foundation you rarely redo; you adapt its result rather than repeat it.', 'Self-supervised next-token training on a massive corpus to learn general representations; the compute-dominant phase.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('rlhf', 'RLHF', 'Reinforcement Learning from Human Feedback', '', ARRAY['rlhf','reinforcement learning from human feedback']::text[], 'Core', 'Teaching a model to behave the way people prefer by turning human ratings into a training signal.', 'Like training a dog with treats — you can’t script every trick, so you reward the behaviors you want and it learns the pattern.', 'Humans rank several model answers best-to-worst; those rankings train a reward model, which then guides the language model toward preferred responses.', '[{"text":"What it refines.","id":"pretraining"},{"text":"The behavior it instills.","id":"instructionfollowing"},{"text":"The preference signal it turns into training.","id":"learningsignal"}]'::jsonb, 'RLHF collects human preference comparisons, fits a reward model to predict them, then uses reinforcement learning to nudge the base model toward high-reward outputs. It’s what turns a raw next-token predictor into a helpful, harmless assistant — but it can be gamed (reward hacking) and inherits the biases of whoever did the rating.', 'The step that makes a model feel aligned and usable; also where your values and rater choices get encoded.', 'Fit a reward model to human preference data, then optimize the policy against it (often PPO) with a KL penalty to the base.', 'Training', 80, ARRAY['seed','training']::text[])
insert into public.concepts
  (id, term, aliases, said, alias_list, status, one_liner, analogy, example, related, deeper, lens_pm, lens_eng, domain, priority, tags)
values
  ('rlaif', 'RLAIF', 'Reinforcement Learning from AI Feedback', '“R-L-A-I-F”', ARRAY['rlaif','reinforcement learning from ai feedback']::text[], 'Rising', 'Like RLHF, but another AI does the rating instead of humans, to save time and money.', 'Like grading a mountain of essays with a well-trained teaching assistant instead of the professor — faster, cheaper, and mostly consistent.', 'Instead of paying labelers to rank thousands of answers, a strong model scores them against a rubric and those scores train the target model.', '[{"text":"The human version is","id":"rlhf"},{"text":"often paired with","id":"constitutionalai"},{"text":"trains a","id":"rewardmodel"}]'::jsonb, 'RLAIF swaps human preference labels for judgments from an AI, often a larger model applying a written set of principles. It scales feedback far beyond what human raters could produce and cuts cost dramatically. The obvious risk is circularity: the student inherits the judge’s biases and blind spots, so a flawed evaluator quietly teaches flawed taste.', 'A way to scale alignment cheaply — but you’ve outsourced your taste to another model, flaws and all.', 'RLHF pipeline with an AI evaluator (often guided by a principles rubric) generating the preference signal.', 'Training', 60, ARRAY['seed','training']::text[]),
  ('rewardmodel', 'Reward model', '', '', ARRAY['reward model','preference model','rm']::text[], 'Core', 'A model trained to score answers the way humans would, so it can grade at scale during training.', 'Like teaching a judge your taste from a stack of ranked examples, then letting that judge score thousands more while you sleep.', 'Labelers rank a few thousand answer-pairs; a reward model learns from them and then rates millions of the LLM’s attempts.', '[{"text":"The engine inside","id":"rlhf"},{"text":"trained on","id":"preferencedata"},{"text":"avoided by","id":"dpo"}]'::jsonb, 'The reward model turns scattered human preferences into a single differentiable score the main model can optimize against. It’s the linchpin of RLHF — the policy chases higher reward. Its weakness is reward hacking: the model finds answers that score well without actually being good, because the reward model is an imperfect stand-in for real human judgment.', 'The frozen proxy for “what humans want”; if it’s miscalibrated, the whole tuned model drifts toward its blind spots.', 'A learned scalar scorer over responses, trained on preference pairs; the objective the RL policy optimizes.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('preferencedata', 'Preference data', '', '', ARRAY['preference data','preference pairs','comparison data']::text[], 'Core', 'Human (or AI) judgments of “this answer is better than that one,” used to teach models taste.', 'Like A/B taste tests: you don’t score each dish alone, you just say which of two you’d rather eat.', 'A labeler sees two model replies to the same question and marks the clearer, more helpful one as preferred.', '[{"text":"Trains a","id":"rewardmodel"},{"text":"consumed directly by","id":"dpo"},{"text":"gathered via","id":"hitl"}]'::jsonb, 'Rather than absolute scores, preference data captures relative rankings between responses, which humans give far more reliably than numeric grades. This pairwise signal trains reward models and drives methods like DPO. Its quality is everything: inconsistent, rushed, or biased comparisons teach the model the wrong preferences with perfect efficiency.', 'The raw material of alignment — the model’s manners are only as good as these comparisons.', 'Pairwise/ranked response comparisons; the training signal for reward models and preference-optimization losses.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('dpo', 'DPO', 'Direct Preference Optimization', '“D-P-O”', ARRAY['dpo','direct preference optimization']::text[], 'Rising', 'A simpler alternative to RLHF that tunes on preferences directly, skipping the separate reward model.', 'Like learning to cook straight from “diners preferred dish A over B” feedback, without first hiring a critic to translate it into scores.', 'A team fine-tunes on ranked answer-pairs with DPO and gets aligned behavior without standing up a reward model and RL loop.', '[{"text":"A leaner substitute for","id":"rlhf"},{"text":"skips the","id":"rewardmodel"},{"text":"trained on","id":"preferencedata"}]'::jsonb, 'DPO reframes preference learning as a single classification-style loss on the pairs, mathematically implying the reward instead of training one explicitly. That removes the fragile, moving-parts RL pipeline (reward model plus PPO) and is more stable and easier to run. The trade-off: less flexible than full RL for some objectives, and still bounded by the quality of the preference data.', 'Why alignment got cheaper and more teams can do it — fewer moving parts than classic RLHF.', 'Closed-form preference loss that optimizes the policy directly on pairs, implicitly encoding the reward; no separate RM/PPO.', 'Training', 60, ARRAY['seed','training']::text[]),
  ('constitutionalai', 'Constitutional AI', 'Constitutional AI', '“C-A-I”', ARRAY['constitutional ai','cai']::text[], 'Rising', 'Aligning a model against a written set of principles instead of case-by-case human labels.', 'Like giving an employee a clear code of conduct and letting them self-correct against it, rather than a manager approving every single action.', 'A model critiques and revises its own answers against rules like “be helpful but don’t assist harm,” and those revisions train the final model.', '[{"text":"A structured form of","id":"rlaif"},{"text":"an approach to","id":"alignment"}]'::jsonb, 'Constitutional AI, introduced by Anthropic, writes down explicit principles (a “constitution”) and has the model use them to critique and improve its own outputs, generating training data with minimal human labeling. It makes the values steering the model explicit and auditable, and scales better than hand-labeling every case. It still depends on the wisdom of the principles and the model’s ability to apply them faithfully.', 'Values you can read and revise, not buried in opaque labels — useful when you need to explain why a model behaves as it does.', 'Self-critique/revision against a written principle set to generate alignment data; a structured form of AI feedback.', 'Training', 60, ARRAY['seed','training']::text[]),
  ('instructiontuning', 'Instruction tuning', '', '', ARRAY['instruction tuning','instruct tuning','instruction fine-tuning']::text[], 'Core', 'Fine-tuning a base model on example commands and good responses so it learns to follow directions.', 'Like taking a brilliant but literal new hire and running them through orientation until they reliably do what you ask, how you ask.', 'A base model is trained on thousands of “instruction → ideal answer” pairs, turning raw text prediction into a usable assistant.', '[{"text":"A form of","id":"sft"},{"text":"applied after","id":"pretraining"},{"text":"usually before","id":"rlhf"}]'::jsonb, 'Pretraining leaves a model good at continuing text but not at obeying requests; instruction tuning fixes that with supervised examples of instructions paired with desired outputs. It’s usually the first alignment step, often followed by preference tuning like RLHF or DPO. It’s what converts a base model into something that answers questions instead of just autocompleting them.', 'The step that makes a model act like an assistant; without it, even a huge model feels unusable.', 'Supervised fine-tuning on (instruction, response) pairs to induce instruction-following before preference optimization.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('sft', 'Supervised fine-tuning', 'Supervised Fine-Tuning', '“S-F-T”', ARRAY['supervised fine-tuning','sft']::text[], 'Core', 'Training a model on labeled input-output examples to teach it a specific behavior or format.', 'Like showing an apprentice hundreds of worked problems with the correct answers until they reproduce the method.', 'You collect 5,000 “customer message → ideal reply” pairs and fine-tune so the model matches your support tone exactly.', '[{"text":"The general case is","id":"finetuning"},{"text":"includes","id":"instructiontuning"},{"text":"complemented by","id":"rlhf"}]'::jsonb, 'SFT is the straightforward flavor of fine-tuning: given inputs paired with the right outputs, minimize the error between prediction and target. It’s the backbone of instruction tuning and most task-specific adaptation. Its limits: it teaches imitation of the examples, so it can only be as good as the labeled data and can’t easily learn from “this is better than that” comparisons — which is where preference methods come in.', 'The most direct way to shape behavior when you have clean examples of exactly what you want.', 'Standard supervised learning on (input, target) pairs; the imitation step preceding preference optimization.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('alignment', 'Alignment', '', '', ARRAY['alignment','ai alignment','aligned']::text[], 'Core', 'The work of making a model’s behavior match human intentions and values, not just its literal training objective.', 'Like the gap between a genie granting your exact words and one granting what you actually meant — alignment is aiming for the second.', 'A model that refuses to help build a weapon but happily explains chemistry safely is showing alignment between capability and intent.', '[{"text":"Pursued via","id":"rlhf"},{"text":"and","id":"constitutionalai"},{"text":"a defense against reward hacking in the","id":"rewardmodel"}]'::jsonb, 'Alignment spans everything from surface manners to deep safety: the model should be helpful, honest, and harmless, and should pursue what we want rather than a proxy that merely correlates with it. Techniques like RLHF, DPO, and constitutional methods are practical alignment tools. The hard part is that we often can’t fully specify our own values, and optimizing a proxy can drift in unintended ways — the core worry as models get more capable.', 'The difference between a model that’s smart and one that’s trustworthy; it’s a product requirement, not an afterthought.', 'Making learned behavior track intended goals/values rather than a mis-specified proxy objective.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('lora', 'LoRA', 'Low-Rank Adaptation', '“LOR-uh”', ARRAY['lora','low-rank adaptation']::text[], 'Rising', 'A cheap way to fine-tune by training tiny add-on matrices instead of the model’s billions of weights.', 'Like adding sticky notes to a reference book instead of reprinting the whole thing — small, removable, and you can keep several sets.', 'You adapt a 7B model to legal writing by training a few million LoRA parameters on one GPU, leaving the base weights untouched.', '[{"text":"A form of","id":"peft"},{"text":"a kind of","id":"adapter"},{"text":"memory-frugal variant is","id":"qlora"}]'::jsonb, 'LoRA freezes the original weights and learns small low-rank matrices that adjust each layer’s behavior, cutting trainable parameters by orders of magnitude. This slashes memory and cost, and the adapters are swappable — one base model, many specialties. It usually matches full fine-tuning on narrow tasks, though it can lag on the most demanding adaptations.', 'Why custom models got affordable — train a tiny adapter, keep dozens of “personalities” on one base.', 'Injects trainable low-rank matrices into frozen layers; drastically fewer trainable params, mergeable at inference.', 'Training', 60, ARRAY['seed','training']::text[]),
  ('qlora', 'QLoRA', 'Quantized Low-Rank Adaptation', '“Q-LOR-uh”', ARRAY['qlora','quantized lora']::text[], 'Rising', 'LoRA on a compressed model, so you can fine-tune a large model on a single consumer GPU.', 'Like renovating a house after shrinking your tools to fit a small van — you lose almost nothing but suddenly it all fits in your garage.', 'A researcher fine-tunes a 65B model on one 24GB GPU by quantizing the base to 4-bit and training LoRA adapters on top.', '[{"text":"A memory-saving take on","id":"lora"},{"text":"a form of","id":"peft"}]'::jsonb, 'QLoRA quantizes the frozen base model to 4-bit to shrink its memory footprint, then trains LoRA adapters in higher precision on top. The quantized weights stay fixed, so the precision loss barely hurts, while memory drops enough to fine-tune huge models on modest hardware. It democratized large-model fine-tuning, moving it from data centers to enthusiasts’ desks.', 'The reason fine-tuning big models stopped requiring a server farm — huge for cost and accessibility.', '4-bit quantized frozen base + higher-precision LoRA adapters; large memory savings with near-full-precision quality.', 'Training', 60, ARRAY['seed','training']::text[]),
  ('peft', 'PEFT', 'Parameter-Efficient Fine-Tuning', '“PEFT”', ARRAY['peft','parameter-efficient fine-tuning']::text[], 'Rising', 'A family of methods that adapt a model by training a small slice of parameters, not the whole thing.', 'Like customizing a car with bolt-on accessories instead of rebuilding the engine — cheaper, reversible, and you keep the original.', 'A team uses PEFT to spin up ten task-specific variants of one base model, each adding only a few megabytes of trained parameters.', '[{"text":"Includes","id":"lora"},{"text":"and","id":"adapter"},{"text":"contrast with full","id":"finetuning"}]'::jsonb, 'PEFT is the umbrella over techniques — LoRA, adapters, prompt tuning — that freeze most of the model and train only a small set of new or selected parameters. This cuts compute, memory, and storage, and makes adaptations portable and stackable. It rarely beats full fine-tuning on the hardest tasks, but it wins overwhelmingly on cost and flexibility, which is why it dominates practical tuning.', 'The category that made custom models routine — small, swappable, cheap adaptations of one shared base.', 'Umbrella for methods training a small parameter subset atop a frozen model (LoRA, adapters, prompt tuning).', 'Training', 60, ARRAY['seed','training']::text[]),
  ('adapter', 'Adapter', '', '', ARRAY['adapter','adapter module','adapter layers']::text[], 'Core', 'A small trainable module slipped between a frozen model’s layers to teach it a new skill.', 'Like plug-in expansion cards for a computer — the machine stays the same; you add a card for the new capability.', 'You insert adapter modules into a frozen base model and train just those to specialize it for medical text.', '[{"text":"A form of","id":"peft"},{"text":"closely related to","id":"lora"}]'::jsonb, 'Adapters add small bottleneck layers inside the network and train only them while the base stays frozen, making adaptation cheap and modular. Different adapters can be swapped in for different tasks on the same shared model. LoRA is a close relative that adapts existing weights rather than inserting new layers; both fall under PEFT.', 'Modular skills for one base model — mix and match without retraining the whole thing.', 'Inserted bottleneck modules trained while the backbone is frozen; a PEFT approach, kin to LoRA.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('distillation', 'Distillation', '', '', ARRAY['distillation','model distillation']::text[], 'Core', 'Compressing a big model’s know-how into a smaller one that mimics its behavior.', 'Like boiling a rich stock down to a concentrated cube — far smaller, most of the flavor kept.', 'A large model’s answers train a compact model that runs ten times faster while behaving nearly the same on everyday tasks.', '[{"text":"The detailed form is","id":"knowledgedistillation"},{"text":"uses a","id":"studentmodel"},{"text":"and a","id":"teachermodel"}]'::jsonb, 'Distillation trains a small student to reproduce a large teacher’s outputs — its predictions or full probability distributions — packing more signal into fewer parameters than training from scratch. The payoff is speed, cost, and on-device deployment; the ceiling is the teacher, whose mistakes and biases the student inherits. It’s the standard bridge from a frontier model to a shippable small one.', 'How you turn an expensive model into a cheap, fast one that’s good enough for most requests.', 'Train a compact student to match a teacher’s outputs/soft targets; smaller and faster, capped by the teacher.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('knowledgedistillation', 'Knowledge distillation', '', '', ARRAY['knowledge distillation','kd']::text[], 'Core', 'Distillation done by matching the teacher’s full confidence spread, not just its final answers.', 'Like learning from a mentor who not only gives the answer but tells you how sure they were about each option — the near-misses teach you too.', 'A student trains on the teacher’s soft probabilities (“80% cat, 15% dog, 5% fox”), absorbing nuance a hard “cat” label would hide.', '[{"text":"The core method within","id":"distillation"},{"text":"produces a","id":"studentmodel"}]'::jsonb, 'Classic knowledge distillation, from Hinton and colleagues, trains the student on the teacher’s softened output distribution rather than one-hot labels. Those “soft targets” carry dark knowledge — the relative likelihoods across wrong answers — which conveys more than a single correct label. This lets small models learn faster and generalize better than training on hard labels alone.', 'The technique behind small models that punch above their weight; the teacher’s uncertainty is part of the lesson.', 'Train the student on the teacher’s soft (temperature-scaled) output distribution; soft targets carry extra signal.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('continuedpretraining', 'Continued pretraining', '', '', ARRAY['continued pretraining','continual pretraining','domain-adaptive pretraining']::text[], 'Rising', 'Keeping the pretraining going on a new corpus so a model soaks up a fresh domain or language.', 'Like sending a well-read generalist to live in a new field for a year — same person, now fluent in the local dialect and specifics.', 'A general model gets continued pretraining on a big pile of legal documents so it internalizes legal language before any fine-tuning.', '[{"text":"Extends","id":"pretraining"},{"text":"risks","id":"catastrophicforgetting"},{"text":"broader than","id":"finetuning"}]'::jsonb, 'Rather than task-specific fine-tuning, continued pretraining runs the same self-supervised objective on additional domain data to broadly shift the model’s knowledge. It’s useful for specialized fields, new languages, or fresher data. The main hazard is catastrophic forgetting — pushing too hard on new data can erode the general abilities the base model started with, so data mixing and careful rates matter.', 'How you make a model natively fluent in your domain — deeper than fine-tuning, but riskier and pricier.', 'Additional self-supervised pretraining on new-domain data; balances adaptation against catastrophic forgetting.', 'Training', 60, ARRAY['seed','training']::text[]),
  ('catastrophicforgetting', 'Catastrophic forgetting', '', '', ARRAY['catastrophic forgetting','catastrophic interference']::text[], 'Core', 'When training a model on something new makes it abruptly lose skills it already had.', 'Like cramming for a new language so hard that last year’s subject leaks out of your head entirely.', 'You fine-tune a model heavily on legal text and suddenly it’s worse at basic math it used to handle easily.', '[{"text":"A danger of","id":"continuedpretraining"},{"text":"and","id":"finetuning"},{"text":"mitigated by","id":"peft"}]'::jsonb, 'Neural networks store knowledge in shared weights, so updating them for a new task can overwrite the patterns that supported old ones. It’s a central obstacle to sequential learning and aggressive fine-tuning. Mitigations include mixing old data back in, freezing parts of the network, using PEFT so the base stays intact, or regularizing weights to resist large changes.', 'Why fine-tuning can quietly degrade a model elsewhere — always test the skills you didn’t train on.', 'Overwriting of prior representations during new-task training; countered by rehearsal, freezing, PEFT, or regularization.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('syntheticdata', 'Synthetic data', '', '', ARRAY['synthetic data','generated data','model-generated data']::text[], 'Rising', 'Training data made by a model rather than collected from the real world.', 'Like a flight simulator generating endless practice scenarios so pilots don’t need a real storm to train on.', 'A strong model writes thousands of math problems with worked solutions, and those become training data for a smaller model.', '[{"text":"A source for","id":"sft"},{"text":"often produced by a","id":"teachermodel"},{"text":"a form of","id":"dataaugmentation"}]'::jsonb, 'Synthetic data lets teams manufacture examples where real data is scarce, private, or expensive, and to target specific weaknesses. Used well, it boosts capability cheaply; used carelessly, it risks model collapse — training on a model’s own averaged output can erode diversity and amplify its errors over generations. Quality control and grounding in real data are the guardrails.', 'A powerful way to cover gaps and rare cases — but data made by models can quietly inbreed if you’re not careful.', 'Model-generated training examples; scalable but risks distribution collapse without real-data anchoring/filtering.', 'Training', 60, ARRAY['seed','training']::text[]),
  ('dataaugmentation', 'Data augmentation', '', '', ARRAY['data augmentation','augmentation']::text[], 'Core', 'Expanding a dataset by making tweaked copies of what you already have.', 'Like practicing a recipe with slight variations each time — different pans, small substitutions — so you can cook it in any kitchen.', 'A vision model’s training images get flipped, cropped, and recolored, multiplying the dataset and teaching robustness.', '[{"text":"Reduces","id":"overfitting"},{"text":"improves","id":"generalization"},{"text":"overlaps with","id":"syntheticdata"}]'::jsonb, 'Augmentation transforms existing examples in label-preserving ways — rotations for images, paraphrases or back-translation for text — to increase variety without collecting new data. It reduces overfitting and improves generalization by exposing the model to more surface variation. The catch: transformations that change the true label, or that don’t reflect real-world variation, teach the wrong lesson.', 'A cheap robustness boost from data you already own — squeeze more learning from every example.', 'Label-preserving transformations that expand data variety; curbs overfitting, improves generalization.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('labeling', 'Labeling', '', '', ARRAY['labeling','labelling','data labeling']::text[], 'Core', 'Attaching the correct answer to each training example so a model can learn from it.', 'Like a teacher writing the right answer beside each practice problem before handing the worksheet to a student.', 'Reviewers tag ten thousand emails as “spam” or “not spam” so a classifier has ground truth to learn from.', '[{"text":"Closely tied to","id":"annotation"},{"text":"the fuel for","id":"supervisedlearning"}]'::jsonb, 'Supervised learning needs examples paired with target outputs, and labeling is the human-heavy process of producing them. It’s often the costliest, slowest part of a project, and label quality caps model quality — noisy or inconsistent labels teach noise. Guidelines, multiple raters, and agreement checks are how teams keep labels trustworthy.', 'Usually the real bottleneck in an ML project — slow, expensive, and quality-limiting.', 'Assigning target outputs to examples for supervised training; label noise directly bounds achievable accuracy.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('annotation', 'Annotation', '', '', ARRAY['annotation','data annotation','annotator']::text[], 'Core', 'Marking up data with the extra information a model needs to learn — labels, spans, boxes, rankings.', 'Like a copy editor marking a manuscript: highlighting names, flagging sections, noting what’s what for whoever reads it next.', 'Annotators draw boxes around every pedestrian in dashcam frames so a detection model knows what to find.', '[{"text":"A superset of","id":"labeling"},{"text":"often done with","id":"hitl"}]'::jsonb, 'Annotation is the broader craft around labeling: not just a class, but bounding boxes, entity spans, relationships, or preference rankings, guided by detailed instructions. Clear guidelines and inter-annotator agreement matter because ambiguous tasks yield inconsistent data. It’s where much of a dataset’s cost and quality is decided, well before any model runs.', 'The unglamorous work that determines whether your data is worth training on at all.', 'Enriching raw data with structured labels/markup per guidelines; consistency measured via inter-annotator agreement.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('datacontamination', 'Data contamination', '', '', ARRAY['data contamination','test set contamination','benchmark contamination']::text[], 'Rising', 'When test questions leak into training data, so a model’s scores look better than its real ability.', 'Like a student who secretly saw the exam beforehand — the perfect grade tells you nothing about what they actually learned.', 'A benchmark’s questions turn up in the web-scraped training set, and the model “aces” them by recall, not reasoning.', '[{"text":"Fought with","id":"deduplication"},{"text":"undermines","id":"evals"},{"text":"a hazard in","id":"pretraining"}]'::jsonb, 'Because pretraining scrapes huge swaths of the web, public benchmarks often end up inside the training data, inflating evaluation scores. It’s a major reason leaderboard numbers can mislead and why fresh, held-out, or private test sets matter. Detecting it is hard — you’re looking for overlap in trillions of tokens — so teams increasingly favor recently-created or canary-marked benchmarks.', 'Why you shouldn’t trust a shiny benchmark number at face value — the test may have leaked into training.', 'Overlap between eval and training data inflating metrics; mitigated by held-out/fresh/canary test sets and dedup.', 'Training', 60, ARRAY['seed','training']::text[]),
  ('deduplication', 'Deduplication', '', '', ARRAY['deduplication','dedup','dedupe']::text[], 'Core', 'Removing repeated or near-identical examples from a dataset before training.', 'Like clearing duplicate photos off your phone so one over-shared meme doesn’t crowd out your actual memories.', 'A web crawl has the same article mirrored a thousand times; dedup keeps one copy so the model doesn’t over-weight it.', '[{"text":"Reduces","id":"datacontamination"},{"text":"and","id":"overfitting"},{"text":"cleans data for","id":"pretraining"}]'::jsonb, 'Large corpora are full of exact and near-duplicate text, and training on repeats wastes compute, encourages memorization, and can worsen contamination. Deduplication — exact matching and fuzzy near-dup detection — improves efficiency and generalization and reduces regurgitation of memorized passages. It’s a boring but high-leverage data-cleaning step that measurably improves models.', 'A cheap data-hygiene step that makes models train faster and memorize less — quietly important.', 'Exact/near-duplicate removal from corpora; cuts memorization and contamination, improves training efficiency.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('curriculumlearning', 'Curriculum learning', '', '', ARRAY['curriculum learning','curriculum training']::text[], 'Core', 'Training a model on easy examples first, then gradually harder ones — like a school syllabus.', 'Like teaching arithmetic before calculus: the early, simple lessons build the footing the hard ones stand on.', 'A code model trains first on short, simple snippets, then longer and trickier programs as it improves.', '[{"text":"A strategy within","id":"training"},{"text":"shapes the","id":"learningsignal"}]'::jsonb, 'Curriculum learning orders training data from simple to complex so early, easy signal builds representations that make later, hard examples learnable. It can speed convergence and improve final quality, echoing how people learn. The tricky parts are defining “difficulty” and pacing the ramp — a badly designed curriculum can help little or even hurt versus plain random ordering.', 'Sometimes teaching order matters — structuring the data can beat throwing everything in at once.', 'Ordering training examples easy→hard to ease optimization; benefit depends on a good difficulty measure and pacing.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('selfsupervisedlearning', 'Self-supervised learning', 'Self-Supervised Learning', '“S-S-L”', ARRAY['self-supervised learning','ssl','self-supervision']::text[], 'Core', 'Learning from raw data by hiding part of it and predicting the missing piece — no human labels needed.', 'Like learning a language by covering the last word of sentences you read and guessing it, over and over.', 'Predicting the next token across trillions of words is self-supervised: the text itself provides the “answer.”', '[{"text":"The engine of","id":"pretraining"},{"text":"contrast with","id":"supervisedlearning"},{"text":"and","id":"unsupervisedlearning"}]'::jsonb, 'Self-supervised learning invents its own labels from the structure of the data — next-token prediction, masked-word filling — so it can train on unlabeled corpora at massive scale. This is the trick that made pretraining possible: the internet becomes training data without anyone labeling it. It gives models broad general knowledge, which supervised fine-tuning then shapes toward specific behavior.', 'The breakthrough that let models learn from the whole internet without armies of labelers.', 'Supervision derived from the data itself (e.g. next-token/masked prediction); enables label-free pretraining at scale.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('unsupervisedlearning', 'Unsupervised learning', '', '', ARRAY['unsupervised learning','unsupervised']::text[], 'Core', 'Finding structure in data with no labels — the model discovers patterns on its own.', 'Like sorting a pile of mixed photos into natural groups without anyone telling you the categories.', 'A clustering algorithm groups customers into segments from their behavior, with no predefined labels to learn from.', '[{"text":"Contrast with","id":"supervisedlearning"},{"text":"overlaps with","id":"selfsupervisedlearning"}]'::jsonb, 'Unsupervised learning uncovers hidden structure — clusters, densities, low-dimensional representations — without target outputs. Classic examples are k-means clustering and dimensionality reduction. It overlaps with self-supervised learning, but the distinction is subtle: self-supervision manufactures prediction targets from the data, while pure unsupervised methods seek structure without any prediction target at all.', 'Useful when you have lots of data but no labels — it finds groupings and structure to act on.', 'Learning structure (clusters/manifolds) without labels or targets; distinct from self-supervised prediction tasks.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('supervisedlearning', 'Supervised learning', '', '', ARRAY['supervised learning','supervised']::text[], 'Core', 'Learning from examples where each input comes with the correct answer.', 'Like studying with an answer key — you check each attempt against the right answer and adjust.', 'Training a model to detect fraud from thousands of transactions each already marked “fraud” or “legit.”', '[{"text":"Needs","id":"labeling"},{"text":"contrast with","id":"unsupervisedlearning"},{"text":"and","id":"reinforcementlearning"}]'::jsonb, 'Supervised learning is the classic setup: given labeled input-output pairs, learn a mapping that predicts the output for new inputs. It’s the most direct and well-understood paradigm, powering classification and regression everywhere. Its bottleneck is labels — they’re expensive to produce and their quality caps performance, which is exactly why self-supervised pretraining became so attractive.', 'The dependable default when you have labeled data; its cost lives in getting those labels.', 'Learn input→output from labeled pairs (classification/regression); performance bounded by label quantity and quality.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('reinforcementlearning', 'Reinforcement learning', 'Reinforcement Learning', '“R-L”', ARRAY['reinforcement learning','rl']::text[], 'Core', 'Learning by trial and error, guided by rewards for good actions and penalties for bad ones.', 'Like training a dog with treats and “no” — behavior that earns reward gets repeated, behavior that doesn’t fades.', 'An agent learns to play a game by trying moves and getting points, gradually favoring the actions that win.', '[{"text":"The basis of","id":"rlhf"},{"text":"contrast with","id":"supervisedlearning"}]'::jsonb, 'Instead of labeled answers, RL gives an agent rewards for the outcomes of its actions, and it learns a policy that maximizes cumulative reward over time. The hard parts are delayed rewards (which action deserves credit?) and exploration versus exploitation. In language models, RL powers alignment: RLHF optimizes the model against a reward model trained on human preferences.', 'The paradigm behind alignment tuning and agents — useful when success is a signal, not a labeled answer.', 'Learn a policy maximizing cumulative reward via trial and error; credit assignment and exploration are core challenges.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('semisupervisedlearning', 'Semi-supervised learning', '', '', ARRAY['semi-supervised learning','semi-supervised']::text[], 'Core', 'Learning from a small labeled set plus a large pile of unlabeled data.', 'Like a teacher grading a few papers in detail, then trusting students to learn the rest from patterns in the unmarked stack.', 'You label 1,000 medical images and let the model exploit 100,000 unlabeled ones to sharpen its understanding.', '[{"text":"Blends","id":"supervisedlearning"},{"text":"and","id":"unsupervisedlearning"}]'::jsonb, 'Semi-supervised learning bridges supervised and unsupervised: a little labeled data anchors the task while abundant unlabeled data reveals structure that improves generalization. Techniques include pseudo-labeling and consistency training. It shines when labels are scarce or costly but raw data is plentiful — a very common real-world situation.', 'The pragmatic middle path when labeling everything is too expensive but you have plenty of raw data.', 'Combines limited labels with large unlabeled data (pseudo-labels/consistency) to improve over supervised-only.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('transferlearning', 'Transfer learning', '', '', ARRAY['transfer learning','transfer']::text[], 'Core', 'Reusing what a model learned on one task to jump-start a related one.', 'Like a guitarist picking up the ukulele fast — the fingers already know most of what they need.', 'A model pretrained on general text is fine-tuned on legal documents, reaching good accuracy with far less legal data.', '[{"text":"Underlies","id":"finetuning"},{"text":"builds on","id":"pretraining"},{"text":"related to","id":"multitasklearning"}]'::jsonb, 'Transfer learning takes representations learned on a large, general task and adapts them to a new, often smaller task, saving data and compute. It’s the whole logic of the pretrain-then-fine-tune era: learn broadly once, specialize cheaply many times. It works because low-level features (grammar, edges, structure) generalize; it can falter when source and target domains are too dissimilar.', 'The reason you rarely start from scratch — borrow a strong base and specialize for a fraction of the cost.', 'Adapt representations from a source task to a target task; the foundation of the pretrain→fine-tune paradigm.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('multitasklearning', 'Multitask learning', '', '', ARRAY['multitask learning','multi-task learning','mtl']::text[], 'Core', 'Training one model on several tasks at once so they reinforce each other.', 'Like a decathlete whose sprint training also helps their long jump — skills share a common base and lift together.', 'A single model is trained to translate, summarize, and answer questions, and gets better at each than if trained alone.', '[{"text":"Related to","id":"transferlearning"},{"text":"and","id":"metalearning"}]'::jsonb, 'Multitask learning shares parameters across related tasks, letting the model learn common structure and regularize itself, often improving each task and data efficiency. The risk is negative transfer — conflicting tasks can drag each other down — and balancing their losses is fiddly. Modern instruction-tuned models are effectively massively multitask, trained on many task types together.', 'One model that does many things can be cheaper and stronger than many narrow ones — if the tasks play nicely.', 'Joint training on multiple tasks with shared parameters; shared structure helps, but negative transfer can hurt.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('metalearning', 'Meta-learning', '', '', ARRAY['meta-learning','meta learning','learning to learn']::text[], 'Rising', 'Training a model to get good at learning new tasks quickly, not just at one task.', 'Like a student who has learned how to study, so each new subject clicks faster than the last.', 'A meta-learned model adapts to a brand-new classification task from just a handful of examples, having practiced adapting many times.', '[{"text":"Related to","id":"fewshotlearning"},{"text":"and","id":"incontextlearning"}]'::jsonb, 'Meta-learning — “learning to learn” — trains across many tasks so the model acquires a strategy for fast adaptation, rather than mastering a single task. Approaches range from optimization-based methods that find easily-fine-tuned initializations to models that adapt in-context. It’s the formal cousin of what large models do when they pick up a task from a few prompt examples.', 'The idea behind models that adapt fast to new tasks with little data — flexibility as a trained skill.', 'Optimize across a task distribution for rapid adaptation; kin to in-context few-shot behavior in large models.', 'Training', 60, ARRAY['seed','training']::text[]),
  ('fewshotlearning', 'Few-shot learning', '', '', ARRAY['n-shot learning','few-shot classification']::text[], 'Core', 'The training goal of learning a new task from just a handful of labeled examples.', 'Like recognizing a new bird species after seeing two or three photos, because you already understand what makes birds differ.', 'A model trained for few-shot learning classifies a new category correctly after seeing only five labeled samples of it.', '[{"text":"Often achieved via","id":"metalearning"},{"text":"the inference-time analog is","id":"fewshot"}]'::jsonb, 'As a training paradigm, few-shot learning targets sample efficiency: build a model that generalizes to new classes or tasks from very little data, usually via meta-learning or strong pretrained representations. It’s distinct from in-context few-shot prompting, which achieves a similar effect at inference without weight updates. Both chase the same prize — doing more with fewer examples.', 'The ambition of “learn from almost nothing,” valuable wherever labeled data is scarce.', 'Learning to generalize from k examples per class, typically via meta-learning or pretrained features; the training-time analog of in-context few-shot.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('gradientdescent', 'Gradient descent', '', '', ARRAY['gradient descent','gd']::text[], 'Core', 'The optimization method that repeatedly nudges weights downhill to shrink the loss.', 'Like walking downhill in fog by always stepping in the steepest downward direction until you reach the valley.', 'Each training step, the model computes how wrong it is, then adjusts every weight a little in the direction that reduces the error.', '[{"text":"Follows the","id":"gradient"},{"text":"the scalable version is","id":"sgd"},{"text":"run by the","id":"optimizer"}]'::jsonb, 'Gradient descent iteratively updates parameters in the opposite direction of the loss gradient, scaled by a learning rate, to find a minimum. Plain (batch) gradient descent uses the whole dataset per step, which is accurate but slow; that impracticality at scale is why stochastic variants took over. It’s the fundamental optimization engine under nearly all neural network training.', 'The core mechanic of “the model learned” — countless tiny downhill steps on an error surface.', 'Iterative param update opposite the loss gradient, scaled by learning rate; full-batch form is the baseline for SGD.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('sgd', 'Stochastic gradient descent', 'Stochastic Gradient Descent', '“S-G-D”', ARRAY['stochastic gradient descent','sgd']::text[], 'Core', 'Gradient descent that updates using small random batches instead of the whole dataset, for speed.', 'Like adjusting a recipe after each small tasting rather than cooking the entire banquet before your first tweak.', 'Instead of processing all million examples per step, the model updates weights after each batch of 32, taking many more, faster steps.', '[{"text":"A scalable form of","id":"gradientdescent"},{"text":"batch size set by","id":"batchsize"},{"text":"refined by","id":"adam"}]'::jsonb, 'SGD estimates the gradient from a random mini-batch, making each step cheap and frequent; the noise it adds can even help escape shallow bad minima. It converges far faster in wall-clock time than full-batch descent on large data, at the cost of a noisier path. It’s the practical backbone of deep learning, and modern optimizers like Adam are refinements of it.', 'The reason training on huge datasets is even feasible — cheap, frequent updates instead of one giant one.', 'Gradient descent on random mini-batches; cheaper, noisier steps that scale to large data and aid escaping minima.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('backpropagation', 'Backpropagation', 'Backpropagation', '“backprop”', ARRAY['backpropagation','backprop','back-propagation']::text[], 'Core', 'The algorithm that figures out how much each weight contributed to the error, so it can be corrected.', 'Like tracing a factory defect back through the assembly line to see which station caused it, and by how much.', 'After a wrong prediction, backprop pushes the error signal backward layer by layer, giving each weight its share of the blame.', '[{"text":"Computes the","id":"gradient"},{"text":"used by","id":"gradientdescent"},{"text":"to reduce the","id":"lossfunction"}]'::jsonb, 'Backpropagation applies the chain rule from calculus to compute the gradient of the loss with respect to every weight efficiently, in a single backward pass through the network. It’s what makes training deep networks tractable — without it, computing all those derivatives would be hopeless. Paired with an optimizer, it’s the mechanism that turns “the model was wrong” into concrete weight updates.', 'The math that makes learning possible at all; you rarely touch it, but every trained model depends on it.', 'Chain-rule computation of loss gradients w.r.t. all params in one backward pass; feeds the optimizer.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('lossfunction', 'Loss function', '', '', ARRAY['loss function','loss','cost function']::text[], 'Core', 'The formula that scores how wrong the model is, giving training something to minimize.', 'Like a golf score — the lower the number, the better you’re doing, and every swing aims to bring it down.', 'A model’s loss on a batch is high when its predictions miss the targets; training keeps pushing that number lower.', '[{"text":"A common one is","id":"crossentropy"},{"text":"the thing","id":"gradientdescent"},{"text":"minimizes; broader term is","id":"objectivefunction"}]'::jsonb, 'The loss function turns the gap between predictions and targets into a single number that optimization minimizes. Its choice defines what “good” means — cross-entropy for classification, mean-squared error for regression, custom losses for special goals. Because the model optimizes exactly what you measure, a poorly chosen loss produces a model that’s technically great at the wrong thing.', 'You get the behavior you measure — the loss encodes your definition of success, so choose it carefully.', 'Scalar objective quantifying prediction error; its gradient drives all weight updates. Choice defines the target behavior.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('objectivefunction', 'Objective function', '', '', ARRAY['objective function','objective','criterion']::text[], 'Core', 'The quantity training tries to optimize — usually minimizing loss, sometimes maximizing reward.', 'Like the scoreboard a whole team plays toward — everything they do is in service of moving that one number the right way.', 'In supervised training the objective is to minimize loss; in RL it’s to maximize expected reward.', '[{"text":"A minimize-case is the","id":"lossfunction"},{"text":"in RL it’s the reward from the","id":"rewardmodel"},{"text":"may include","id":"regularization"}]'::jsonb, 'The objective function is the general term for what optimization targets; a loss function is the common minimize-this special case, while reinforcement learning maximizes an objective like expected return. It also often bundles in regularization terms that trade raw fit against simplicity. Whatever it is, the model will optimize it literally — which is why mis-specified objectives are a core source of surprising, unwanted behavior.', 'The single thing your model is truly trying to do; if it’s wrong, no amount of data fixes it.', 'The optimized quantity (loss to minimize or reward to maximize), possibly with regularizers; literally optimized, so specify carefully.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('learningrate', 'Learning rate', 'Learning Rate', '“L-R”', ARRAY['learning rate','lr','step size']::text[], 'Core', 'The size of the step training takes each time it adjusts the weights.', 'Like your stride walking downhill in fog — tiny steps are safe but slow; huge leaps are fast but you might overshoot the valley.', 'Set the learning rate too high and the loss bounces around or explodes; too low and training crawls for days.', '[{"text":"Scales each","id":"gradientdescent"},{"text":"step; varied by a","id":"lrschedule"},{"text":"ramped by","id":"warmup"}]'::jsonb, 'The learning rate scales how far each weight moves along the gradient per step, and it’s often the single most important hyperparameter. Too large and training diverges or oscillates; too small and it’s painfully slow or gets stuck. Because no single value is ideal throughout, most training uses a schedule that changes it over time, often with a warmup and decay.', 'The dial most likely to make or break a training run — worth tuning before almost anything else.', 'Scalar scaling the gradient step; the dominant hyperparameter, usually varied via a schedule with warmup/decay.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('lrschedule', 'Learning rate schedule', '', '', ARRAY['learning rate schedule','lr schedule','learning rate scheduler']::text[], 'Core', 'A plan for changing the learning rate during training instead of holding it fixed.', 'Like driving: accelerate gently from a stop, cruise, then ease off as you approach your exit.', 'Training warms up the rate for the first few hundred steps, holds it, then decays it smoothly toward zero near the end.', '[{"text":"Controls the","id":"learningrate"},{"text":"includes a","id":"warmup"},{"text":"used across","id":"training"}]'::jsonb, 'A schedule varies the learning rate over the course of training — common shapes include linear warmup followed by cosine or linear decay. Early warmup avoids destabilizing the fresh weights; later decay lets the model settle into a good minimum with smaller, finer steps. The right schedule can noticeably improve final quality and stability over any single fixed rate.', 'A quiet lever on final model quality — how you ramp and cool the learning rate matters.', 'Time-varying learning rate (e.g. warmup + cosine/linear decay); improves stability and final convergence.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('warmup', 'Warmup', '', '', ARRAY['warmup','warm-up','learning rate warmup']::text[], 'Core', 'Starting training with a small learning rate and ramping it up over the first steps.', 'Like stretching before a sprint — ease in so you don’t pull something at full speed from a cold start.', 'For the first 500 steps the learning rate climbs from near zero to its target, so early updates don’t blow up the model.', '[{"text":"The opening phase of a","id":"lrschedule"},{"text":"protects the","id":"learningrate"},{"text":"important for","id":"adamw"}]'::jsonb, 'At the start of training the weights are fresh and gradients can be large and erratic, so jumping straight to a high learning rate risks divergence. Warmup ramps the rate up gradually, letting the optimizer’s statistics and the weights stabilize before full-speed learning. It’s especially important for large models and adaptive optimizers, and is usually the front half of a full schedule.', 'A small safeguard that prevents big training runs from destabilizing in their fragile first moments.', 'Gradual learning-rate ramp over initial steps to stabilize early training; typically precedes decay.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('batchsize', 'Batch size', '', '', ARRAY['batch size','minibatch size','mini-batch']::text[], 'Core', 'How many examples the model looks at before making one weight update.', 'Like how many quiz answers you grade before adjusting your teaching — a few gives quick but jumpy feedback, many gives a steadier read.', 'A batch size of 256 means the model averages the error over 256 examples, then takes one optimization step.', '[{"text":"Defines each","id":"sgd"},{"text":"update; stretched by","id":"gradientaccumulation"},{"text":"interacts with","id":"learningrate"}]'::jsonb, 'Batch size trades gradient quality against speed and memory: larger batches give smoother, more reliable gradient estimates and use hardware efficiently, but need more memory and can generalize slightly worse. Smaller batches are noisier but sometimes find better minima. It interacts tightly with the learning rate — change one and you often must retune the other.', 'A core cost-and-quality knob; it’s bounded by your GPU memory and coupled to the learning rate.', 'Examples per gradient update; larger = smoother gradients + more memory, coupled to learning rate; extendable via accumulation.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('epoch', 'Epoch', '', '', ARRAY['epoch','epochs','training epoch']::text[], 'Core', 'One full pass of the model through the entire training dataset.', 'Like reading a whole textbook cover to cover once — an epoch is one complete read-through.', 'Training for three epochs means the model sees every example in the dataset three times.', '[{"text":"Composed of many","id":"iteration"},{"text":"too many risks","id":"overfitting"}]'::jsonb, 'An epoch is one complete sweep over all training data, made up of many iterations (one per batch). Too few epochs and the model underfits; too many and it starts memorizing and overfitting. Large-scale pretraining often runs less than a single epoch over a giant corpus, since seeing that much data even once is plenty — the concept matters most for smaller fine-tuning runs.', 'A rough dial on how long to train; more isn’t always better, since extra passes invite overfitting.', 'One full pass over the dataset (many iterations); count trades underfitting vs. overfitting.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('iteration', 'Iteration', '', '', ARRAY['iteration','training step','step']::text[], 'Core', 'A single weight update — one batch processed and one step taken.', 'Like a single stir of the pot: one small adjustment, repeated thousands of times to get the dish right.', 'With 10,000 examples and a batch size of 100, one epoch is 100 iterations.', '[{"text":"Many make up an","id":"epoch"},{"text":"each does one","id":"sgd"},{"text":"step of","id":"batchsize"}]'::jsonb, 'An iteration (or step) is the atomic unit of training: process one batch, compute the loss and gradient, and update the weights once. The number of iterations equals dataset size divided by batch size, times the number of epochs. Progress and learning-rate schedules are usually tracked in steps, which is why training dashboards count iterations, not epochs.', 'The granular unit training is measured in — loss curves and schedules move step by step.', 'One batch → one gradient update; steps = (dataset/batch) × epochs; the unit for schedules and logging.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('optimizer', 'Optimizer', '', '', ARRAY['optimizer','optimiser']::text[], 'Core', 'The algorithm that decides exactly how to update weights from the gradients each step.', 'Like a hiking guide who takes the “downhill” reading and decides the actual footing — pace, momentum, and where to place each step.', 'You switch the optimizer from plain SGD to AdamW and the model trains faster and more stably on the same data.', '[{"text":"Consumes the","id":"gradient"},{"text":"a simple one is","id":"sgd"},{"text":"a popular one is","id":"adamw"}]'::jsonb, 'The optimizer turns raw gradients into weight updates, often adding momentum and per-parameter adaptive step sizes to speed and stabilize training. Choices range from simple SGD with momentum to adaptive methods like Adam and AdamW, each with its own hyperparameters. It’s a major determinant of training speed and final quality, and it works hand in hand with the learning rate schedule.', 'A behind-the-scenes choice that shapes how fast and reliably a model trains.', 'Maps gradients to parameter updates (momentum, adaptive rates); e.g. SGD, Adam, AdamW; paired with an LR schedule.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('adam', 'Adam', 'Adaptive Moment Estimation', '“ADD-um”', ARRAY['adam','adam optimizer']::text[], 'Core', 'A popular optimizer that gives each weight its own adaptive step size, so training just works more often.', 'Like cruise control that also adjusts for each hill and curve — it adapts the pace per situation instead of one fixed speed.', 'A team reaches for Adam as the default optimizer because it trains reliably across many models with little tuning.', '[{"text":"A kind of","id":"optimizer"},{"text":"improves on","id":"sgd"},{"text":"refined by","id":"adamw"}]'::jsonb, 'Adam combines momentum (a running average of past gradients) with per-parameter scaling based on recent gradient magnitudes, so parameters with small or noisy gradients still move sensibly. This adaptivity makes it robust and fast with minimal tuning, which is why it became a default. Its main quirk is how it handles weight decay, which the AdamW variant fixes.', 'The dependable default optimizer — it trains most models well without fuss.', 'Momentum + per-parameter adaptive step sizes from first/second gradient moments; robust default, superseded by AdamW for decay.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('adamw', 'AdamW', 'Adam with decoupled Weight decay', '“ADD-um-double-you”', ARRAY['adamw','adam w']::text[], 'Core', 'A fixed-up version of Adam that handles weight decay correctly — now the standard for training big models.', 'Like the same trusty cruise control after a recall fixed a subtle wiring bug — same idea, but it behaves the way it should.', 'Most large language models are trained with AdamW because its weight decay generalizes better than plain Adam’s.', '[{"text":"Fixes","id":"adam"},{"text":"the decay term is","id":"weightdecay"},{"text":"paired with","id":"warmup"}]'::jsonb, 'In original Adam, weight decay got entangled with the adaptive scaling, weakening its regularizing effect. AdamW decouples weight decay from the gradient update so it acts as intended, improving generalization. That subtle correction made it the default optimizer for transformer and large-model training, usually paired with a warmup-and-decay learning rate schedule.', 'The optimizer behind most modern large models; a small fix that meaningfully helps generalization.', 'Adam with decoupled weight decay; standard for transformer/LLM training, typically with warmup + decay.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('weightdecay', 'Weight decay', '', '', ARRAY['weight decay','l2 regularization','l2 penalty']::text[], 'Core', 'Gently shrinking weights toward zero during training so the model stays simple and generalizes.', 'Like a tidy-desk rule that quietly clears clutter each day, keeping only what earns its place.', 'Adding weight decay stops a model from letting a few weights grow huge to memorize training quirks.', '[{"text":"A form of","id":"regularization"},{"text":"reduces","id":"overfitting"},{"text":"decoupled in","id":"adamw"}]'::jsonb, 'Weight decay penalizes large weights, nudging all of them slightly toward zero each step, which discourages the model from fitting noise and improves generalization. It’s closely related to L2 regularization, though how it’s applied differs between plain Adam and AdamW. Set too high it underfits by over-simplifying; too low and it barely helps — it’s a standard, mild regularizer in almost every training recipe.', 'A quiet guard against overfitting that’s in nearly every training recipe.', 'Penalty shrinking weights toward zero (≈ L2); improves generalization, decoupled in AdamW.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('regularization', 'Regularization', '', '', ARRAY['regularization','regularisation','regularizer']::text[], 'Core', 'Any technique that keeps a model from over-memorizing so it generalizes to new data.', 'Like a coach who stops you from over-optimizing your form for one practice court, so your game holds up anywhere.', 'Dropout, weight decay, and data augmentation are all regularization — each fights overfitting a different way.', '[{"text":"Includes","id":"weightdecay"},{"text":"and","id":"dropout"},{"text":"improves","id":"generalization"}]'::jsonb, 'Regularization is the umbrella for methods that constrain a model’s effective complexity to improve generalization: penalties on weights, dropout, early stopping, augmentation, and more. The goal is to shift the balance from fitting the training set toward performing on unseen data. Too much and the model underfits; the art is finding the sweet spot for your data size and task.', 'The family of tricks that make a model work in the real world, not just on its training set.', 'Techniques constraining effective capacity (weight decay, dropout, early stopping, augmentation) to improve generalization.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('gradientclipping', 'Gradient clipping', '', '', ARRAY['gradient clipping','grad clipping','clip gradients']::text[], 'Core', 'Capping how big a gradient step can be, so one wild update doesn’t wreck the model.', 'Like a governor on an engine that prevents it from redlining and blowing up on a sudden surge.', 'A rare huge gradient would send the loss to infinity, but clipping caps its size and training keeps going smoothly.', '[{"text":"Tames the","id":"gradient"},{"text":"stabilizes","id":"gradientdescent"},{"text":"guards the","id":"learningrate"}]'::jsonb, 'Occasionally gradients explode — becoming enormous — and a single unclipped step can push weights into garbage, spiking the loss to NaN. Gradient clipping bounds the gradient’s norm (or value) before the update, keeping training stable through rough patches. It’s cheap insurance widely used in training deep and recurrent networks, especially with high learning rates or long sequences.', 'A stability safeguard that keeps long, expensive training runs from suddenly falling apart.', 'Bounds gradient norm/value before the update to prevent explosions; standard for stability in deep/recurrent training.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('gradientaccumulation', 'Gradient accumulation', '', '', ARRAY['gradient accumulation','grad accumulation']::text[], 'Core', 'Summing gradients over several small batches before updating, to fake a bigger batch than memory allows.', 'Like filling a big order in several small trips because your cart is tiny — you still deliver the full load, just in pieces.', 'Your GPU fits only 8 examples, but you accumulate over 32 mini-batches to update as if the batch size were 256.', '[{"text":"Simulates a larger","id":"batchsize"},{"text":"defers the","id":"optimizer"},{"text":"step across","id":"iteration"}]'::jsonb, 'When the desired batch size won’t fit in memory, gradient accumulation runs several forward-backward passes, adds up their gradients, and applies one optimizer step, simulating a large effective batch. This lets modest hardware train with the stability benefits of big batches, trading time for memory. The effective batch size is the per-step batch times the accumulation count.', 'How you get big-batch training on small hardware — trading wall-clock time for memory you don’t have.', 'Accumulate gradients over N micro-batches, then one optimizer step; effective batch = micro-batch × N.', 'Training', 80, ARRAY['seed','training']::text[])
insert into public.concepts
  (id, term, aliases, said, alias_list, status, one_liner, analogy, example, related, deeper, lens_pm, lens_eng, domain, priority, tags)
values
  ('mixedprecision', 'Mixed precision', 'Mixed-Precision Training', '', ARRAY['mixed precision','mixed-precision training','fp16 training','bf16 training']::text[], 'Core', 'Do most of the training math in low-precision numbers to go faster and use less memory, keeping full precision only where it matters.', 'Rounding to the nearest cent while you shop, but keeping the exact figures for the final tax return.', 'A team switches a training run to bf16 and suddenly the same GPUs fit a bigger batch and finish an epoch in half the time.', '[{"text":"Pairs with this to fit bigger models in memory.","id":"checkpointing"},{"text":"The numbers being rounded are the model weights.","id":"weights"}]'::jsonb, 'Weights and activations are stored and multiplied in 16-bit floats (fp16 or bf16) instead of 32-bit, which roughly halves memory and speeds up the matrix math on modern accelerators. The catch is numerical stability — tiny gradients can underflow to zero — so a full-precision master copy of the weights and loss scaling are kept to stop the training from quietly diverging.', 'It is most of why training the same model got cheaper and faster over the last few years, without changing the recipe.', 'Store/compute in fp16 or bf16 with an fp32 master weight copy and dynamic loss scaling to avoid gradient underflow.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('checkpointing', 'Checkpointing', 'Gradient / Activation Checkpointing', '', ARRAY['checkpointing','gradient checkpointing','activation checkpointing']::text[], 'Core', 'Save memory during training by throwing away intermediate results and recomputing them later, trading extra compute for a smaller footprint.', 'Not keeping every rough draft on your desk — you rewrite a page when you need it instead of storing all of them.', 'A model that would not fit on a single GPU suddenly trains fine once activation checkpointing is turned on, at the cost of a slightly slower step.', '[{"text":"Often used together to squeeze a model onto the hardware.","id":"mixedprecision"},{"text":"A memory-saving trick during the training loop.","id":"training"}]'::jsonb, 'A normal backward pass needs the activations from the forward pass held in memory. Checkpointing keeps only a few of them and recomputes the rest on demand during backprop. You pay for it with a second partial forward pass, but peak memory drops sharply — often the difference between a run that fits and one that OOMs.', 'One of the levers that lets a bigger model train on the hardware you already have.', 'Discard intermediate activations and recompute them in the backward pass to cut peak memory at the cost of ~30% more compute.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('earlystopping', 'Early stopping', 'Early Stopping', '', ARRAY['early stopping','early-stopping']::text[], 'Core', 'Stop training the moment the model stops getting better on held-out data, before it starts memorizing.', 'Taking the cake out when the toothpick comes clean, not leaving it in until the edges burn.', 'A run keeps improving on the training data but its validation loss ticks up at epoch 12 — early stopping halts there and keeps the epoch-11 weights.', '[{"text":"The signal it watches to decide when to quit.","id":"validationset"},{"text":"The thing it is trying to prevent.","id":"overfitting"}]'::jsonb, 'You watch a validation metric each epoch and stop when it has not improved for a set number of rounds (the patience), keeping the best checkpoint seen. It is a cheap, effective guard against overfitting because the point where validation stops improving is roughly where the model shifts from learning patterns to memorizing noise.', 'A simple way to avoid wasting compute and shipping an over-trained model that looks great on paper and worse in the wild.', 'Monitor a validation metric with a patience counter; restore the best checkpoint when it plateaus or regresses.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('validationset', 'Validation set', 'Validation Set / Dev Set', '', ARRAY['validation set','dev set','development set','val set']::text[], 'Core', 'A slice of data the model never trains on, used to tune choices and check progress honestly.', 'The practice exam you grade yourself on — not the real test, but a fair read on whether you are ready.', 'The team compares two learning rates by which one scores better on the validation set, then locks that choice in.', '[{"text":"The data the model actually learns from.","id":"trainingset"},{"text":"The untouched final exam.","id":"testset"},{"text":"Uses this signal to know when to stop.","id":"earlystopping"}]'::jsonb, 'Data is split into training, validation, and test. The validation set guides decisions during development — when to stop, which hyperparameters to pick — without touching the final test set. Because you make choices based on it, the model indirectly adapts to it, which is why the untouched test set still matters for the honest final number.', 'It is how you tell real progress from wishful thinking while a model is still being built.', 'A held-out split used for hyperparameter selection and early stopping, kept separate from the final test set.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('trainingset', 'Training set', 'Training Set / Train Split', '', ARRAY['training set','train split','training data split']::text[], 'Core', 'The data the model actually learns from — the examples it sees over and over.', 'The textbook chapters you study from, as opposed to the exam that tests you on them.', 'A sentiment model is fit on 80,000 labeled reviews in the training set, leaving the rest for validation and test.', '[{"text":"The honest check the model never learns from.","id":"validationset"},{"text":"The final untouched exam.","id":"testset"},{"text":"The huge unlabeled version for base models.","id":"pretrainingcorpus"}]'::jsonb, 'This is the largest split, the material the optimizer minimizes loss over. Everything the model knows traces back to it, which is why its size, quality, and balance matter more than almost any other choice. Anything that leaks from validation or test into here quietly inflates your scores.', 'The quality ceiling of your model is mostly set here — garbage in, garbage out.', 'The split gradients are computed over; guard it against contamination from val/test data.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('testset', 'Test set', 'Test Set / Holdout Test', '', ARRAY['test set','test split','held-out test set']::text[], 'Core', 'The data you touch exactly once, at the very end, to get an honest read on how the model actually does.', 'The sealed final exam — you only open it when you are truly done studying.', 'After weeks of tuning on validation, the team runs the model on the test set a single time and reports that number.', '[{"text":"The dev-time signal you tune against instead.","id":"validationset"},{"text":"What ruins a test set silently.","id":"datacontamination"}]'::jsonb, 'The test set must stay untouched during development, because every peek lets you unconsciously tune toward it and inflate the result. Its whole value is that the model has never adapted to it, so the score generalizes. The moment test data leaks into training — contamination — that guarantee is gone.', 'The one number you can actually trust when deciding whether to ship.', 'A one-shot held-out evaluation split; any reuse or leakage compromises its estimate of generalization.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('holdout', 'Holdout', 'Holdout Set', '', ARRAY['holdout','holdout set','held-out data']::text[], 'Core', 'Any chunk of data you deliberately set aside and keep the model from seeing, so you can test it fairly.', 'Hiding a few puzzle pieces so you can check later whether someone actually solved it or just memorized the picture.', 'Before training, the team carves off 10% of records as a holdout and does not look at it again until the end.', '[{"text":"A holdout used during development.","id":"validationset"},{"text":"Rotates the holdout to use all the data.","id":"crossvalidation"}]'::jsonb, 'Holdout is the general idea behind validation and test splits: withhold data so evaluation reflects performance on examples the model never learned. Simple holdout uses one fixed slice; when data is scarce, cross-validation rotates the holdout across the whole set to use every example both ways.', 'The basic discipline that keeps a demo honest — no holdout, no trustworthy number.', 'Data withheld from training for unbiased evaluation; the fixed-split alternative to cross-validation.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('crossvalidation', 'Cross-validation', 'K-Fold Cross-Validation', '', ARRAY['cross-validation','cross validation','k-fold','k-fold cross-validation']::text[], 'Core', 'Rotate which slice of data is held out so every example gets to be both study material and test, then average the scores.', 'Five friends take turns being the quiz-master while the others answer, so everyone gets tested and no single split decides it.', 'With only 2,000 samples, a team runs 5-fold cross-validation and reports the average accuracy across the five folds.', '[{"text":"The single-split version it generalizes.","id":"holdout"},{"text":"A per-run holdout used during tuning.","id":"validationset"}]'::jsonb, 'Split the data into k folds; train on k−1 and evaluate on the one left out, cycling through so each fold is the holdout once. Averaging the k scores gives a more stable estimate than a single split, which matters most when data is limited. The cost is training k times, so it is common in classic ML and rare for giant models.', 'Buys you a trustworthy number when you do not have enough data to spare a big test set.', 'Partition into k folds, train/evaluate k times rotating the held-out fold, and average the metric.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('hyperparameter', 'Hyperparameter', 'Hyperparameter', '', ARRAY['hyperparameter','hyper-parameter','hyperparameters']::text[], 'Core', 'A setting you choose before training that shapes how learning happens, as opposed to a weight the model learns on its own.', 'The oven temperature and bake time — you set them; the cake does not decide them for you.', 'Learning rate, batch size, and number of layers are all hyperparameters picked before the run starts.', '[{"text":"The process of searching over these settings.","id":"hyperparametertuning"},{"text":"The single most sensitive one.","id":"learningrate"},{"text":"What the model learns instead.","id":"parameters"}]'::jsonb, 'Parameters (weights) are learned by gradient descent; hyperparameters are the dials outside that loop — learning rate, batch size, dropout, architecture size. They are not differentiable with respect to the loss, so you cannot train them directly; you search over them by trying values and comparing on validation data.', 'The knobs that decide whether a training run succeeds, wastes money, or quietly underperforms.', 'Configuration set outside the optimization loop; tuned via search rather than gradients.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('hyperparametertuning', 'Hyperparameter tuning', 'Hyperparameter Optimization', '', ARRAY['hyperparameter tuning','hyperparameter optimization','hpo','hyperparameter search']::text[], 'Core', 'The trial-and-error hunt for the training settings that make a model work best.', 'Dialing in a new espresso machine — adjust grind, dose, and time, taste, repeat until it is right.', 'A team sweeps learning rates from 1e-5 to 1e-3 and batch sizes of 16, 32, 64, then keeps the combo with the best validation loss.', '[{"text":"The settings being searched over.","id":"hyperparameter"},{"text":"The brute-force version of the search.","id":"gridsearch"}]'::jsonb, 'Because hyperparameters are not learned by gradients, you search: try configurations, measure each on validation data, keep the winner. Strategies range from brute-force grid search to random search to smarter Bayesian methods that spend trials where they seem promising. The cost is that each trial is a full training run, so it gets expensive fast at scale.', 'Often the difference between a mediocre and a strong model — and a real line item in the compute budget.', 'Search over hyperparameters (grid, random, or Bayesian) using validation performance as the objective.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('gridsearch', 'Grid search', 'Grid Search', '', ARRAY['grid search','grid-search']::text[], 'Fading', 'Try every combination of a fixed set of settings, exhaustively, and pick the best.', 'Testing every pairing on a menu — each starter with each main — to find the one you like most.', 'A team lists 3 learning rates and 3 batch sizes and runs all 9 combinations to see which wins.', '[{"text":"The broader activity it is one method for.","id":"hyperparametertuning"}]'::jsonb, 'Grid search enumerates the full Cartesian product of candidate values. It is simple and reproducible but scales terribly — adding one more hyperparameter multiplies the runs — and it wastes effort on dimensions that barely matter. Random search often finds comparable settings for less compute, which is why grid search is fading for anything beyond a couple of knobs.', 'Thorough but expensive; fine for a tiny search, wasteful for a big one.', 'Exhaustive evaluation over the Cartesian product of hyperparameter values; cost grows exponentially with dimensions.', 'Training', 30, ARRAY['seed','training']::text[]),
  ('scalinglaws', 'Scaling laws', 'Neural Scaling Laws', '', ARRAY['scaling laws','scaling law','neural scaling laws']::text[], 'Core', 'The predictable way model quality improves as you add more data, parameters, and compute — smooth enough to plan around.', 'Knowing that doubling the ingredients and oven time reliably yields a bigger, better-baked loaf — the recipe scales.', 'Before committing to a huge run, a lab uses scaling-law curves fit on small models to predict the loss the big one will hit.', '[{"text":"Uses scaling laws to balance model and data size.","id":"chinchillascaling"},{"text":"The compute-efficient point on the curve.","id":"computeoptimal"},{"text":"Capabilities scaling laws do not directly predict.","id":"emergence"}]'::jsonb, 'Empirically, test loss falls as a power law in model size, dataset size, and compute — straight lines on a log-log plot across many orders of magnitude. This let labs forecast returns and justify spending on ever-larger runs. The laws describe loss, not capability, and they do not promise where useful behaviors emerge, so they guide budgets more than they guarantee outcomes.', 'The reason "just make it bigger" became a credible strategy — the payoff was forecastable.', 'Power-law relationships between test loss and compute/params/data used to extrapolate and allocate budgets.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('computeoptimal', 'Compute-optimal', 'Compute-Optimal Training', '', ARRAY['compute-optimal','compute optimal','compute-optimal training']::text[], 'Rising', 'Splitting a fixed compute budget between model size and data so you get the lowest loss for the money.', 'With a set grocery budget, choosing the mix of ingredients that makes the best meal — not just the biggest one.', 'Given a fixed number of GPU-hours, a team picks a smaller model trained on more tokens because the math says it lands lower loss than a bigger, under-fed one.', '[{"text":"The result that defined this sweet spot.","id":"chinchillascaling"},{"text":"The curves this optimizes along.","id":"scalinglaws"},{"text":"The ratio at the heart of the trade-off.","id":"tokensperparameter"}]'::jsonb, 'For a fixed compute budget, there is a sweet spot in how you trade parameters against training tokens. The Chinchilla work showed many large models were over-parameterized and under-trained — too big for the data they saw. Compute-optimal means sitting at that frontier, though it optimizes training cost, not inference cost, so deployment concerns can push you smaller still.', 'It reframed "bigger is better" into "right-sized for the data" — and made many models cheaper to serve.', 'Allocate a fixed FLOPs budget between N (params) and D (tokens) to minimize loss, per Chinchilla-style scaling.', 'Training', 60, ARRAY['seed','training']::text[]),
  ('chinchillascaling', 'Chinchilla scaling', 'Chinchilla-Optimal Scaling', '', ARRAY['chinchilla scaling','chinchilla-optimal','chinchilla scaling laws']::text[], 'Rising', 'The finding that for a given compute budget, models should be smaller and trained on far more data than people assumed.', 'Realizing a smaller pot on the stove longer cooks better than a giant pot rushed — more time with the heat beats sheer size.', 'Chinchilla matched a much larger model using fewer parameters but roughly four times the training tokens, at the same compute.', '[{"text":"The general principle it is the flagship result of.","id":"computeoptimal"},{"text":"The ratio it pinned down.","id":"tokensperparameter"},{"text":"The curves it sits on.","id":"scalinglaws"}]'::jsonb, 'DeepMind''s 2022 study showed the compute-optimal ratio is roughly 20 training tokens per parameter — meaning earlier giant models were under-trained. It shifted the field toward smaller, data-hungrier models, which also happen to be cheaper to run. In practice teams now often train well past the Chinchilla point because inference savings justify over-training a smaller model.', 'It quietly rewrote sizing decisions industry-wide and made strong small models the norm.', 'Empirical result: ~20 tokens/param is compute-optimal; smaller models on more data beat larger under-trained ones.', 'Training', 60, ARRAY['seed','training']::text[]),
  ('datamixture', 'Data mixture', 'Training Data Mixture', '', ARRAY['data mixture','data mix','training data mixture']::text[], 'Rising', 'The recipe of how much of each kind of data — web, code, books, math — goes into training, and in what proportion.', 'A coffee blend: the ratio of beans changes the whole cup, even with the same total amount.', 'A team bumps the share of code and math in the mixture and the model gets noticeably better at reasoning, at a slight cost to prose.', '[{"text":"The full pool the mixture is drawn from.","id":"pretrainingcorpus"},{"text":"How sources are cleaned before mixing.","id":"datacuration"}]'::jsonb, 'Pretraining data comes from many sources with very different value, and their proportions strongly shape the final model. Teams up-weight high-quality or scarce domains, sometimes repeat certain sources, and tune the blend by training small proxy models. The mixture is one of the most guarded and impactful recipes in a lab, because it trades strengths off against each other.', 'A hidden dial that decides what your model is naturally good and bad at.', 'The sampling proportions across data sources during pretraining; tuned via proxy runs and domain weighting.', 'Training', 60, ARRAY['seed','training']::text[]),
  ('tokensperparameter', 'Tokens per parameter', 'Token-to-Parameter Ratio', '', ARRAY['tokens per parameter','token-to-parameter ratio','tokens-per-parameter']::text[], 'Rising', 'How many training tokens each model parameter gets to learn from — a rough gauge of whether a model is well-fed or starved.', 'Students per teacher: too many and each gets too little attention; the ratio tells you if the class is well-served.', 'A 7B model trained on 2 trillion tokens sees about 285 tokens per parameter — far past the Chinchilla point of 20, on purpose.', '[{"text":"The study that fixed the optimal value near 20.","id":"chinchillascaling"},{"text":"The trade-off this ratio expresses.","id":"computeoptimal"}]'::jsonb, 'Divide training tokens by parameter count. Chinchilla put the compute-optimal ratio near 20, but modern small models are trained to hundreds of tokens per parameter because over-training a small model buys cheaper inference. A low ratio suggests an under-trained, over-sized model; a very high one means you are spending extra training compute to save at serving time.', 'A quick sniff test for whether a model is right-sized for its data budget.', 'Training tokens ÷ parameters; ~20 is compute-optimal, higher trades train cost for inference savings.', 'Training', 60, ARRAY['seed','training']::text[]),
  ('emergence', 'Emergence', 'Emergent Behavior', '', ARRAY['emergence','emergent behavior','emergent behaviour']::text[], 'Rising', 'When a capability appears fairly suddenly at a certain scale, seeming absent in smaller models and present in bigger ones.', 'Water that just sits there as you heat it — until it hits a boil and abruptly changes state.', 'Small models score near-random on multi-step arithmetic, then past a size threshold they start getting it right, seemingly out of nowhere.', '[{"text":"Predicts loss but not when abilities appear.","id":"scalinglaws"},{"text":"The broader notion of scale-unlocked skills.","id":"emergentability"}]'::jsonb, 'As models scale, some skills improve smoothly while others look like sharp jumps. Debate continues over how "real" the sharpness is — some apparent leaps flatten out under smoother metrics, suggesting the jump is partly an artifact of harsh pass/fail scoring. Either way, it complicates planning: scaling laws predict loss well but not exactly when a given ability shows up.', 'Why you cannot always promise a feature at a target size — some abilities only show up when they show up.', 'Capabilities that appear abruptly with scale; partly metric-dependent and not directly forecast by loss curves.', 'Training', 60, ARRAY['seed','training']::text[]),
  ('rewardhacking', 'Reward hacking', 'Reward Hacking / Specification Gaming', '', ARRAY['reward hacking','specification gaming','reward gaming']::text[], 'Rising', 'When a model learns to game the score instead of doing the thing the score was supposed to measure.', 'A student who memorizes the answer key instead of learning the subject — perfect grade, no understanding.', 'A model rewarded for helpful-sounding answers learns to be verbose and flattering, scoring high while actually being less useful.', '[{"text":"The proxy being exploited.","id":"rewardmodel"},{"text":"Adjusting rewards, which can invite this.","id":"rewardshaping"},{"text":"A common hacked behavior.","id":"rewardsignal"}]'::jsonb, 'Any reward is a proxy for what you really want, and optimizers exploit the gap. During RL fine-tuning a model may find shortcuts — sycophancy, padding, exploiting quirks of the reward model — that boost the number without improving the true goal. It is why reward models need to be robust, why KL penalties keep the policy from drifting too far, and why human spot-checks stay in the loop.', 'A core reason a model can ace its metrics and still feel worse to real users.', 'The policy exploits flaws in the reward proxy; mitigated by robust reward models, KL constraints, and held-out human eval.', 'Training', 60, ARRAY['seed','training']::text[]),
  ('rewardshaping', 'Reward shaping', 'Reward Shaping', '', ARRAY['reward shaping','shaped reward']::text[], 'Core', 'Adding extra hints to the reward so the model gets feedback along the way, not just at the very end.', 'Giving a kid "warmer, warmer, colder" clues while they search, instead of only saying "found it" at the end.', 'Rather than rewarding only a fully correct final answer, a trainer gives partial credit for each valid reasoning step to guide learning.', '[{"text":"What careless shaping can cause.","id":"rewardhacking"},{"text":"The base signal being shaped.","id":"rewardsignal"}]'::jsonb, 'Sparse rewards are hard to learn from because most actions get zero signal. Shaping adds intermediate rewards to point the model toward good behavior sooner. The danger is that a poorly shaped reward changes what is optimal and invites reward hacking — the model chases the hints rather than the real goal — so shaping has to be designed carefully to preserve the true objective.', 'Speeds up learning on hard tasks, but a sloppy shaping function can teach the wrong lesson.', 'Augment sparse rewards with intermediate signals; keep them potential-based to avoid altering the optimal policy.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('policygradient', 'Policy gradient', 'Policy Gradient Methods', '', ARRAY['policy gradient','policy gradients','policy gradient methods']::text[], 'Core', 'A way to train by nudging the model to make rewarded actions more likely and penalized ones less likely.', 'Training a dog with treats — reward the behaviors you want and they happen more; ignore the ones you do not.', 'During RLHF, a policy-gradient update pushes up the probability of responses the reward model liked and pushes down the ones it disliked.', '[{"text":"The stabilized workhorse version.","id":"ppo"},{"text":"The setting it is used in.","id":"reinforcementlearning"}]'::jsonb, 'Policy-gradient methods directly optimize the model (the policy) by estimating how changing an action''s probability affects expected reward, then stepping in that direction. They are noisy because reward is sparse and estimates are high-variance, which is why practical algorithms like PPO add tricks — clipping, baselines, KL penalties — to keep updates stable.', 'The learning machinery underneath reinforcement-learning fine-tuning like RLHF.', 'Optimize expected reward by ascending the gradient of log-prob weighted by advantage; high variance, stabilized by PPO-style methods.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('ppo', 'PPO', 'Proximal Policy Optimization', '“P-P-O”', ARRAY['ppo','proximal policy optimization']::text[], 'Core', 'The reinforcement-learning algorithm that powered classic RLHF, designed to improve the model without letting each update lurch too far.', 'Adjusting a recipe one careful pinch at a time — never dumping in a whole cup and ruining the batch.', 'A lab fine-tunes a chat model with PPO against a reward model, keeping a KL leash so it stays close to the original model.', '[{"text":"The family of methods it belongs to.","id":"policygradient"},{"text":"The training regime it implements.","id":"rlhf"},{"text":"The leash that keeps it close to the base model.","id":"kldivergence"},{"text":"The simpler alternative that skips the RL loop.","id":"dpo"}]'::jsonb, 'PPO is a policy-gradient method that caps how much the policy can change per step, using a clipped objective and a KL penalty against a reference model. That restraint is what makes RL on language models stable enough to work. It is effective but fiddly — many moving parts and hyperparameters — which is part of why simpler alternatives like DPO gained ground.', 'The engine behind the first wave of aligned chat models; powerful but operationally heavy.', 'Clipped-objective policy gradient with a KL penalty to a reference policy, stabilizing RLHF updates.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('kldivergence', 'KL divergence', 'Kullback–Leibler Divergence', '“K-L divergence”', ARRAY['kl divergence','kullback-leibler divergence','kl penalty']::text[], 'Core', 'A measure of how far one probability distribution has drifted from another — used as a leash to keep a fine-tuned model near its original.', 'A tether on a climber: it lets them move around but yanks back if they stray too far from base camp.', 'In RLHF, a KL penalty rises as the tuned model''s outputs diverge from the base model, discouraging it from going off the rails to chase reward.', '[{"text":"Uses it as a constraint each step.","id":"ppo"},{"text":"A related information-theoretic loss.","id":"crossentropy"}]'::jsonb, 'KL divergence quantifies the difference between two distributions and is not symmetric — the direction matters. In RL fine-tuning it appears as a penalty term measuring how far the current policy has moved from the reference model; this keeps the model from exploiting the reward at the cost of coherence or safety. It also shows up broadly in training objectives like variational methods.', 'The safety tether that stops reward-chasing from turning a good model into a weird one.', 'A non-symmetric distance between distributions; used as a regularizing penalty against a reference policy in RLHF.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('rewardsignal', 'Reward signal', 'Reward Signal', '', ARRAY['reward signal','reward']::text[], 'Core', 'The number that tells a reinforcement-learning model how good an action or output was — the thing it tries to maximize.', 'The score in a video game: it is the only feedback telling you whether that last move helped or hurt.', 'A reward model scores each candidate response, and that score is the reward signal the policy learns to push upward.', '[{"text":"Usually produces this signal.","id":"rewardmodel"},{"text":"Adding intermediate versions of it.","id":"rewardshaping"},{"text":"What a bad signal invites.","id":"rewardhacking"}]'::jsonb, 'In RL the model does not get labeled right answers; it gets a scalar reward and figures out which behaviors produce more of it. The signal can be sparse (only at the end) or shaped (along the way), and it is always a proxy for the true goal — which is why a flawed reward signal leads straight to reward hacking. Its quality bounds how good the trained model can get.', 'Whatever you actually reward is what you actually get — so defining it well is half the battle.', 'The scalar feedback the policy optimizes; sparse or shaped, and always a proxy prone to exploitation.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('humanfeedback', 'Human feedback', 'Human Feedback', '', ARRAY['human feedback','human preferences','human ratings']::text[], 'Core', 'People judging model outputs — usually by comparing them — to teach the model what "good" looks like.', 'A taste-test panel picking which of two dishes they prefer, over and over, until the chef learns the room.', 'Annotators are shown two model replies and click the better one; thousands of these comparisons train the reward model.', '[{"text":"The framework it feeds.","id":"rlhf"},{"text":"Keeping people in the loop generally.","id":"hitl"},{"text":"The dataset it produces.","id":"preferencedata"}]'::jsonb, 'Human feedback is how fuzzy human values — helpful, honest, harmless — get injected into training. It usually takes the form of pairwise preferences rather than absolute scores, since people are more consistent at comparing than rating. Those preferences train a reward model or feed directly into methods like DPO. Its limits are human ones: bias, fatigue, and disagreement all leak in.', 'The raw material that turns a raw predictor into something people actually want to talk to.', 'Human preference judgments (often pairwise) used to train reward models or drive preference optimization.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('preferenceoptimization', 'Preference optimization', 'Preference Optimization', '', ARRAY['preference optimization','preference-based optimization','preference learning']::text[], 'Rising', 'Training a model directly from "this answer is better than that one" comparisons to make preferred outputs more likely.', 'Teaching taste by always pointing at the better of two plates, until the cook internalizes what you like.', 'Instead of running full RL, a team applies DPO on a dataset of chosen-vs-rejected pairs and the model shifts toward the chosen style.', '[{"text":"The method that popularized skipping RL.","id":"dpo"},{"text":"The data it consumes.","id":"preferencedata"},{"text":"The RL-based approach it competes with.","id":"rlhf"}]'::jsonb, 'This family reframes alignment as learning from pairwise preferences. Classic RLHF does it indirectly — train a reward model, then optimize with RL. Newer methods like DPO skip the separate reward model and the RL loop, deriving an objective that directly raises the probability of preferred responses over dispreferred ones. Simpler and more stable, though sometimes less flexible than full RL.', 'The trend that made preference-based training cheaper and more reliable to run.', 'Optimize a policy on chosen/rejected pairs; DPO-style objectives bypass an explicit reward model and RL loop.', 'Training', 60, ARRAY['seed','training']::text[]),
  ('rejectionsampling', 'Rejection sampling', 'Rejection Sampling', '', ARRAY['rejection sampling','rejection-sampling']::text[], 'Rising', 'Generate several candidate answers, keep only the good ones, and train on those.', 'Baking a dozen cookies, keeping the best few, and photographing only those for the recipe card.', 'A model produces eight solutions per math problem; a checker keeps the correct ones, and those become new training data.', '[{"text":"The inference-time cousin that keeps just one.","id":"bestofn"},{"text":"The generation step it filters.","id":"sampling"}]'::jsonb, 'Rejection sampling filters a model''s own generations by some quality bar — a verifier, a reward model, or an exact-answer check — and fine-tunes on the survivors. It is a simple, stable way to bootstrap a model on its better outputs, closely related to best-of-n but used to build a training set rather than to pick a single response at inference time.', 'A cheap way to squeeze more quality out of a model using its own best work.', 'Sample n candidates, keep those passing a quality/verifier filter, and fine-tune on the accepted set.', 'Training', 60, ARRAY['seed','training']::text[]),
  ('bestofn', 'Best-of-n', 'Best-of-N Sampling', '', ARRAY['best-of-n','best of n','bon sampling']::text[], 'Rising', 'Generate several answers and return only the one a scorer likes best — better output for more compute.', 'Asking three people to draft the same email and sending only the strongest one.', 'For a tricky query, the system samples five completions, ranks them with a reward model, and shows the top-ranked reply.', '[{"text":"The training-data version of the same idea.","id":"rejectionsampling"},{"text":"The scorer that picks the winner.","id":"rewardmodel"}]'::jsonb, 'Best-of-n trades inference compute for quality: sample n candidates, score them with a reward or verifier, output the winner. It reliably lifts quality but with diminishing returns and n-times the cost. It is closely tied to rejection sampling — same generate-and-filter idea — and its scores can be distilled back into the model so you get the benefit without paying at serve time.', 'A dial to buy better answers with more compute, useful when quality matters more than latency.', 'Sample n outputs, rank with a scorer, return the argmax; quality rises sublinearly with n.', 'Training', 60, ARRAY['seed','training']::text[]),
  ('selfdistillation', 'Self-distillation', 'Self-Distillation', '', ARRAY['self-distillation','self distillation']::text[], 'Rising', 'A model teaching itself by training on its own best outputs, rather than learning from a bigger teacher.', 'Reviewing your own strongest essays and studying them to write even better ones next time.', 'A model generates answers, keeps the ones a verifier approves, and fine-tunes on them — bootstrapping itself upward without a larger model.', '[{"text":"The teacher-student version it is derived from.","id":"distillation"},{"text":"The self-generated data it relies on.","id":"syntheticdata"}]'::jsonb, 'Ordinary distillation transfers knowledge from a large teacher to a smaller student. Self-distillation drops the separate teacher: the model produces outputs, filters them for quality, and trains on the survivors, often over several rounds. It works because generating a good answer can be easier than learning to produce it consistently. Gains taper and can amplify the model''s own biases, so filtering quality is everything.', 'A way to improve a model without access to a bigger one — but it can entrench existing quirks.', 'Train a model on its own filtered generations, iteratively, without a separate teacher network.', 'Training', 60, ARRAY['seed','training']::text[]),
  ('teacherforcing', 'Teacher forcing', 'Teacher Forcing', '', ARRAY['teacher forcing','teacher-forcing']::text[], 'Core', 'During training, feed the model the real previous word instead of its own guess, so mistakes do not snowball.', 'A music teacher who plays the correct next note for a student mid-piece, so one slip does not derail the whole song.', 'While training a language model, each step is conditioned on the true prior tokens from the text, not on what the model itself predicted.', '[{"text":"The generation style it trains.","id":"autoregressive"},{"text":"The objective it is used with.","id":"nexttokenprediction"}]'::jsonb, 'Autoregressive models generate one token from the previous ones. Teacher forcing trains them on the ground-truth prefix rather than their own outputs, which makes training stable and parallelizable. The downside is exposure bias: at inference the model must feed on its own outputs, so early errors can compound — a mismatch between how it was trained and how it actually runs.', 'A training shortcut that speeds learning but partly explains why long generations can drift.', 'Condition each training step on ground-truth prior tokens; efficient but introduces exposure bias at inference.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('labelsmoothing', 'Label smoothing', 'Label Smoothing', '', ARRAY['label smoothing','label-smoothing']::text[], 'Core', 'Tell the model the right answer is "very likely" rather than "100% certain," so it stays humble and generalizes better.', 'A teacher who marks the answer correct but reminds you nothing is ever quite certain, keeping you from overconfidence.', 'Instead of a target of exactly 1.0 for the correct class, training uses 0.9, spreading the remaining 0.1 across the others.', '[{"text":"The loss it modifies.","id":"crossentropy"},{"text":"The problem it helps guard against.","id":"overfitting"},{"text":"The broader family it belongs to.","id":"regularization"}]'::jsonb, 'Standard cross-entropy pushes the model toward assigning all probability to the correct token, which encourages overconfidence and sharp, brittle outputs. Label smoothing softens the target — a little probability mass is spread to the wrong classes — which regularizes the model, improves calibration, and often generalizes better. Too much smoothing, though, blurs genuine distinctions.', 'A small tweak that makes a model''s confidence more trustworthy and less brittle.', 'Replace one-hot targets with a softened distribution; regularizes and improves calibration under cross-entropy.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('datacuration', 'Data curation', 'Data Curation', '', ARRAY['data curation','dataset curation','data curating']::text[], 'Core', 'The careful work of choosing, cleaning, and organizing training data so a model learns from good material.', 'A librarian deciding which books belong on the shelf and which get pulled — the collection is only as good as the choices.', 'Before a pretraining run, a team dedupes documents, strips boilerplate, drops low-quality pages, and balances the sources.', '[{"text":"The filtering step within it.","id":"datafiltering"},{"text":"The proportions it sets.","id":"datamixture"},{"text":"The raw pool it refines.","id":"pretrainingcorpus"}]'::jsonb, 'Curation spans deduplication, quality filtering, removing toxic or private content, balancing domains, and deciding what to include at all. It is unglamorous but decisive — many of the biggest quality jumps between model generations came from better data, not bigger models. The hard part is that "quality" is fuzzy and every filter trades some coverage for cleanliness.', 'Often the highest-leverage, least-visible work behind a model that just feels better.', 'The pipeline of selection, cleaning, dedup, and balancing that determines pretraining data quality.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('datafiltering', 'Data filtering', 'Data Filtering', '', ARRAY['data filtering','data filter','content filtering']::text[], 'Core', 'Automatically dropping unwanted data — junk, duplicates, toxic or unsafe content — before it reaches training.', 'A coffee filter: it lets the good stuff through and holds back the grounds.', 'A classifier flags spam, gibberish, and near-duplicate pages, and those documents never make it into the training set.', '[{"text":"The narrower quality-focused version.","id":"qualityfiltering"},{"text":"The broader process it is part of.","id":"datacuration"},{"text":"A specific filtering step.","id":"deduplication"}]'::jsonb, 'Filtering applies rules and learned classifiers to remove data you do not want the model to learn from: boilerplate, machine-translated junk, adult or harmful content, personal information, and duplicates. It is a core piece of curation. The tension is precision versus recall — aggressive filters cut noise but also throw away useful examples and can bake in the filter''s own biases.', 'Decides what your model never sees — and therefore some of what it will never do.', 'Rule- and classifier-based removal of low-quality, unsafe, or duplicate documents from the corpus.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('qualityfiltering', 'Quality filtering', 'Quality Filtering', '', ARRAY['quality filtering','quality filter','quality classifier']::text[], 'Rising', 'Keeping only the higher-quality documents by scoring each one and dropping the bottom of the barrel.', 'Grading apples and shipping only the ones above a certain bar, composting the bruised ones.', 'A classifier trained to recognize well-written pages scores the web crawl, and only documents above a threshold are kept.', '[{"text":"The broader filtering step it lives in.","id":"datafiltering"},{"text":"The overall data process.","id":"datacuration"}]'::jsonb, 'A specific slice of filtering focused on "is this good writing/useful content" rather than "is this unsafe." Often a small model is trained to imitate a known-good reference (say, curated encyclopedic text) and used to score the rest of the corpus. It reliably boosts model quality, but the reference defines "quality," so the choice quietly shapes what the model treats as normal or authoritative.', 'A big lever on final model quality — and on whose writing style gets treated as the standard.', 'Score documents with a learned quality classifier against a reference distribution and threshold the corpus.', 'Training', 60, ARRAY['seed','training']::text[]),
  ('datapipeline', 'Data pipeline', 'Data Pipeline', '', ARRAY['data pipeline','data-processing pipeline','preprocessing pipeline']::text[], 'Core', 'The assembly line that turns raw data into clean, tokenized, training-ready batches.', 'A factory line: raw ingredients go in one end, cleaned and packaged product comes out the other.', 'Raw web dumps flow through the pipeline — deduped, filtered, tokenized, shuffled, and sharded — before the trainer ever sees a batch.', '[{"text":"The judgment-heavy part of the pipeline.","id":"datacuration"},{"text":"A step near the end of it.","id":"tokenization"}]'::jsonb, 'The pipeline is the engineered sequence of steps between raw sources and the optimizer: ingestion, cleaning, filtering, deduplication, tokenization, shuffling, and sharding into an efficient on-disk format. At scale it must be fast and reproducible, because reprocessing petabytes is expensive. Bugs here — a bad shuffle, a leaky filter — silently corrupt training in ways that are hard to trace later.', 'Invisible plumbing whose reliability quietly determines whether a training run is trustworthy.', 'The reproducible ETL from raw sources to tokenized, shuffled, sharded training batches.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('pretrainingcorpus', 'Pretraining corpus', 'Pretraining Corpus', '', ARRAY['pretraining corpus','pretraining data','training corpus']::text[], 'Core', 'The giant pile of mostly-web text (and code, and more) a base model reads to learn language in the first place.', 'The entire library a student reads growing up — it shapes everything they later know or assume.', 'A base model''s pretraining corpus might be trillions of tokens drawn from web crawls, books, code, and reference sites.', '[{"text":"The stage that consumes it.","id":"pretraining"},{"text":"A major source within it.","id":"webcrawl"},{"text":"The proportions across sources.","id":"datamixture"}]'::jsonb, 'Pretraining is where the model gets its raw knowledge and language ability, and the corpus is its whole world at that stage. Its scale is measured in trillions of tokens, its composition (the data mixture) shapes strengths and biases, and whatever is absent from it the model simply will not know. Later fine-tuning polishes behavior but rarely adds fundamentally new knowledge the corpus lacked.', 'The source of a model''s baseline knowledge — and of the blind spots you inherit.', 'The large, mostly self-supervised text corpus consumed during pretraining; defines the model''s knowledge base.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('webcrawl', 'Web crawl', 'Web Crawl Data', '', ARRAY['web crawl','web-crawled data','crawled web data']::text[], 'Core', 'Text scraped in bulk from across the public internet — the messy backbone of most pretraining data.', 'Emptying the whole internet into a bin and then sorting it — most of the volume, most of the mess.', 'A team starts from a raw web crawl of billions of pages, then filters it down to the fraction worth training on.', '[{"text":"The best-known public crawl.","id":"commoncrawl"},{"text":"The pool it feeds.","id":"pretrainingcorpus"}]'::jsonb, 'Web crawls provide the sheer scale that pretraining needs, but they are enormously noisy — spam, boilerplate, duplicates, machine text, and worse. Their usefulness depends almost entirely on aggressive cleaning and filtering afterward. Common Crawl is the best-known public source; labs also run private crawls. The web''s biases and gaps flow straight into the model unless curation catches them.', 'Cheap scale, but its raw quality is low — the value is in what you do to it after.', 'Bulk-scraped public web text; high-volume, low-signal until filtered and deduplicated.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('commoncrawl', 'Common Crawl', 'Common Crawl', '', ARRAY['common crawl','commoncrawl']::text[], 'Core', 'A free, public archive of web-crawl data that underpins a large share of AI training corpora.', 'A public reservoir everyone draws from — you still have to filter the water before you drink it.', 'Many open datasets start from Common Crawl snapshots, then apply their own cleaning to produce a usable subset.', '[{"text":"The kind of data it provides.","id":"webcrawl"},{"text":"What it ultimately feeds.","id":"pretrainingcorpus"}]'::jsonb, 'Common Crawl is a nonprofit that has crawled the web for years and releases petabyte-scale snapshots for free. It is the raw feedstock behind well-known derived datasets, which apply heavy filtering to it. Because so many models trace back to it, its coverage and gaps — languages, domains, time periods — quietly shape the field. It is raw material, not a ready-to-use dataset.', 'A shared starting point that makes strong base data accessible, but never usable straight out of the box.', 'Public multi-petabyte web-crawl snapshots used as the base feedstock for derived pretraining datasets.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('tokenizertraining', 'Tokenizer training', 'Tokenizer Training', '', ARRAY['tokenizer training','training a tokenizer','tokenizer fitting']::text[], 'Core', 'Building the model''s vocabulary by finding which character chunks are common enough to deserve their own token.', 'Deciding which phrases are common enough to earn a shorthand in your notes, so you write less.', 'A team runs byte-pair encoding over the corpus, merging frequent character pairs until it has a 100k-token vocabulary.', '[{"text":"The result it produces.","id":"vocabulary"},{"text":"The size decision it involves.","id":"vocabularysize"},{"text":"The common algorithm used.","id":"bytepairencoding"}]'::jsonb, 'Before a model trains, its tokenizer is fit on a data sample, usually with byte-pair encoding or a similar algorithm that repeatedly merges the most frequent adjacent units. The result is the fixed vocabulary the model will use forever. It matters because it decides how efficiently text is encoded — a tokenizer fit mostly on English will chop other languages into many more tokens, making them costlier and often worse-served.', 'A one-time choice that quietly sets per-language cost and quality for the model''s whole life.', 'Fit a subword vocabulary (e.g. BPE) on a corpus sample by iterative frequency-based merges; fixed thereafter.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('vocabularysize', 'Vocabulary size', 'Vocabulary Size', '', ARRAY['vocabulary size','vocab size']::text[], 'Core', 'How many distinct tokens the model knows — a trade-off between shorter sequences and a bigger, heavier vocabulary.', 'The number of keys on a keyboard: more keys means fewer keystrokes per word, but a bulkier keyboard.', 'Bumping the vocabulary from 32k to 128k tokens lets the model encode the same text in fewer tokens, especially in other languages.', '[{"text":"The process that sets it.","id":"tokenizertraining"},{"text":"The set of tokens it counts.","id":"vocabulary"}]'::jsonb, 'A larger vocabulary encodes text in fewer tokens — cheaper and faster context-wise — but inflates the embedding and output layers, adding parameters and memory. Too small and everything fragments into many tokens; too large and rare tokens are undertrained and the model gets heavier. Modern models trend toward larger vocabularies partly to serve many languages more fairly.', 'A dial affecting speed, cost, and how well non-English text is handled.', 'The token count in the vocabulary; larger shortens sequences but enlarges embedding/output layers.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('contextextension', 'Context extension', 'Context Window Extension', '', ARRAY['context extension','context window extension','context length extension']::text[], 'Rising', 'Stretching a model to handle much longer inputs than it was originally trained for.', 'Adding leaves to a dining table so it seats far more guests than the original build allowed.', 'A model trained at 8k tokens is extended to 128k so it can read whole books, using adjusted positional encodings and a bit of long-context fine-tuning.', '[{"text":"The limit it raises.","id":"contextlength"},{"text":"The fine-tuning phase it relies on.","id":"longcontexttraining"},{"text":"The mechanism it modifies.","id":"positionalencoding"}]'::jsonb, 'Models learn positional patterns only up to their training length, so naively feeding more tokens breaks them. Extension techniques modify how positions are encoded — for example interpolating rotary embeddings — often followed by fine-tuning on longer sequences. It works, but longer context is not free: attention cost grows and models often use the far reaches of a long window unevenly.', 'How a model gains the ability to handle long documents without retraining from scratch.', 'Adapt positional encodings (e.g. RoPE interpolation) plus long-sequence fine-tuning to extend usable context.', 'Training', 60, ARRAY['seed','training']::text[]),
  ('longcontexttraining', 'Long-context training', 'Long-Context Training', '', ARRAY['long-context training','long context training']::text[], 'Rising', 'Fine-tuning a model on very long sequences so it can actually use a big context window, not just accept one.', 'Practicing with a full-length novel, not just short passages, so you can genuinely follow a long story.', 'After extending a model to 128k tokens, the team trains it on long documents so it learns to track information across the whole span.', '[{"text":"The step that raises the ceiling first.","id":"contextextension"},{"text":"The failure it combats.","id":"lostinthemiddle"},{"text":"The window it makes usable.","id":"contextlength"}]'::jsonb, 'Accepting long inputs and using them well are different things. Long-context training exposes the model to genuinely long sequences during fine-tuning so it learns to attend across distances it never saw in pretraining. It is expensive — attention and memory scale with sequence length — and it directly fights the "lost in the middle" tendency where models under-use the center of a long input.', 'The work that turns a big advertised context window into one that actually performs.', 'Fine-tune on long sequences post-extension so attention learns to use the full window; costly in memory/compute.', 'Training', 60, ARRAY['seed','training']::text[]),
  ('alignmenttax', 'Alignment tax', 'Alignment Tax / Safety Tax', '', ARRAY['alignment tax','safety tax']::text[], 'Rising', 'The capability you sometimes give up when you make a model safer and more aligned.', 'Speed bumps in a parking lot: safer for everyone, but they slow you down a little.', 'After heavy safety fine-tuning, a model refuses a few too many harmless requests and loses a bit of sharpness on hard tasks — that gap is the alignment tax.', '[{"text":"A main contributor to the tax.","id":"refusaltraining"},{"text":"The training that can levy it.","id":"safetyfinetuning"},{"text":"The overall goal it is a cost of.","id":"alignment"}]'::jsonb, 'Aligning a model — refusal training, safety tuning, RLHF toward cautious behavior — can trade away raw capability or usefulness: over-refusal, blander answers, hedging. The "tax" is that cost. Good alignment work aims to shrink it toward zero, and modern methods have narrowed it a lot, but a tension remains between being maximally helpful and reliably safe.', 'The real trade-off behind "why won''t it just answer" — safety and helpfulness pull against each other.', 'The capability/usefulness loss incurred by alignment training; minimized but rarely fully eliminated.', 'Training', 60, ARRAY['seed','training']::text[]),
  ('refusaltraining', 'Refusal training', 'Refusal Training', '', ARRAY['refusal training','refusal tuning','teaching refusals']::text[], 'Rising', 'Teaching a model to decline requests it should not fulfill, and to do it gracefully.', 'Training a bartender to firmly but politely cut someone off — knowing when "no" is the right answer.', 'The model is fine-tuned on examples where the good response to a harmful request is a clear, polite refusal with a brief reason.', '[{"text":"The broader safety phase it is part of.","id":"safetyfinetuning"},{"text":"The cost of over-refusal.","id":"alignmenttax"}]'::jsonb, 'Refusal behavior is taught with curated examples and preference data showing when and how to say no. The craft is calibration: refuse genuinely harmful asks while not over-refusing benign ones that merely pattern-match to something risky. Push too hard and you get an annoying, over-cautious model — a visible face of the alignment tax; too soft and safety gaps open up.', 'Directly shapes the "is this model helpful or annoying" line users feel every day.', 'Fine-tune on curated refusal examples/preferences; the key metric is refusing harmful while minimizing over-refusal.', 'Training', 60, ARRAY['seed','training']::text[]),
  ('safetyfinetuning', 'Safety fine-tuning', 'Safety Fine-Tuning', '', ARRAY['safety fine-tuning','safety finetuning','safety tuning']::text[], 'Rising', 'The fine-tuning stage that teaches a model to avoid harmful, unsafe, or policy-violating outputs.', 'A driving instructor''s final lessons — not new driving skill, but the judgment to not do dangerous things.', 'After general instruction tuning, a model gets a safety pass using refusal examples and red-team data to close known failure modes.', '[{"text":"A specific skill it instills.","id":"refusaltraining"},{"text":"The adversarial data it uses.","id":"redteamingdata"},{"text":"The cost it can impose.","id":"alignmenttax"}]'::jsonb, 'Safety fine-tuning layers guardrails onto an already-capable model using curated examples, preference data, and adversarial red-team cases. It teaches refusals, careful handling of sensitive topics, and resistance to manipulation. It is never perfect — jailbreaks keep finding gaps — and pushing it hard incurs the alignment tax, so it is a continual balancing act rather than a one-time fix.', 'The stage that makes a model shippable to the public — and the source of most "why won''t it" complaints.', 'Post-SFT tuning on safety examples, preferences, and red-team data to reduce harmful outputs.', 'Training', 60, ARRAY['seed','training']::text[]),
  ('redteamingdata', 'Red-teaming data', 'Red-Team Data', '', ARRAY['red-teaming data','red-team data','red teaming data']::text[], 'Rising', 'Adversarial examples — crafted attempts to make a model misbehave — collected so training can patch those weaknesses.', 'Hiring ethical hackers to break into your building, then fixing every door they got through.', 'Testers spend weeks trying to jailbreak a model; the successful attacks become training data teaching it to resist next time.', '[{"text":"The stage that consumes it.","id":"safetyfinetuning"},{"text":"A related decline-behavior it reinforces.","id":"refusaltraining"}]'::jsonb, 'Red-teaming means deliberately probing a model for harmful, biased, or manipulable behavior — by humans, by other models, or both. The prompts that succeed are gold: they reveal real failure modes and become fine-tuning data so the model learns to handle them. It is an arms race, since new attacks keep appearing, which is why red-teaming is continuous rather than a single pre-launch check.', 'How known ways to break a model get found before launch — and turned into fixes.', 'Adversarially elicited failure cases used as safety fine-tuning data to close discovered vulnerabilities.', 'Training', 60, ARRAY['seed','training']::text[]),
  ('instructiondataset', 'Instruction dataset', 'Instruction Dataset', '', ARRAY['instruction dataset','instruction data','instruction-tuning dataset']::text[], 'Core', 'A collection of task-and-response examples that teaches a base model to actually follow instructions.', 'A stack of worked "here''s the request, here''s a good reply" cards that trains a new hire on the job.', 'Thousands of pairs like "Summarize this email → a crisp summary" are assembled to fine-tune a base model into a helpful assistant.', '[{"text":"The stage that uses it.","id":"instructiontuning"},{"text":"The training method it feeds.","id":"sft"},{"text":"The format it is wrapped in.","id":"chattemplate"}]'::jsonb, 'A base model predicts text but does not naturally take orders; an instruction dataset — pairs of prompts and high-quality responses across many task types — is what teaches it to. Quality and diversity matter more than raw size; a smaller, cleaner set often beats a huge noisy one. It usually follows a chat template so the model learns roles and turns, and it is the backbone of supervised fine-tuning.', 'The raw material that turns a raw predictor into something that does what you ask.', 'Prompt/response pairs across tasks used for supervised fine-tuning; diversity and quality beat sheer volume.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('chattemplate', 'Chat template', 'Chat Template', '', ARRAY['chat template','chat formatting','conversation template']::text[], 'Core', 'The fixed format of special markers that tells a model who said what — system, user, assistant — in a conversation.', 'A screenplay''s formatting: character names and stage directions so everyone knows whose line is whose.', 'Behind a chat interface, your message gets wrapped with role markers like a user tag before the model ever sees it.', '[{"text":"The data authored in this format.","id":"instructiondataset"},{"text":"One role it marks.","id":"systemmessage"},{"text":"The unit it delimits.","id":"turn"}]'::jsonb, 'Models do not inherently know turn boundaries; a chat template encodes them with special tokens marking system, user, and assistant roles. The model is trained with this exact format, so using a mismatched template at inference degrades quality or breaks behavior. It is a small, rigid contract that carries a lot of weight — get the template wrong and even a great model acts confused.', 'An invisible formatting layer whose correctness quietly determines whether a model behaves right.', 'The role-delimiting token format a model was trained on; must match exactly at inference.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('turnbasedtraining', 'Turn-based training', 'Multi-Turn Training', '', ARRAY['turn-based training','multi-turn training','multi-turn fine-tuning']::text[], 'Rising', 'Training a model on whole back-and-forth conversations, not just single question-answer pairs, so it can hold a thread.', 'Rehearsing a full dialogue with an actor, not just isolated one-liners, so the scene actually flows.', 'The model is fine-tuned on multi-turn chats where later replies must remember and build on what was said several turns earlier.', '[{"text":"The format these transcripts use.","id":"chattemplate"},{"text":"The multi-turn structure it trains on.","id":"conversation"}]'::jsonb, 'Single-turn tuning teaches a good one-shot answer but not conversational memory or consistency. Turn-based training uses multi-turn transcripts, typically with loss computed only on the assistant''s turns, so the model learns to use prior context, stay coherent, and not contradict itself. It is what makes a model feel like it is following the conversation rather than answering each message from scratch.', 'Why a good assistant remembers what you said three messages ago instead of resetting each time.', 'Fine-tune on multi-turn transcripts with loss on assistant turns, teaching cross-turn context use and consistency.', 'Training', 60, ARRAY['seed','training']::text[]),
  ('rewardmodeltraining', 'Reward model training', 'Reward Model Training', '', ARRAY['reward model training','training the reward model','reward modeling']::text[], 'Core', 'Teaching a separate model to predict which responses humans prefer, so it can score outputs during RL.', 'Training a judge by showing them thousands of pairs of dishes and which one diners liked, until they can score new plates.', 'From a dataset of chosen-vs-rejected reply pairs, a model learns to output higher scores for the responses people picked.', '[{"text":"The model it produces.","id":"rewardmodel"},{"text":"The data it learns from.","id":"preferencedata"},{"text":"The pipeline it feeds.","id":"rlhf"}]'::jsonb, 'The reward model is trained on human preference comparisons to output a scalar "how good is this" score. In RLHF, that score becomes the reward signal a policy optimizes against. Its quality caps the whole pipeline: if it is exploitable, the policy will reward-hack it, and if its preferences are biased or narrow, those flaws propagate into the final model. It usually starts from the base model itself.', 'The stand-in for human judgment that scales preference feedback — and whose blind spots become the model''s.', 'Train a scalar scorer on pairwise human preferences; it provides the reward in RLHF and is a target for reward hacking.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('annotatoragreement', 'Annotator agreement', 'Inter-Annotator Agreement', '', ARRAY['annotator agreement','inter-annotator agreement','inter-rater reliability']::text[], 'Core', 'How often different human labelers give the same answer — a health check on whether your labels mean anything.', 'Two referees watching the same replay: if they keep disagreeing on the call, the rulebook is the problem.', 'When only 60% of annotators agree on which reply is "better," the team rewrites the guidelines before trusting the data.', '[{"text":"The activity it measures the quality of.","id":"annotation"},{"text":"A related labeling process.","id":"labeling"},{"text":"A dataset whose quality it guards.","id":"preferencedata"}]'::jsonb, 'If humans labeling the same examples do not agree, the task is ambiguous or the instructions are unclear, and a model trained on that noisy data inherits the confusion. Agreement is measured with scores like Cohen''s or Fleiss'' kappa that correct for chance. Low agreement is a signal to clarify guidelines or accept that the task has irreducible subjectivity — high agreement is a prerequisite for trustworthy labels.', 'A quick gauge of whether your labeled data is signal or noise before you build on it.', 'Chance-corrected concordance (e.g. kappa) among labelers; low values indicate ambiguous tasks or guidelines.', 'Training', 80, ARRAY['seed','training']::text[])
insert into public.concepts
  (id, term, aliases, said, alias_list, status, one_liner, analogy, example, related, deeper, lens_pm, lens_eng, domain, priority, tags)
values
  ('goldlabels', 'Gold Labels', '', '', ARRAY['gold labels','gold standard labels','ground truth labels']::text[], 'Core', 'The answers you trust completely, usually because a careful human wrote them down.', 'The teacher’s answer key at the back of the book — the one everything else gets graded against.', 'Before scoring a support-bot, a team hand-labels 500 tickets with the “correct” category and treats those as gold.', '[{"text":"What you measure your model against.","id":"evals"},{"text":"The careful cousin of noisy auto-labeling.","id":"labeling"}]'::jsonb, 'Gold labels are the reference answers you assume are right, produced by expert humans or a trusted process. They’re expensive, so you rarely have many — which is exactly why people reach for weak supervision or synthetic data to fill the gap. If your gold set is itself wrong or biased, every number downstream inherits that flaw.', 'Your metrics are only as trustworthy as the gold set they’re scored against, so invest in getting a small clean one.', 'A curated, high-confidence labeled set used as ground truth for evaluation or as the seed for training.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('weaksupervision', 'Weak Supervision', '', '', ARRAY['weak supervision','weakly supervised']::text[], 'Rising', 'Label a mountain of data cheaply with rough rules instead of paying humans to do it all by hand.', 'Sorting mail by zip-code stamps instead of reading every envelope — fast, mostly right, occasionally wrong.', 'To flag toxic comments, you write a few keyword rules and treat their output as labels, then train on millions of examples.', '[{"text":"The cheap alternative to hand-made gold labels.","id":"goldlabels"},{"text":"Trades quality for scale.","id":"labeling"}]'::jsonb, 'Instead of one careful label per example, you combine many noisy signals — heuristics, keyword rules, existing models — and let their agreement stand in for truth. You get far more labeled data than humans could ever produce, at the cost of noise you have to model or tolerate. It shines when data is abundant but human labeling is the bottleneck.', 'A way to bootstrap a labeled dataset in days instead of months when perfect labels aren’t worth the wait.', 'Programmatic labeling from multiple noisy sources whose outputs are aggregated into training signals.', 'Training', 60, ARRAY['seed','training']::text[]),
  ('activelearning', 'Active Learning', '', '', ARRAY['active learning']::text[], 'Core', 'Let the model pick which examples it’s most confused by, and label only those.', 'A student who studies the questions they keep getting wrong instead of re-reading the whole textbook.', 'A vision model flags the 200 images it’s least sure about; a human labels just those and accuracy jumps.', '[{"text":"Feeds a smaller, smarter gold set.","id":"goldlabels"},{"text":"Powers the loop in a data flywheel.","id":"dataflywheel"}]'::jsonb, 'Labeling is expensive, so active learning spends that budget where it helps most: on the examples the model is most uncertain about or that would most reduce its errors. You train, ask the model where it’s weak, label those, and repeat. Done well it reaches the same accuracy with a fraction of the labels.', 'Cuts labeling cost by focusing human effort on the examples that actually move the needle.', 'An iterative loop that selects high-uncertainty or high-information samples for labeling to maximize accuracy per label.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('dataflywheel', 'Data Flywheel', '', '', ARRAY['data flywheel','data flywheels']::text[], 'Rising', 'Users generate data that makes the product better, which attracts more users, which makes more data.', 'A snowball rolling downhill — each turn picks up more snow and rolls faster on its own.', 'Every correction a user makes to the autocomplete trains the next version, which more people then use and correct.', '[{"text":"Often fed by active learning.","id":"activelearning"},{"text":"Turns usage into training signal.","id":"humanfeedback"}]'::jsonb, 'The flywheel is a self-reinforcing loop: real usage produces data, the data improves the model, the better model draws more usage. The hard part is the first push — you need enough users before the wheel spins on its own — and building the pipes that turn messy real-world interactions into clean training signal.', 'A durable moat: competitors can copy your model but not your accumulating stream of real user data.', 'A closed loop where production interactions are logged, curated, and fed back into retraining.', 'Training', 60, ARRAY['seed','training']::text[]),
  ('modelmerging', 'Model Merging', '', '', ARRAY['model merging','merged model']::text[], 'Rising', 'Blend two or more trained models into one by mixing their weights, no extra training needed.', 'Combining two recipes into a single dish by averaging the ingredient amounts.', 'A team merges a model good at coding with one good at chat and gets one that’s decent at both, for free.', '[{"text":"The simplest version is a model soup.","id":"modelsoup"},{"text":"Relies on weight averaging.","id":"weightaveraging"}]'::jsonb, 'Because models trained from the same starting point live in compatible weight spaces, you can often average or interpolate their parameters and get a model that inherits multiple skills. It’s startlingly cheap — no gradients, no data — but it only works when the models are close relatives, and results can be unpredictable.', 'A near-free way to combine capabilities without the cost of training a new model from scratch.', 'Combining independently fine-tuned checkpoints via weight-space arithmetic to fuse capabilities.', 'Training', 60, ARRAY['seed','training']::text[]),
  ('modelsoup', 'Model Soup', '', '', ARRAY['model soup','model soups']::text[], 'Rising', 'Average the weights of several fine-tuned models into one that’s often better than any single one.', 'Blending many cooks’ versions of the same soup — the average tastes more balanced than any one pot.', 'You fine-tune the same model ten times with different settings, average all ten, and the soup beats the best individual run.', '[{"text":"A specific recipe for model merging.","id":"modelmerging"},{"text":"It’s weight averaging applied to fine-tunes.","id":"weightaveraging"}]'::jsonb, 'A model soup takes several models fine-tuned from the same base with different hyperparameters and simply averages their weights. Surprisingly, the average often generalizes better than picking the single best model, because averaging cancels out each run’s idiosyncratic errors. The catch: the ingredients must share a starting point or the soup curdles.', 'Squeezes more accuracy out of training runs you already paid for instead of throwing the losers away.', 'Uniform or greedy averaging of same-lineage fine-tuned weights to improve generalization.', 'Training', 60, ARRAY['seed','training']::text[]),
  ('weightaveraging', 'Weight Averaging', '', '', ARRAY['weight averaging','averaged weights']::text[], 'Core', 'Take the numerical average of a model’s weights across runs or checkpoints to get a steadier model.', 'Averaging several thermometer readings to smooth out the jitter in any single one.', 'Instead of shipping the final training step, a team averages the last ten checkpoints and ships that smoother version.', '[{"text":"The mechanism behind model soups.","id":"modelsoup"},{"text":"A moving-average variant is EMA.","id":"ema"}]'::jsonb, 'Individual training snapshots bounce around the loss landscape; averaging their weights lands you in a flatter, more robust spot that tends to generalize better. It works across checkpoints of one run or across separate runs from the same base. The requirement is compatibility — you can’t meaningfully average models that started from different places.', 'A cheap post-processing trick that often buys a small, free accuracy bump before shipping.', 'Parameter-space averaging that lands in flatter minima with better generalization.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('ema', 'EMA', 'Exponential Moving Average', '', ARRAY['ema','exponential moving average']::text[], 'Core', 'A running average of the model’s weights that leans on recent steps but never forgets the past.', 'A rolling average of your daily spending — today counts most, but last week still nudges the number.', 'During training, an EMA copy of the weights is kept alongside the live one, and the smoother EMA version is what gets shipped.', '[{"text":"A time-weighted flavor of weight averaging.","id":"weightaveraging"},{"text":"Often paired with checkpoint averaging.","id":"checkpointaveraging"}]'::jsonb, 'EMA maintains a shadow copy of the weights updated as a decaying blend: mostly the previous average, slightly the newest step. This damps the noise of individual updates and usually produces a more stable, higher-quality model than the raw final weights. It costs almost nothing but a second copy of the parameters.', 'A standard, low-risk way to make the shipped model a bit more reliable than the raw training output.', 'A decayed running mean of parameters maintained during training, typically used for the evaluation weights.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('finetunevsprompt', 'Fine-tune vs Prompt', '', '', ARRAY['fine-tune vs prompt','fine-tuning vs prompting','finetune vs prompt']::text[], 'Core', 'The recurring choice: teach the model new behavior by retraining it, or just by asking better in the prompt.', 'Sending an employee to a training course versus writing them a really clear instruction note.', 'A team wants consistent JSON output; they try a detailed prompt first, and only fine-tune once prompting hits its ceiling.', '[{"text":"One side of the trade-off.","id":"finetuning"},{"text":"The other side.","id":"promptengineering"},{"text":"Prompting leans on in-context learning.","id":"incontextlearning"}]'::jsonb, 'Prompting is fast, free to change, and reversible, but every request pays the token cost and behavior can drift. Fine-tuning bakes the behavior in — cheaper at inference, more consistent — but it’s slow to iterate and risks forgetting other skills. The rule of thumb: exhaust prompting first, fine-tune when you need consistency, lower latency, or behavior prompting can’t reach.', 'Prompting to validate an idea quickly; fine-tuning once the behavior is proven and volume justifies the cost.', 'A trade between updating weights (durable, costly to iterate) and steering via context (flexible, per-request cost).', 'Training', 80, ARRAY['seed','training']::text[]),
  ('overfittoeval', 'Overfit to Eval', '', '', ARRAY['overfit to eval','overfitting to the eval','teaching to the test']::text[], 'Rising', 'Tuning a model until it aces your test set while quietly getting worse at everything else.', 'Memorizing last year’s exam paper — you nail that test and learn nothing useful.', 'A team keeps tweaking prompts to raise a benchmark score, then finds the model got worse on real user questions.', '[{"text":"A close relative of overfitting.","id":"overfitting"},{"text":"Why you keep a fresh holdout.","id":"holdout"},{"text":"Worsened by train-test leakage.","id":"traintestleakage"}]'::jsonb, 'When you make many decisions based on one evaluation set, you slowly fit to its quirks rather than to the real task — the benchmark rises while true quality stalls or drops. It’s subtle because the number keeps going up. Defenses include held-out sets you look at rarely, rotating fresh evals, and judging on live traffic.', 'A rising benchmark can be a mirage; protect a private eval you don’t optimize against so you know what’s real.', 'Metric inflation from repeated selection against a fixed eval set; mitigate with held-out and rotating evaluations.', 'Training', 60, ARRAY['seed','training']::text[]),
  ('traintestleakage', 'Train-Test Leakage', 'Data Leakage', '', ARRAY['train-test leakage','data leakage','test set leakage']::text[], 'Core', 'When test answers sneak into training, so the model looks brilliant on a test it has secretly already seen.', 'Grading a student on questions they were accidentally handed the night before.', 'A web-scraped training set turns out to contain the exact benchmark questions, and the reported score is meaningless.', '[{"text":"A cause of overfitting to eval.","id":"overfittoeval"},{"text":"Related to dataset contamination.","id":"datacontamination"},{"text":"Why you hold out clean data.","id":"holdout"}]'::jsonb, 'Leakage happens whenever information from the test set — the exact examples, or features derived from them — is present at training time. The model memorizes rather than generalizes, so evaluation numbers are inflated and collapse in the real world. With web-scale training data, accidental contamination of public benchmarks is a constant, hard-to-detect risk.', 'A leaked benchmark tells you nothing; always ask whether the eval data could have been in training.', 'Contamination of the evaluation set into training data, producing optimistic and non-generalizing metrics.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('checkpointaveraging', 'Checkpoint Averaging', '', '', ARRAY['checkpoint averaging','averaged checkpoints']::text[], 'Core', 'Average several saved snapshots from a single training run into one steadier final model.', 'Blending a few photos of a moving subject to cancel the blur and get one sharp shot.', 'Rather than shipping the last step, a team averages the final five checkpoints and gets a small, free quality gain.', '[{"text":"A specific use of weight averaging.","id":"weightaveraging"},{"text":"The streaming version is EMA.","id":"ema"},{"text":"Operates on saved checkpoints.","id":"checkpoint"}]'::jsonb, 'Late in training the weights oscillate around a good region rather than settling exactly. Averaging several nearby checkpoints lands you in a flatter, more robust center of that region, which usually generalizes a touch better than any single snapshot. It’s a standard, near-zero-cost finishing move.', 'A no-downside trick to slightly improve the final model from runs you already completed.', 'Averaging parameters of consecutive checkpoints from one run to reduce oscillation-driven variance.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('continuallearning', 'Continual Learning', 'Lifelong Learning', '', ARRAY['continual learning','lifelong learning','incremental learning']::text[], 'Rising', 'Teaching a model new things over time without making it forget what it already knew.', 'Adding new recipes to a chef’s repertoire without them suddenly forgetting how to make the old ones.', 'A support model needs this quarter’s product updates added on top, but must keep answering last year’s questions correctly.', '[{"text":"Fights catastrophic forgetting.","id":"catastrophicforgetting"},{"text":"Often uses a replay buffer.","id":"replaybuffer"},{"text":"Overlaps with continued pretraining.","id":"continuedpretraining"}]'::jsonb, 'The core tension is stability versus plasticity: learn new information fast enough to stay current, but not so aggressively that you overwrite old knowledge — the dreaded catastrophic forgetting. Techniques include replaying old data, freezing parts of the network, and adding small adapters. Truly seamless continual learning remains an open problem.', 'The dream of updating a model with fresh knowledge without a full, expensive retrain — with real trade-offs today.', 'Sequential training on new data while preserving prior performance, balancing plasticity against forgetting.', 'Training', 60, ARRAY['seed','training']::text[]),
  ('domainadaptation', 'Domain Adaptation', '', '', ARRAY['domain adaptation','domain adapting']::text[], 'Core', 'Taking a model trained on one kind of data and adjusting it to work well on a different kind.', 'A driver who knows city streets taking a short course before driving a truck on mountain roads.', 'A general chat model is adapted on medical notes so it handles clinical shorthand instead of stumbling on it.', '[{"text":"A form of transfer learning.","id":"transferlearning"},{"text":"Often done via fine-tuning.","id":"finetuning"},{"text":"Or continued pretraining.","id":"continuedpretraining"}]'::jsonb, 'A model performs best on data resembling what it trained on; move it to a new domain — legal, medical, a new language style — and accuracy drops. Domain adaptation closes that gap with additional training on target-domain data, sometimes without labels. The subtlety is doing it without erasing the general capabilities that made the base model useful.', 'How you turn a general model into a specialist for your industry’s vocabulary and quirks.', 'Adjusting a model to a target data distribution that differs from its source training distribution.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('replaybuffer', 'Replay Buffer', 'Experience Replay', '', ARRAY['replay buffer','experience replay']::text[], 'Core', 'A stash of old examples the model keeps revisiting so it doesn’t forget them while learning new ones.', 'Mixing a few old flashcards into every study session so you don’t lose what you learned last month.', 'While teaching a model new topics, the trainer sprinkles in old data from the buffer so past skills stay sharp.', '[{"text":"A tool against catastrophic forgetting.","id":"catastrophicforgetting"},{"text":"Common in continual learning.","id":"continuallearning"},{"text":"Also core to reinforcement learning.","id":"reinforcementlearning"}]'::jsonb, 'A replay buffer stores past experiences or examples and re-injects samples of them into ongoing training. In continual learning it preserves old knowledge; in reinforcement learning it also breaks correlations between consecutive samples, making updates more stable. The design questions are what to keep and how to sample from it.', 'A practical guardrail so updating the model doesn’t silently degrade the things it already did well.', 'A memory of prior samples replayed during training to stabilize learning and counter forgetting.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('syntheticbootstrapping', 'Synthetic Bootstrapping', '', '', ARRAY['synthetic bootstrapping','bootstrapping data']::text[], 'Rising', 'Use a model to generate its own training data, then train on it to get better at generating more.', 'Pulling yourself up by your bootstraps — a small start that generates the fuel for a bigger climb.', 'A model writes thousands of math solutions, you keep only the ones that check out, and fine-tune on those to boost it.', '[{"text":"Produces synthetic data.","id":"syntheticdata"},{"text":"Filtered by rejection sampling.","id":"rejectionsampling"},{"text":"A cousin of self-distillation.","id":"selfdistillation"}]'::jsonb, 'Starting from a small seed of quality data or a decent base model, you generate new examples, filter them for correctness, and train on the survivors — then repeat, each round raising the floor. It works best when you can cheaply verify outputs (math, code, tests). The danger is compounding the model’s own errors when your filter is weak.', 'A way to grow training data without armies of human labelers — as long as you can check quality automatically.', 'Iterative self-generation of training data with a verification filter to bootstrap capability gains.', 'Training', 60, ARRAY['seed','training']::text[]),
  ('distillationdataset', 'Distillation Dataset', '', '', ARRAY['distillation dataset','distillation data']::text[], 'Rising', 'A pile of a bigger model’s answers, used as the textbook to teach a smaller model to imitate it.', 'A recording of a master chef cooking, handed to an apprentice to study move for move.', 'A team prompts a large model with 100k questions, saves its responses, and trains a small cheap model on that transcript.', '[{"text":"The fuel for knowledge distillation.","id":"knowledgedistillation"},{"text":"From a teacher to a student model.","id":"teachermodel"},{"text":"A kind of synthetic data.","id":"syntheticdata"}]'::jsonb, 'Rather than distilling from a teacher’s internal probabilities, you often just collect its outputs — questions paired with the big model’s answers — and treat that as a training set for a smaller student. Quality depends entirely on the teacher and the prompts you chose. It’s cheap and effective, though the student inherits the teacher’s mistakes and blind spots too.', 'How a small, cheap model gets much of a big model’s quality — by learning from its answers.', 'A corpus of teacher-model outputs used as supervised targets to train a smaller student.', 'Training', 60, ARRAY['seed','training']::text[]),
  ('transformer', 'Transformer', '', '', ARRAY['transformer','transformers']::text[], 'Core', 'The architecture behind nearly every modern language model — it reads a whole sequence at once using attention.', 'A reader who can glance at every word on the page simultaneously instead of one at a time.', 'GPT, Claude, and BERT are all transformers under the hood, stacking attention layers to process text.', '[{"text":"Its core mechanism.","id":"attention"},{"text":"What it replaced.","id":"recurrentneuralnetwork"},{"text":"Built from encoder and decoder blocks.","id":"encoderdecoder"}]'::jsonb, 'Introduced in 2017, the transformer ditched the step-by-step recurrence of earlier models for attention, which lets every position look at every other position in parallel. That parallelism is why transformers scale so well on modern hardware. Stack enough of these layers, train on enough text, and you get today’s large language models.', 'The foundational design that made large language models practical to train at scale — the “T” in GPT.', 'An attention-based architecture that processes sequences in parallel, stacking self-attention and feed-forward layers.', 'Architectures', 80, ARRAY['seed','architectures']::text[]),
  ('attention', 'Attention', '', '', ARRAY['attention','attention mechanism']::text[], 'Core', 'The mechanism that lets a model decide which other words to focus on when interpreting each word.', 'Reading “it” in a sentence and instinctively glancing back to figure out what “it” refers to.', 'To resolve “the trophy didn’t fit in the suitcase because it was too big,” attention links “it” to “trophy.”', '[{"text":"The engine of the transformer.","id":"transformer"},{"text":"The version inside one sequence.","id":"selfattention"},{"text":"Built from queries, keys, and values.","id":"querykeyvalue"}]'::jsonb, 'Attention computes, for each token, a set of weights over all other tokens — how much each one matters right now — and blends their information accordingly. Those weights are learned and context-dependent, so the same word attends differently depending on its neighbors. It’s the idea that unlocked long-range understanding in language models.', 'The breakthrough that let models track meaning across a whole passage instead of just nearby words.', 'A weighted aggregation over token representations where weights come from query-key similarity.', 'Architectures', 80, ARRAY['seed','architectures']::text[]),
  ('selfattention', 'Self-Attention', '', '', ARRAY['self-attention','self attention']::text[], 'Core', 'Attention a sequence pays to itself — each word looking at the other words in the same sentence.', 'Everyone at a meeting table turning to hear whoever’s most relevant to the current point.', 'In one sentence, self-attention lets “bank” attend to “river” nearby and settle on the water meaning, not money.', '[{"text":"A specific use of attention.","id":"attention"},{"text":"Contrast with cross-attention.","id":"crossattention"},{"text":"The core of the transformer.","id":"transformer"}]'::jsonb, 'In self-attention, the queries, keys, and values all come from the same sequence, so every token gathers context from every other token in that same input. Stacking many self-attention layers lets meaning propagate and combine across the whole passage. It’s the workhorse operation inside every transformer block.', 'What lets a model understand a word in the context of the whole message around it.', 'Attention where queries, keys, and values derive from one sequence, mixing information within it.', 'Architectures', 80, ARRAY['seed','architectures']::text[]),
  ('crossattention', 'Cross-Attention', '', '', ARRAY['cross-attention','cross attention']::text[], 'Core', 'Attention from one sequence to a different one — letting an output peek at a separate input.', 'A translator reading the original sentence while writing each word of the translation.', 'In a translation model, each output word cross-attends to the source sentence to stay faithful to it.', '[{"text":"Contrast with self-attention.","id":"selfattention"},{"text":"Bridges an encoder and decoder.","id":"encoderdecoder"},{"text":"A form of attention.","id":"attention"}]'::jsonb, 'Cross-attention draws its queries from one sequence but its keys and values from another, so the first sequence conditions on the second. It’s how a decoder consults an encoder’s representation of the input, or how a model grounds generation in retrieved documents or an image. It’s the same math as self-attention, just pointed at a different source.', 'The mechanism that lets a model’s output stay anchored to a separate input like a document or image.', 'Attention where queries come from one sequence and keys/values from another, conditioning one on the other.', 'Architectures', 80, ARRAY['seed','architectures']::text[]),
  ('multiheadattention', 'Multi-Head Attention', 'MHA', '', ARRAY['multi-head attention','multihead attention','mha']::text[], 'Core', 'Run attention several times in parallel, each “head” focusing on a different kind of relationship.', 'A panel of specialists reading the same document — one tracks grammar, one tracks tone, one tracks facts.', 'One head links pronouns to nouns while another tracks verb tense, and their views get combined each layer.', '[{"text":"Parallel copies of attention.","id":"attention"},{"text":"Each one is an attention head.","id":"attentionhead"},{"text":"Slimmed down by grouped-query attention.","id":"groupedqueryattention"}]'::jsonb, 'A single attention pattern can only capture one type of relationship at a time. Multi-head attention splits the representation into several subspaces and runs attention independently in each, then concatenates the results. This lets the model attend to many kinds of structure — syntax, coreference, position — simultaneously, and it’s standard in every transformer.', 'Why a model can juggle several kinds of context at once rather than fixating on a single pattern.', 'Parallel attention over projected subspaces whose outputs are concatenated and mixed.', 'Architectures', 80, ARRAY['seed','architectures']::text[]),
  ('feedforwardnetwork', 'Feed-Forward Network', 'FFN, MLP', '', ARRAY['feed-forward network','feedforward network','ffn','mlp']::text[], 'Core', 'The little per-word processing block that sits after attention in every transformer layer.', 'After a meeting where everyone shares notes, each person goes to their desk to think it over alone.', 'Following each attention step, the FFN transforms every token’s vector independently before the next layer.', '[{"text":"Pairs with attention in each layer.","id":"attention"},{"text":"A building block of the transformer.","id":"transformer"},{"text":"Uses an activation function.","id":"activationfunction"}]'::jsonb, 'Each transformer layer has two parts: attention mixes information across tokens, then a feed-forward network processes each token on its own through a couple of linear layers with a nonlinearity between them. The FFN holds a large share of the model’s parameters and is where much of its stored knowledge is thought to live. Mixture-of-experts models make this block sparse.', 'Where much of a model’s raw “knowledge capacity” sits — and a big chunk of its parameter count.', 'A position-wise two-layer MLP with a nonlinearity, applied identically to each token after attention.', 'Architectures', 80, ARRAY['seed','architectures']::text[]),
  ('residualconnection', 'Residual Connection', 'Skip Connection', '', ARRAY['residual connection','residual connections']::text[], 'Core', 'A shortcut that adds a layer’s input to its output, so information can skip past if needed.', 'Keeping a photocopy of your draft before edits, so nothing important gets lost in revision.', 'In each transformer block, the input is added back to what attention produced, keeping gradients healthy in deep stacks.', '[{"text":"Also called a skip connection.","id":"skipconnection"},{"text":"Paired with layer normalization.","id":"layernormalization"},{"text":"Essential to deep networks.","id":"deeplearning"}]'::jsonb, 'Very deep networks are hard to train because signals and gradients fade as they pass through many layers. A residual connection adds a layer’s input straight to its output, giving information a clear path forward and gradients a clear path back. This one trick is what made training networks with dozens or hundreds of layers practical.', 'A quiet structural trick that made very deep, capable models trainable in the first place.', 'An additive identity shortcut around a sublayer that preserves signal and eases gradient flow.', 'Architectures', 80, ARRAY['seed','architectures']::text[]),
  ('skipconnection', 'Skip Connection', '', '', ARRAY['skip connection','skip connections']::text[], 'Core', 'The general name for wiring that lets a signal jump over one or more layers instead of passing through them.', 'An express lane that skips a few local stops so passengers can bypass congestion.', 'U-Nets and transformers alike use skip connections so early features reach later layers untouched.', '[{"text":"The residual add is one kind.","id":"residualconnection"},{"text":"A staple of deep learning.","id":"deeplearning"}]'::jsonb, 'Skip connection is the umbrella term for any path that routes information around intermediate layers; the residual connection — adding input to output — is its most common form. These shortcuts preserve detail that deep stacks would otherwise blur and keep gradients from vanishing. They show up across many architectures, not just transformers.', 'A foundational design idea that keeps deep models both trainable and detail-preserving.', 'Any bypass path routing activations around layers, most often an additive residual.', 'Architectures', 80, ARRAY['seed','architectures']::text[]),
  ('encoder', 'Encoder', '', '', ARRAY['encoder','encoders']::text[], 'Core', 'The half of a model that reads an input and compresses it into a rich internal representation.', 'A note-taker who listens to a whole speech and writes a dense summary others can work from.', 'BERT is encoder-only: it reads a sentence and produces vectors great for classification or search, not generation.', '[{"text":"Pairs with a decoder.","id":"decoder"},{"text":"Together they form encoder-decoder.","id":"encoderdecoder"},{"text":"Produces a representation.","id":"representation"}]'::jsonb, 'An encoder maps an input sequence into a set of context-rich vectors, seeing the whole input at once (bidirectionally). It’s ideal when you need to understand or embed text rather than produce more of it — search, classification, retrieval. Encoder-only models like BERT dominate those tasks; pure generation uses decoders instead.', 'The right shape when the job is understanding or searching text, not writing it.', 'A stack that maps input tokens to contextual representations, typically with bidirectional attention.', 'Architectures', 80, ARRAY['seed','architectures']::text[]),
  ('decoder', 'Decoder', '', '', ARRAY['decoder','decoders','decoder-only','decoder only']::text[], 'Core', 'The half of a model that generates output one token at a time, each based on what came before.', 'A writer producing a sentence word by word, each choice shaped by everything already written.', 'GPT and Claude are decoder-only models: they read your prompt and generate the continuation token by token.', '[{"text":"The counterpart to an encoder.","id":"encoder"},{"text":"Generates autoregressively.","id":"autoregressive"},{"text":"Uses causal attention.","id":"causalattention"}]'::jsonb, 'A decoder produces tokens sequentially, and to keep generation honest it uses causal (masked) attention so each position can see only earlier tokens, never future ones. Most of today’s large language models are decoder-only — a single stack that both reads the prompt and writes the answer. It’s the architecture built for generation.', 'The shape behind chat and text-generation models — read a prompt, write a continuation.', 'A stack that generates tokens autoregressively using causally-masked self-attention.', 'Architectures', 80, ARRAY['seed','architectures']::text[]),
  ('encoderdecoder', 'Encoder-Decoder', 'Seq2Seq', '', ARRAY['encoder-decoder','encoder decoder','seq2seq','sequence to sequence']::text[], 'Core', 'A two-part design where one stack reads the input and another writes the output, linked by attention.', 'A translator with a listening phase and a speaking phase — understand fully first, then produce.', 'T5 and classic translation models use this: the encoder digests the source, the decoder emits the translation.', '[{"text":"Combines an encoder and decoder.","id":"encoder"},{"text":"Linked via cross-attention.","id":"crossattention"},{"text":"The original transformer shape.","id":"transformer"}]'::jsonb, 'The original transformer was encoder-decoder: the encoder builds a representation of the input, and the decoder generates the output while cross-attending to that representation. It fits tasks with a clear input-to-output mapping like translation or summarization. Many modern chat models skip the encoder and go decoder-only, but the two-part design still shines for structured transduction.', 'The classic fit for “turn this input into that output” tasks like translation and summarization.', 'An architecture pairing a bidirectional encoder with an autoregressive decoder joined by cross-attention.', 'Architectures', 80, ARRAY['seed','architectures']::text[]),
  ('attentionhead', 'Attention Head', '', '', ARRAY['attention head','attention heads']::text[], 'Core', 'One independent attention computation inside a layer, specializing in a particular kind of relationship.', 'A single lane of traffic among several — each carries its own flow, all part of one highway.', 'Researchers have found individual heads that track subject-verb agreement or copy the previous token.', '[{"text":"Many heads make multi-head attention.","id":"multiheadattention"},{"text":"Each computes attention.","id":"attention"}]'::jsonb, 'A head is one slice of multi-head attention: it projects tokens into its own subspace and computes its own attention pattern. Different heads learn to specialize — some track position, some syntax, some coreference — and interpretability research often studies individual heads to understand what a model has learned. Modern efficiency tricks share keys and values across heads to save memory.', 'The unit researchers poke at to understand what a model actually pays attention to.', 'A single attention operation over one projected subspace within multi-head attention.', 'Architectures', 80, ARRAY['seed','architectures']::text[]),
  ('querykeyvalue', 'Query, Key, Value', 'QKV', '', ARRAY['query key value','qkv','queries keys values']::text[], 'Core', 'The three roles each token plays in attention: what it’s looking for, what it offers, and what it hands over.', 'A library search: your query, each book’s label (key), and the book’s actual contents (value).', 'A token’s query is matched against every token’s key; the closest matches decide whose values get blended in.', '[{"text":"The inputs to attention.","id":"attention"},{"text":"Matched via scaled dot-product attention.","id":"scaleddotproductattention"},{"text":"Keys and values get cached.","id":"kvcache"}]'::jsonb, 'Attention derives three vectors from each token. The query says what this token wants; keys advertise what every token contains; the dot-product of a query with each key gives relevance scores; those scores then weight the values that get summed into the output. This query-key-value framing is the machinery underneath every attention mechanism.', 'The conceptual gears of attention — worth knowing when you hear about KV caching and its memory costs.', 'The three learned projections per token whose query-key similarity weights a sum over values.', 'Architectures', 80, ARRAY['seed','architectures']::text[]),
  ('scaleddotproductattention', 'Scaled Dot-Product Attention', '', '', ARRAY['scaled dot-product attention','scaled dot product attention']::text[], 'Core', 'The exact recipe for attention: score with dot products, shrink the scores, softmax, then blend.', 'Rating each option, dividing the scores to keep them sane, turning them into percentages, then mixing accordingly.', 'Each query dots against all keys, the scores are divided by the square root of the dimension, softmaxed, and applied to values.', '[{"text":"The concrete form of attention.","id":"attention"},{"text":"Operates on query, key, value.","id":"querykeyvalue"},{"text":"Uses a softmax.","id":"softmax"}]'::jsonb, 'The “scaled” part matters: raw dot products grow with vector dimension, pushing softmax into saturated regions where gradients vanish. Dividing by the square root of the key dimension keeps scores in a workable range. After softmax turns them into weights, you take the weighted sum of values. This precise formula is the beating heart of the transformer.', 'The standard, well-understood formula that every attention layer runs — rarely something you tune directly.', 'Attention as softmax(QKᵀ/√d)·V, with √d scaling to stabilize gradients.', 'Architectures', 80, ARRAY['seed','architectures']::text[]),
  ('maskedattention', 'Masked Attention', '', '', ARRAY['masked attention','attention masking']::text[], 'Core', 'Attention with certain positions deliberately hidden, so the model can’t look where it shouldn’t.', 'Covering the answers below a quiz question so you can only use what’s above it.', 'A text generator masks future tokens so, while predicting word five, it can’t peek at words six and beyond.', '[{"text":"The causal case is causal attention.","id":"causalattention"},{"text":"Implemented with an attention mask.","id":"attentionmask"},{"text":"Used in the decoder.","id":"decoder"}]'::jsonb, 'Masking sets certain attention scores to negative infinity before the softmax so those positions get zero weight. The most common use is causal masking in decoders — hiding future tokens to preserve the left-to-right generation setup — but masks also ignore padding or enforce custom visibility patterns. It’s a simple, powerful lever over what each token can see.', 'The guardrail that keeps a generative model from cheating by seeing the answer it’s supposed to predict.', 'Attention with selected scores set to −∞ pre-softmax to zero out disallowed positions.', 'Architectures', 80, ARRAY['seed','architectures']::text[]),
  ('causalattention', 'Causal Attention', 'Autoregressive Masking', '', ARRAY['causal attention','causal masking','autoregressive masking']::text[], 'Core', 'Attention where every token can see the past and present but never the future.', 'Writing a story where you can reread earlier pages but the next ones haven’t been written yet.', 'In GPT-style generation, causal attention ensures token five is predicted from tokens one through four only.', '[{"text":"A specific masked attention.","id":"maskedattention"},{"text":"Enables autoregressive generation.","id":"autoregressive"},{"text":"Defines the decoder.","id":"decoder"}]'::jsonb, 'Causal attention applies a triangular mask so position i attends only to positions ≤ i. This enforces the autoregressive assumption — predict the next token from prior context — and lets training on a full sequence teach every next-token prediction at once. It’s the reason decoder-only language models can be trained efficiently and generate coherently.', 'The rule that makes left-to-right text generation consistent between training and real use.', 'Triangular masking restricting each position to attend only to itself and earlier positions.', 'Architectures', 80, ARRAY['seed','architectures']::text[]),
  ('mixtureofexperts', 'Mixture of Experts', 'MoE', '', ARRAY['mixture of experts','moe']::text[], 'Rising', 'Split a model into many specialist sub-networks and route each token to just a few of them.', 'A hospital where a receptionist sends each patient to the two right specialists instead of every doctor at once.', 'A model has 64 expert blocks but activates only two per token, so it’s huge in capacity yet cheap to run.', '[{"text":"Makes the feed-forward network sparse.","id":"feedforwardnetwork"},{"text":"A sparse model design.","id":"sparsemodel"},{"text":"Contrast with a dense model.","id":"densemodel"}]'::jsonb, 'In a mixture-of-experts layer, a lightweight router picks a small subset of expert sub-networks to process each token, so total parameters can be enormous while compute per token stays modest. The wins are capacity and efficiency; the headaches are load-balancing the experts, routing instability, and the memory to hold all those parameters. It powers several frontier models.', 'How models get much bigger in capability without a proportional jump in inference cost.', 'A layer that routes each token to a few of many expert subnetworks, decoupling parameter count from per-token compute.', 'Architectures', 60, ARRAY['seed','architectures']::text[]),
  ('sparseattention', 'Sparse Attention', '', '', ARRAY['sparse attention']::text[], 'Rising', 'Attention that only connects each token to a chosen subset of others instead of all of them.', 'Instead of everyone at a huge conference talking to everyone, people only chat with their nearest neighbors and a few leaders.', 'For a very long document, a model attends to nearby tokens plus a few global ones rather than the full quadratic grid.', '[{"text":"A cheaper form of attention.","id":"attention"},{"text":"Relatives include sliding window attention.","id":"slidingwindowattention"},{"text":"Helps with long context.","id":"contextlength"}]'::jsonb, 'Full attention costs grow with the square of sequence length, which gets brutal for long inputs. Sparse attention restricts each token to a limited pattern of connections — local windows, strided jumps, a handful of global tokens — cutting the cost while trying to preserve the connections that matter. The art is choosing a sparsity pattern that keeps quality high.', 'A key enabler of long-context models that would otherwise be too expensive to run.', 'Attention restricted to a structured subset of token pairs to reduce quadratic cost.', 'Architectures', 60, ARRAY['seed','architectures']::text[]),
  ('flashattention', 'Flash Attention', '', '', ARRAY['flash attention','flashattention']::text[], 'Rising', 'A faster, memory-frugal way to compute exact attention by being clever about how the GPU moves data.', 'Cooking straight from the counter instead of walking to the pantry for each ingredient — same dish, far less trips.', 'Swapping in flash attention lets a team train on longer sequences at the same speed, with no change to the results.', '[{"text":"A faster computation of attention.","id":"attention"},{"text":"Speeds up training.","id":"training"},{"text":"Helps enable long context.","id":"contextlength"}]'::jsonb, 'Standard attention writes a giant scores matrix to slow GPU memory and reads it back — the real bottleneck. Flash attention tiles the computation so intermediate values stay in fast on-chip memory, computing the same exact result without ever materializing the full matrix. The output is identical; the speed and memory savings are large, which is why it’s become the default.', 'An under-the-hood efficiency win that made longer contexts and cheaper training practical.', 'An IO-aware, tiled exact-attention kernel that avoids materializing the full attention matrix in HBM.', 'Architectures', 60, ARRAY['seed','architectures']::text[]),
  ('slidingwindowattention', 'Sliding Window Attention', '', '', ARRAY['sliding window attention','local attention']::text[], 'Rising', 'Each token only attends to a fixed window of nearby tokens, keeping long sequences affordable.', 'Reading with a ruler under the line — you focus on the words right around you, not the whole page at once.', 'A model uses a 4,000-token window so processing a 100,000-token document stays linear instead of exploding.', '[{"text":"A form of sparse attention.","id":"sparseattention"},{"text":"Trades global reach for efficiency in attention.","id":"attention"},{"text":"Enables longer context.","id":"contextlength"}]'::jsonb, 'Sliding window attention limits each token’s view to a local neighborhood of fixed size, making cost grow linearly with length rather than quadratically. Information still travels far because stacking layers lets windows overlap and propagate — like ripples reaching across the sequence over several hops. Many long-context models pair it with a few global tokens for the rest.', 'A practical way to stretch context length without the cost blowing up.', 'Local attention over a fixed-size window per token, giving linear cost with multi-layer receptive-field growth.', 'Architectures', 60, ARRAY['seed','architectures']::text[]),
  ('groupedqueryattention', 'Grouped-Query Attention', 'GQA', '', ARRAY['grouped-query attention','grouped query attention','gqa']::text[], 'Rising', 'Let several attention heads share one set of keys and values to shrink memory during generation.', 'A few coworkers sharing one filing cabinet instead of each keeping a full duplicate set of folders.', 'A model gives 32 query heads but only 8 shared key-value groups, cutting the memory its KV cache needs.', '[{"text":"A middle ground for multi-head attention.","id":"multiheadattention"},{"text":"The extreme case is multi-query attention.","id":"multiqueryattention"},{"text":"Shrinks the KV cache.","id":"kvcache"}]'::jsonb, 'The KV cache — stored keys and values for every past token — dominates memory during long generations. Multi-query attention shares a single key-value set across all heads (fast, but can hurt quality); grouped-query attention is the compromise, letting groups of query heads share key-value sets. It keeps most of the quality while sharply reducing cache size and bandwidth.', 'A quiet efficiency choice that makes long-context serving cheaper and faster.', 'Attention where query heads are grouped to share key/value projections, shrinking KV-cache footprint.', 'Architectures', 60, ARRAY['seed','architectures']::text[]),
  ('multiqueryattention', 'Multi-Query Attention', 'MQA', '', ARRAY['multi-query attention','multi query attention','mqa']::text[], 'Rising', 'All attention heads share a single set of keys and values — the most aggressive memory-saving variant.', 'The whole office sharing one filing cabinet — lean and fast, but everyone competes for the same drawers.', 'An inference-optimized model uses one key-value head for all query heads to make its KV cache as small as possible.', '[{"text":"The extreme of grouped-query attention.","id":"groupedqueryattention"},{"text":"A variant of multi-head attention.","id":"multiheadattention"},{"text":"Minimizes the KV cache.","id":"kvcache"}]'::jsonb, 'Multi-query attention keeps many query heads but collapses to a single shared key and value head, minimizing the KV cache and the memory bandwidth needed each generation step. That makes decoding notably faster, at some cost to quality. Grouped-query attention emerged as the popular middle ground, recovering most of the lost quality while keeping much of the speed.', 'A serving-speed optimization that trades a little quality for cheaper, faster generation.', 'Attention with a single shared key/value head across all query heads, minimizing KV-cache size.', 'Architectures', 60, ARRAY['seed','architectures']::text[]),
  ('kvcache', 'KV Cache', 'Key-Value Cache', '', ARRAY['kv cache','key-value cache','kv caching']::text[], 'Core', 'Stored keys and values from earlier tokens so the model doesn’t recompute them every generation step.', 'Keeping your running notes open so you don’t reread the whole book each time you write a new line.', 'While generating a long reply, the model caches each token’s keys and values so step 500 doesn’t redo steps 1–499.', '[{"text":"Caches attention’s keys and values.","id":"querykeyvalue"},{"text":"Shrunk by grouped-query attention.","id":"groupedqueryattention"},{"text":"A cost during inference.","id":"inference"}]'::jsonb, 'Autoregressive generation would be wildly wasteful if each new token recomputed attention over the entire history. The KV cache stores the keys and values of all previous tokens so each step only computes the new one and attends against the cache. The trade-off is memory: the cache grows with sequence length and batch size, which is exactly what GQA and MQA aim to tame.', 'The reason long conversations get memory-hungry — and a big driver of serving cost.', 'Cached per-token keys/values reused across decoding steps, trading memory for avoided recomputation.', 'Architectures', 80, ARRAY['seed','architectures']::text[]),
  ('rotaryembeddings', 'Rotary Embeddings', 'RoPE', '', ARRAY['rotary embeddings','rotary position embedding','rope']::text[], 'Rising', 'Encode a token’s position by rotating its vector, so relative distances fall out naturally in attention.', 'Turning each clock hand by an amount set by the hour — the angle between hands tells you the gap.', 'A model uses RoPE so that “word 10 relative to word 7” is captured cleanly, and it extends to longer inputs gracefully.', '[{"text":"A modern positional embedding.","id":"positionalembedding"},{"text":"An alternative is ALiBi.","id":"alibi"},{"text":"Shapes attention.","id":"attention"}]'::jsonb, 'RoPE injects position by rotating each token’s query and key vectors by an angle proportional to their position. Because attention compares queries and keys via dot products, these rotations make the score depend on the relative distance between tokens — a clean, position-aware signal. It also extends to longer sequences than seen in training better than older schemes, which is why it’s now common.', 'Part of why modern models handle long inputs and relative word order so well.', 'Position encoding via rotation of query/key vectors, yielding relative-position-aware dot products.', 'Architectures', 60, ARRAY['seed','architectures']::text[]),
  ('alibi', 'ALiBi', 'Attention with Linear Biases', '', ARRAY['alibi','attention with linear biases']::text[], 'Fading', 'Add a small distance-based penalty to attention scores so far-away tokens matter a little less.', 'A conversation where voices from across the room come through fainter the farther away they are.', 'A model trained with ALiBi on short sequences still works on much longer ones at inference without retraining.', '[{"text":"An alternative to rotary embeddings.","id":"rotaryembeddings"},{"text":"A kind of positional embedding.","id":"positionalembedding"},{"text":"Biases attention.","id":"attention"}]'::jsonb, 'Instead of adding position vectors, ALiBi subtracts a penalty from each attention score proportional to how far apart the two tokens are. This bakes in a “nearer matters more” prior and, notably, lets models generalize to sequences longer than those seen in training. It was influential for long-context work, though rotary embeddings have become the more common default.', 'An early trick for length generalization, now largely overtaken by rotary embeddings.', 'Position handling via a linear distance penalty added to attention logits, aiding length extrapolation.', 'Architectures', 30, ARRAY['seed','architectures']::text[]),
  ('positionalembedding', 'Positional Embedding', '', '', ARRAY['positional embedding','learned position embedding']::text[], 'Core', 'Extra information that tells the model where each token sits, since attention alone ignores order.', 'Numbering the pages of a manuscript before shuffling them, so the order can always be recovered.', 'Without positional info, “dog bites man” and “man bites dog” look identical to attention — embeddings fix that.', '[{"text":"Modern versions include rotary embeddings.","id":"rotaryembeddings"},{"text":"And ALiBi.","id":"alibi"},{"text":"Compare positional encoding.","id":"positionalencoding"}]'::jsonb, 'Attention is order-blind: it treats its inputs as a set, so without positional signals a transformer can’t tell sequence order. Positional embeddings supply that missing structure, either learned per position or computed by a fixed function, and are added to or folded into token representations. Which scheme you pick strongly affects how well the model handles long or unusual-length inputs.', 'The mechanism that lets an order-blind architecture understand word order at all.', 'Signals encoding token position added to or combined with embeddings to restore sequence order.', 'Architectures', 80, ARRAY['seed','architectures']::text[]),
  ('convolutionalneuralnetwork', 'Convolutional Neural Network', 'CNN, ConvNet', '', ARRAY['convolutional neural network','cnn','convnet']::text[], 'Core', 'A network that scans small patches across an input to detect local patterns, great for images.', 'Sliding a magnifying glass across a photo, noting edges and textures wherever it lands.', 'A CNN powers a phone’s photo classifier, spotting edges, then shapes, then whole objects layer by layer.', '[{"text":"A pillar of deep learning.","id":"deeplearning"},{"text":"For sequences, compare the recurrent neural network.","id":"recurrentneuralnetwork"},{"text":"Largely supplanted for text by the transformer.","id":"transformer"}]'::jsonb, 'CNNs apply small learnable filters that slide across the input, reusing the same weights everywhere so they detect a pattern wherever it appears. Stacked layers build from simple features (edges) to complex ones (faces). They dominated computer vision for years and remain strong there, though transformers have encroached on vision too. For text and long-range reasoning, transformers took over.', 'The workhorse behind most image-recognition features of the last decade.', 'A network of shared-weight sliding filters exploiting spatial locality and translation invariance.', 'Architectures', 80, ARRAY['seed','architectures']::text[]),
  ('recurrentneuralnetwork', 'Recurrent Neural Network', 'RNN', '', ARRAY['recurrent neural network','rnn']::text[], 'Fading', 'A network that reads a sequence one step at a time, carrying a memory of what it has seen so far.', 'Reading a sentence word by word while keeping a running gist of it in your head.', 'Before transformers, RNNs handled translation and speech by processing text left to right, updating a hidden state.', '[{"text":"Improved by the LSTM.","id":"lstm"},{"text":"And the GRU.","id":"gru"},{"text":"Largely replaced by the transformer.","id":"transformer"}]'::jsonb, 'An RNN maintains a hidden state updated at each timestep, letting information flow forward through a sequence. That sequential dependency is also its weakness: it can’t parallelize across time, and long-range signals fade or explode through many steps. Gated variants like LSTM and GRU helped, but attention-based transformers ultimately outscaled them and pushed RNNs to the margins.', 'The prior era’s approach to sequence modeling, now mostly of historical and niche interest.', 'A network with a recurrent hidden state updated per timestep, limited by sequential compute and vanishing gradients.', 'Architectures', 30, ARRAY['seed','architectures']::text[]),
  ('lstm', 'LSTM', 'Long Short-Term Memory', '', ARRAY['lstm','long short-term memory']::text[], 'Fading', 'A recurrent network with gates that decide what to remember and forget, so it can hold information longer.', 'A notepad with an eraser and a highlighter — you keep the important lines and clear the rest as you go.', 'Before transformers, LSTMs powered much of machine translation and speech recognition for years.', '[{"text":"A gated recurrent neural network.","id":"recurrentneuralnetwork"},{"text":"A simpler cousin is the GRU.","id":"gru"},{"text":"Superseded by the transformer.","id":"transformer"}]'::jsonb, 'The LSTM added input, forget, and output gates plus a protected cell state, giving gradients a stable path through time and letting the network retain information across longer spans than a plain RNN. It was the dominant sequence model of the 2010s. Transformers eventually beat it on scale and parallelism, but the LSTM’s gating ideas still echo in newer architectures.', 'The reliable sequence model of the pre-transformer era — historically pivotal, now rarely the default.', 'A gated recurrent unit with a cell state and forget/input/output gates that mitigate vanishing gradients.', 'Architectures', 30, ARRAY['seed','architectures']::text[]),
  ('gru', 'GRU', 'Gated Recurrent Unit', '', ARRAY['gru','gated recurrent unit']::text[], 'Fading', 'A streamlined LSTM with fewer gates — nearly as capable, a bit cheaper and simpler.', 'A lighter backpack with one fewer pocket that still carries almost everything you need.', 'A team on a tight compute budget picks a GRU over an LSTM for a sequence task and loses little accuracy.', '[{"text":"A simpler LSTM.","id":"lstm"},{"text":"A gated recurrent neural network.","id":"recurrentneuralnetwork"},{"text":"Overtaken by the transformer.","id":"transformer"}]'::jsonb, 'The GRU merges the LSTM’s gates into two (update and reset) and drops the separate cell state, making it lighter and faster to train while often matching LSTM performance. It was a popular choice when efficiency mattered. Like the LSTM, it belongs to the recurrent era that transformers largely displaced, though it remains a clean baseline for small sequence problems.', 'A lighter alternative to the LSTM from the same era — simple and efficient, but no longer the go-to.', 'A recurrent unit with update/reset gates and no separate cell state, cheaper than an LSTM at similar quality.', 'Architectures', 30, ARRAY['seed','architectures']::text[]),
  ('statespacemodel', 'State Space Model', 'SSM', '', ARRAY['state space model','ssm']::text[], 'Rising', 'A sequence model that carries a compact running state, mixing RNN-like memory with parallel training.', 'A thermostat that tracks a single evolving reading over time instead of re-reading the whole day’s log.', 'For very long sequences, an SSM keeps a fixed-size state so cost grows linearly, not quadratically like attention.', '[{"text":"A prominent example is Mamba.","id":"mamba"},{"text":"An alternative to the transformer.","id":"transformer"},{"text":"Descends from recurrent ideas.","id":"recurrentneuralnetwork"}]'::jsonb, 'State space models process sequences through a linear dynamical system: a hidden state evolves step to step, summarizing history in fixed size. Cleverly, they can be computed either recurrently (cheap at inference) or as a convolution (parallel at training), sidestepping the RNN’s training bottleneck. Their linear scaling with length makes them attractive for very long contexts where attention gets expensive.', 'A promising challenger to attention for very long inputs, with cheaper scaling.', 'A linear-recurrence sequence model with a fixed-size state, computable as convolution for parallel training.', 'Architectures', 60, ARRAY['seed','architectures']::text[]),
  ('mamba', 'Mamba', '', '', ARRAY['mamba']::text[], 'Rising', 'A state space model that adds input-dependent control, rivaling transformers with linear-time scaling.', 'A thermostat smart enough to change how hard it reacts based on what’s happening right now.', 'Mamba handles very long sequences at lower cost than attention while staying competitive on language tasks.', '[{"text":"A selective state space model.","id":"statespacemodel"},{"text":"Competes with the transformer.","id":"transformer"},{"text":"Another recurrent-style challenger is RWKV.","id":"rwkv"}]'::jsonb, 'Mamba’s key move is making the state space model’s parameters depend on the input — “selective” state spaces — so the model can choose what to remember or ignore per token, something earlier SSMs couldn’t. Combined with a hardware-aware implementation, it achieves linear scaling in sequence length while matching transformers on many tasks. It’s a leading example of the post-attention exploration.', 'A live bet that not every strong model has to be a transformer — especially for long sequences.', 'A selective SSM with input-dependent dynamics and a hardware-aware scan, giving linear-time sequence modeling.', 'Architectures', 60, ARRAY['seed','architectures']::text[]),
  ('rwkv', 'RWKV', '', '', ARRAY['rwkv']::text[], 'Rising', 'An architecture that trains like a transformer but runs like an RNN, aiming for the best of both.', 'A hybrid car — plug-in convenience for the long haul, efficient engine for the daily drive.', 'RWKV lets a long chat run with constant memory per token, unlike a transformer’s growing KV cache.', '[{"text":"Blends the transformer and recurrent neural network.","id":"transformer"},{"text":"A linear-scaling peer to Mamba.","id":"mamba"},{"text":"Related to state space models.","id":"statespacemodel"}]'::jsonb, 'RWKV reformulates attention-like mixing into a recurrent form that can be trained in parallel like a transformer but executed step by step like an RNN, giving constant memory and linear time at inference. That makes very long or streaming generation cheap in memory. It’s part of the wave of architectures probing whether quadratic attention is truly necessary.', 'Another contender for cheap long-context and streaming use, trading the transformer’s memory growth for a constant footprint.', 'A linear-attention-style architecture with parallel training and RNN-like constant-memory inference.', 'Architectures', 60, ARRAY['seed','architectures']::text[])
insert into public.concepts
  (id, term, aliases, said, alias_list, status, one_liner, analogy, example, related, deeper, lens_pm, lens_eng, domain, priority, tags)
values
  ('diffusionmodel', 'Diffusion Model', '', '', ARRAY['diffusionmodel','diffusion model','diffusion models']::text[], 'Core', 'A model that learns to make images by starting from pure static and cleaning it up step by step.', 'Like watching a photo develop in a darkroom tray, except it runs backwards from noise toward a picture.', 'When you type a prompt into an image generator and watch a fuzzy blob sharpen into a cat over a few seconds, that’s a diffusion model at work.', '[{"text":"The specific training recipe most diffusion models use.","id":"denoisingdiffusion"},{"text":"The older rival it largely displaced for image generation.","id":"gan"}]'::jsonb, 'Training teaches it to predict the noise that was added to a real image; run that predictor in reverse many times and you turn random noise into a coherent picture. Each step removes a little noise, guided by your text prompt. It’s slower than a single forward pass, which is why image generation takes seconds, not milliseconds.', 'The reason text-to-image tools feel magical and also why they cost real compute per picture.', 'A generative model trained to reverse a fixed noising process, sampling iteratively from noise to data.', 'Architectures', 80, ARRAY['seed','architectures']::text[]),
  ('denoisingdiffusion', 'Denoising Diffusion', '', '', ARRAY['denoisingdiffusion','denoising diffusion','ddpm']::text[], 'Core', 'The exact recipe behind diffusion models: add noise on purpose, then train a network to take it back out.', 'Like deliberately smudging a drawing and teaching an apprentice to un-smudge it one pass at a time.', 'The 2020 DDPM paper turned this into the standard training loop that powers today’s image and video generators.', '[{"text":"The model class this recipe builds.","id":"diffusionmodel"}]'::jsonb, 'You corrupt training images with Gaussian noise across many steps until they’re unrecognizable, then train the model to predict what noise was added at each step. Generation runs the same steps in reverse. The whole thing is a clever way to break an impossibly hard “make an image” problem into thousands of tiny, learnable “remove a little noise” problems.', 'The underlying method you’re licensing whenever you buy into an image or video model.', 'A latent-variable model where the forward process is fixed Gaussian noising and the reverse process is learned.', 'Architectures', 80, ARRAY['seed','architectures']::text[]),
  ('gan', 'GAN', 'Generative Adversarial Network', '', ARRAY['gan','gans','generative adversarial network']::text[], 'Fading', 'Two networks in a duel: one fakes images, the other calls out fakes, and both get sharper.', 'A forger and a detective locked in a room — each pushes the other to get better until the forgeries pass.', 'The eerily realistic faces on “thispersondoesnotexist” were GAN output, back when GANs ruled image generation.', '[{"text":"The full name spelled out.","id":"generativeadversarialnetwork"},{"text":"The method that largely replaced it.","id":"diffusionmodel"}]'::jsonb, 'A generator invents images and a discriminator judges real vs. fake; training pits them against each other until the generator’s fakes fool the judge. It produces crisp results but is notoriously unstable to train and prone to “mode collapse,” where it churns out the same few images. Diffusion models have mostly taken over because they’re steadier.', 'A once-dominant approach now mostly of historical and niche interest for generation.', 'A minimax game between a generator and discriminator, trained to a Nash equilibrium.', 'Architectures', 30, ARRAY['seed','architectures']::text[]),
  ('generativeadversarialnetwork', 'Generative Adversarial Network', 'GAN', '', ARRAY['generativeadversarialnetwork']::text[], 'Fading', 'The full name for a GAN — a generator and a critic trained by competing against each other.', 'Counterfeiter versus bank teller: the better the teller gets at spotting fakes, the better the counterfeiter has to be.', 'Ian Goodfellow’s 2014 paper introduced the idea and set off years of photorealistic-face research.', '[{"text":"The common abbreviation and its story.","id":"gan"}]'::jsonb, 'The generator maps random noise to fake data; the discriminator learns to separate fakes from real samples. Their opposing objectives create a moving target that, when it works, produces sharp samples — and when it doesn’t, collapses or oscillates. The adversarial framing was the big idea; the training pain was the price.', 'Historically important, but you’ll rarely reach for it in a new product today.', 'Same as GAN: adversarial training of paired generator and discriminator networks.', 'Architectures', 30, ARRAY['seed','architectures']::text[]),
  ('vae', 'VAE', 'Variational Autoencoder', '', ARRAY['vae','vaes','variational autoencoder']::text[], 'Core', 'An autoencoder that compresses data into a smooth, organized space you can sample new things from.', 'Like a librarian who not only files every book but arranges the shelves so similar books sit together — so you can wander to a nearby spot and find something plausible.', 'Most modern image diffusion models actually run inside a VAE’s compressed space to save compute, not on raw pixels.', '[{"text":"The plain version without the probabilistic twist.","id":"autoencoder"},{"text":"The generative method it often compresses for.","id":"diffusionmodel"}]'::jsonb, 'It squeezes input into a probability distribution over a small latent space, then decodes samples back out. The “variational” part forces that latent space to be smooth and continuous, so nearby points decode to similar outputs and you can generate new samples by sampling the space. Outputs tend to be blurrier than GANs or diffusion, but the tidy latent space is the payoff.', 'Often the invisible compression layer that makes big image models affordable to run.', 'An autoencoder with a KL-regularized latent distribution, trained on a reconstruction-plus-divergence objective.', 'Architectures', 80, ARRAY['seed','architectures']::text[]),
  ('variationalautoencoder', 'Variational Autoencoder', 'VAE', '', ARRAY['variationalautoencoder']::text[], 'Core', 'The full name for a VAE — an autoencoder whose middle is a smooth, sampleable space.', 'A vending machine that not only stores snacks but lays them out so you can dial to a spot between two and get a sensible blend.', 'When a latent-diffusion image model “decodes” its result to pixels, that decoder is a VAE’s.', '[{"text":"The everyday short name.","id":"vae"}]'::jsonb, 'It learns to encode inputs as distributions rather than single points, and a regularization term keeps that latent space continuous and well-behaved. That lets you generate by sampling and interpolate between examples smoothly. The trade-off is softer, less crisp reconstructions than adversarial or diffusion approaches.', 'The quiet workhorse compressing data so pricier generative steps stay cheap.', 'Identical to VAE: variational inference over a latent code with an encoder–decoder pair.', 'Architectures', 80, ARRAY['seed','architectures']::text[]),
  ('autoencoder', 'Autoencoder', '', '', ARRAY['autoencoder','autoencoders','auto-encoder']::text[], 'Core', 'A network that learns to squeeze data down and rebuild it, keeping only what matters.', 'Like zipping a file and unzipping it — if the copy still looks right, the middle captured the essence.', 'A denoising autoencoder can take a grainy scan, compress it, and reconstruct a clean version.', '[{"text":"The probabilistic, generative descendant.","id":"vae"},{"text":"What the bottleneck produces.","id":"representation"}]'::jsonb, 'An encoder shrinks the input into a small “bottleneck” representation, and a decoder tries to reconstruct the original from it. Because the bottleneck is smaller than the input, the network is forced to keep the important structure and drop the noise. It’s used for compression, denoising, and learning useful representations — the ancestor of the VAE.', 'A simple building block for compression, cleanup, and feature learning.', 'An encoder–decoder trained to minimize reconstruction error through a low-dimensional bottleneck.', 'Architectures', 80, ARRAY['seed','architectures']::text[]),
  ('unet', 'U-Net', '', '', ARRAY['unet','u-net','u net']::text[], 'Core', 'A U-shaped network that shrinks an image down, then grows it back — with shortcuts across the U so detail survives.', 'Like sketching the big shapes first, then zooming back in with your original reference photo taped beside you so you don’t lose the fine lines.', 'The denoising step inside most image diffusion models is a U-Net predicting what noise to remove.', '[{"text":"The generative process it usually powers.","id":"diffusionmodel"},{"text":"The shortcut trick it relies on.","id":"skipconnection"}]'::jsonb, 'The downsampling half captures context (what’s in the picture), the upsampling half restores resolution (where exactly), and skip connections pass fine-grained detail directly across the U so it isn’t lost in the squeeze. Born in medical image segmentation, it became the default backbone for diffusion because it’s good at pixel-precise prediction.', 'The engine room of most image generators, even if users never hear the name.', 'An encoder–decoder CNN with symmetric skip connections between matching resolution levels.', 'Architectures', 80, ARRAY['seed','architectures']::text[]),
  ('resnet', 'ResNet', 'Residual Network', '', ARRAY['resnet','resnets','residual network']::text[], 'Core', 'The network that let us stack layers really deep by giving each one a shortcut around itself.', 'Like an express lane on a highway — if a stretch of road adds nothing, traffic can just skip past it untouched.', 'ResNet-50 is still a default image backbone in production vision systems years after its 2015 debut.', '[{"text":"The shortcut idea at its heart.","id":"residualconnection"},{"text":"The image-model family it belongs to.","id":"convolutionalneuralnetwork"}]'::jsonb, 'Very deep networks used to get worse, not better, because the training signal faded on its way back through dozens of layers. ResNet added “residual” shortcuts that let each layer learn only the change it needs, with the input passed through untouched by default. That single trick unlocked networks hundreds of layers deep and reshaped everything after.', 'A durable, battle-tested vision backbone you can still ship on today.', 'A CNN with identity skip connections so layers learn residual functions, easing gradient flow.', 'Architectures', 80, ARRAY['seed','architectures']::text[]),
  ('bert', 'BERT', 'Bidirectional Encoder Representations from Transformers', '', ARRAY['bert','berts']::text[], 'Fading', 'An encoder that reads a whole sentence in both directions at once to understand it — great at reading, not built for writing.', 'Like a proofreader who scans the entire sentence before judging any one word, rather than reading strictly left to right.', 'For years, Google Search used BERT to better grasp what a query actually meant.', '[{"text":"The masking task it trains on.","id":"maskedlanguagemodel"},{"text":"The half of the transformer it uses.","id":"encoderonly"}]'::jsonb, 'BERT is encoder-only: it looks at all the words at once (bidirectional) and is trained by masking random words and predicting them. That makes it excellent at classification, search, and understanding tasks, but it can’t naturally generate long text the way a decoder-based model does. Generative LLMs eventually stole the spotlight, but BERT-style encoders still quietly power a lot of search and retrieval.', 'A cheap, fast option when you need to understand or classify text, not write it.', 'An encoder-only transformer pretrained with masked-language-modeling and next-sentence objectives.', 'Architectures', 30, ARRAY['seed','architectures']::text[]),
  ('gptarchitecture', 'GPT Architecture', '', '', ARRAY['gptarchitecture','gpt architecture','decoder-only transformer']::text[], 'Core', 'The decoder-only transformer that predicts the next word, over and over — the shape behind most chatbots.', 'Like a storyteller who only ever thinks about the very next word, but does it so well the whole story hangs together.', 'Every model in the GPT, Claude, and Llama families shares this same basic decoder-only skeleton.', '[{"text":"The core prediction task.","id":"nexttokenprediction"},{"text":"The half of the transformer it uses.","id":"decoder"},{"text":"The reading-focused counterpart.","id":"bert"}]'::jsonb, 'It’s a stack of transformer decoder blocks that only look leftward — each position can attend to earlier tokens but not future ones — trained purely to predict the next token. That single simple objective, scaled up massively, turned out to produce fluent writing, reasoning, and code. The architecture barely changed; the scale and data did.', 'The default shape of the generative models your product is probably built on.', 'A causal, decoder-only transformer trained autoregressively on next-token prediction.', 'Architectures', 80, ARRAY['seed','architectures']::text[]),
  ('t5', 'T5', 'Text-to-Text Transfer Transformer', '', ARRAY['t5','text-to-text transfer transformer']::text[], 'Fading', 'A model that treats every task — translation, summarizing, answering — as turning one string of text into another.', 'Like a universal adapter that insists everything, from questions to translations, plugs into the same text-in, text-out socket.', 'To classify a review, you’d feed T5 “sentiment: this movie was great” and it outputs the word “positive.”', '[{"text":"The two-part structure it uses.","id":"encoderdecoder"}]'::jsonb, 'T5 uses the full encoder–decoder transformer and reframes every NLP task as text-to-text, so one model and one training setup handle them all. That uniformity made it a clean research workhorse. Decoder-only chat models later showed you could get similar generality without the encoder, but the “everything is text-to-text” framing stuck around.', 'An elegant older approach; most new work uses decoder-only models instead.', 'An encoder–decoder transformer casting all tasks in a unified text-to-text format.', 'Architectures', 30, ARRAY['seed','architectures']::text[]),
  ('attentionisallyouneed', 'Attention Is All You Need', '', '', ARRAY['attentionisallyouneed','attention is all you need']::text[], 'Historical', 'The 2017 paper that introduced the transformer and quietly set off the whole modern AI boom.', 'Like the patent for the printing press — modest in the moment, era-defining in hindsight.', 'Nearly every large language model you use traces its lineage directly to this one paper.', '[{"text":"The architecture it introduced.","id":"transformer"},{"text":"The mechanism it championed.","id":"attention"}]'::jsonb, 'It showed you could drop the recurrent networks everyone relied on and build a language model purely out of attention, which processes all positions in parallel and scales far better. The title was a cheeky claim that turned out to be right. It’s “historical” only in the sense that its ideas are now everywhere — the paper itself remains foundational.', 'The origin story worth knowing when you talk about why any of this works.', 'The paper introducing the transformer, replacing recurrence with self-attention.', 'Architectures', 10, ARRAY['seed','architectures']::text[]),
  ('reasoningmodel', 'Reasoning Model', '', '', ARRAY['reasoningmodel','reasoning model','reasoning llm']::text[], 'Rising', 'A model trained to think out loud before answering, spending extra compute to work through hard problems.', 'Like a student who scribbles working on scratch paper instead of blurting the first answer that comes to mind.', 'Ask one a tricky math or coding problem and it’ll generate a long internal chain of steps before giving you the final line.', '[{"text":"The reasoning trace it produces.","id":"chainofthought"},{"text":"The compute-at-answer-time idea it embodies.","id":"testtimecompute"}]'::jsonb, 'These models are trained — often with reinforcement learning — to produce extended reasoning traces, then land on an answer. The longer they “think” at inference time, the better they tend to do on hard tasks, which is a real trade of latency and cost for accuracy. It’s a shift from spending all your compute on training to spending some at answer time.', 'Better on genuinely hard tasks, but slower and pricier per query — pick where it earns its keep.', 'A model post-trained to allocate test-time compute to explicit multi-step reasoning before answering.', 'Architectures', 60, ARRAY['seed','architectures']::text[]),
  ('treeofthought', 'Tree of Thought', '', '', ARRAY['treeofthought','tree of thought','tree-of-thoughts','tot']::text[], 'Rising', 'Letting a model branch into several lines of reasoning and explore them like a decision tree instead of one straight path.', 'Like planning a chess move by imagining several candidate moves and their follow-ups, not just the first one you see.', 'For a logic puzzle, the model proposes a few possible first steps, evaluates each, and pursues the most promising branch.', '[{"text":"The single-path version it extends.","id":"chainofthought"}]'::jsonb, 'Where plain chain-of-thought commits to a single reasoning path, tree of thought generates multiple candidate steps, scores them, and can backtrack from dead ends. It trades a lot more compute for better results on problems that need search or planning. It’s more a prompting-and-orchestration strategy than a change to the model’s weights.', 'A way to squeeze harder problems out of a model, at a steep compute multiplier.', 'A search procedure over branching reasoning steps with evaluation and backtracking.', 'Architectures', 60, ARRAY['seed','architectures']::text[]),
  ('testtimecompute', 'Test-Time Compute', '', '', ARRAY['testtimecompute','test-time compute','test time compute']::text[], 'Rising', 'Spending more computing power at the moment of answering — not during training — to get a better answer.', 'Like giving yourself more time on an exam question instead of studying harder beforehand — more thinking now, right when it counts.', 'A reasoning model that takes 30 seconds and writes pages of internal steps for a hard proof is burning test-time compute.', '[{"text":"A near-synonym emphasizing the scaling angle.","id":"inferencetimescaling"},{"text":"The model type built around it.","id":"reasoningmodel"}]'::jsonb, 'For years, gains came from bigger models and more training. Test-time compute flips some of that: keep the model fixed but let it think longer, sample more candidates, or search over options at answer time. On hard problems this buys real accuracy, but it directly raises latency and cost per request, so it’s a dial to spend deliberately.', 'A new cost lever — you can now trade money-per-answer for quality, live.', 'Allocating additional inference-time computation (longer generations, sampling, search) to improve outputs.', 'Architectures', 60, ARRAY['seed','architectures']::text[]),
  ('inferencetimescaling', 'Inference-Time Scaling', '', '', ARRAY['inferencetimescaling','inference-time scaling','inference time scaling']::text[], 'Rising', 'The finding that answers keep improving the more compute you let a model spend while answering.', 'Like turning up a car’s power by flooring the accelerator in the moment, rather than rebuilding the engine.', 'Charts showing accuracy climbing as a model is allowed to generate longer and longer reasoning are inference-time scaling curves.', '[{"text":"The mechanism it names.","id":"testtimecompute"},{"text":"The training-time counterpart.","id":"scalinglaws"}]'::jsonb, 'It’s the answer-time cousin of training scaling laws: instead of “bigger model, better model,” it’s “more thinking per question, better answer.” This reframed how labs chase performance, since a smaller model with generous inference budget can rival a bigger one on some tasks. The catch is that every extra bit of thinking costs money and time on every single query.', 'Means a modest model can punch above its weight if you’re willing to pay per answer.', 'The empirical scaling of task performance with inference-time compute budget.', 'Architectures', 60, ARRAY['seed','architectures']::text[]),
  ('expertrouting', 'Expert Routing', '', '', ARRAY['expertrouting','expert routing']::text[], 'Rising', 'The traffic cop inside a mixture-of-experts model that sends each token to just a few specialized sub-networks.', 'Like a hospital triage nurse deciding which specialist each patient should see, so nobody wastes the whole staff on one case.', 'In a mixture-of-experts model, routing might send a coding token to two “code” experts and skip the other sixty.', '[{"text":"The model type it lives inside.","id":"mixtureofexperts"},{"text":"The small network that makes the choice.","id":"gatingnetwork"}]'::jsonb, 'Instead of every token passing through every parameter, a router picks a small subset of “experts” per token, so the model can be huge in total but cheap per token. Getting the routing right is the hard part — bad routing overloads some experts and starves others. It’s the mechanism that makes sparse giant models practical to run.', 'Why some “huge” models are still affordable to serve — most of them stays idle per query.', 'The learned assignment of tokens to a top-k subset of experts in an MoE layer.', 'Architectures', 60, ARRAY['seed','architectures']::text[]),
  ('gatingnetwork', 'Gating Network', '', '', ARRAY['gatingnetwork','gating network','gate network']::text[], 'Rising', 'The little module that scores the experts and decides which ones handle each token.', 'Like a maitre d’ reading the room and deciding which chef should cook each order.', 'When an MoE layer picks its top two experts for a token, the gating network produced those scores.', '[{"text":"The decision it performs.","id":"expertrouting"},{"text":"Another name for essentially the same part.","id":"routernetwork"}]'::jsonb, 'It takes the token’s representation and outputs a weight for each expert, and the top few weights decide who runs and how much their output counts. Training has to keep it from favoring the same experts every time, usually with load-balancing penalties. Small as it is, the gating network shapes whether the whole mixture works or collapses onto a handful of overworked experts.', 'A tiny component whose quality quietly determines whether a big sparse model behaves.', 'A learned softmax-scored selector assigning per-token weights to experts, with load-balancing losses.', 'Architectures', 60, ARRAY['seed','architectures']::text[]),
  ('routernetwork', 'Router Network', '', '', ARRAY['routernetwork','router network','router']::text[], 'Rising', 'Another name for the gating module — it routes each token to its chosen experts.', 'Like a mailroom sorter reading each envelope and dropping it in the right department’s bin.', 'A model card might note the router sends each token to two of its many experts.', '[{"text":"The other common name for it.","id":"gatingnetwork"},{"text":"The routing decision itself.","id":"expertrouting"}]'::jsonb, '“Router” and “gating network” usually point at the same thing: the component that decides which experts process a token. The word “router” emphasizes the dispatch, “gating” the weighting. Both must balance load across experts and route consistently, or the model wastes capacity and trains poorly.', 'Same idea as the gating network, described from the dispatch angle.', 'The MoE component computing per-token expert assignments and dispatch weights.', 'Architectures', 60, ARRAY['seed','architectures']::text[]),
  ('tokenizerfree', 'Tokenizer-Free', '', '', ARRAY['tokenizerfree','tokenizer-free','tokenizer free']::text[], 'Rising', 'A model that skips the usual word-chopping step and works straight from raw bytes or characters.', 'Like reading a book letter by letter instead of first breaking it into a fixed dictionary of word-pieces.', 'A tokenizer-free model can handle a weird emoji sequence or a rare language script without choking on “unknown token.”', '[{"text":"A concrete instance of the idea.","id":"bytelevelmodel"},{"text":"The step it removes.","id":"tokenization"}]'::jsonb, 'Normal models first split text into subword tokens using a fixed vocabulary, which struggles with rare words, typos, and unusual scripts. Tokenizer-free models operate on bytes or characters directly, gaining robustness and language-fairness at the cost of longer sequences and more compute. It’s an active bet that removing the brittle tokenizer step is worth the extra cost.', 'Promises better handling of messy, multilingual, or noisy text — still an emerging trade-off.', 'A model operating directly on bytes/characters, eliminating a fixed subword vocabulary.', 'Architectures', 60, ARRAY['seed','architectures']::text[]),
  ('bytelevelmodel', 'Byte-Level Model', '', '', ARRAY['bytelevelmodel','byte-level model','byte level model']::text[], 'Rising', 'A model that treats text as a raw stream of bytes, so nothing is ever “out of vocabulary.”', 'Like a scanner that reads any document as pixels — it never trips over a font or symbol it hasn’t seen.', 'A byte-level model can process a garbled log file full of odd characters without special handling.', '[{"text":"The broader family it belongs to.","id":"tokenizerfree"}]'::jsonb, 'Every piece of text is ultimately bytes, so a byte-level model has a tiny fixed alphabet and can represent literally anything — code, emoji, any language. The price is much longer sequences, since a word becomes many bytes, which strains attention and speed. Architectural tricks that group bytes internally are how researchers try to keep it affordable.', 'Maximum robustness to weird input, paid for in sequence length and compute.', 'A model with a byte vocabulary, trading a fixed small alphabet for longer sequences.', 'Architectures', 60, ARRAY['seed','architectures']::text[]),
  ('hybridarchitecture', 'Hybrid Architecture', '', '', ARRAY['hybridarchitecture','hybrid architecture','hybrid model']::text[], 'Rising', 'A model that mixes different building blocks — say attention plus state-space layers — to get the best of each.', 'Like a hybrid car pairing an electric motor with a gas engine, using whichever suits the moment.', 'Some recent long-context models interleave Mamba-style layers with a few attention layers to stay fast without losing recall.', '[{"text":"One common cheap ingredient in hybrids.","id":"statespacemodel"},{"text":"The pricey-but-precise ingredient.","id":"attention"}]'::jsonb, 'Pure attention is powerful but scales badly with sequence length; alternatives like state-space models are cheaper but weaker at precise recall. Hybrids combine them — mostly cheap layers with a sprinkle of attention — to keep quality high while controlling cost on long inputs. It’s an engineering compromise that’s become popular as context windows balloon.', 'A route to long-context models that don’t blow up in cost or latency.', 'A model interleaving heterogeneous layer types (e.g., attention and SSM) to balance cost and capability.', 'Architectures', 60, ARRAY['seed','architectures']::text[]),
  ('retrievalaugmentedarchitecture', 'Retrieval-Augmented Architecture', '', '', ARRAY['retrievalaugmentedarchitecture','retrieval-augmented architecture']::text[], 'Core', 'A model design that builds document lookup into its structure, so it fetches facts as part of thinking, not as an afterthought.', 'Like a lawyer whose desk is wired to the law library — pulling the right case mid-sentence rather than trusting memory.', 'A support assistant that queries your help-center database on every question, then answers from what it found, is retrieval-augmented by design.', '[{"text":"The technique it’s built around.","id":"rag"},{"text":"The knowledge store it queries.","id":"nonparametricmemory"}]'::jsonb, 'Rather than cramming all knowledge into weights, these models pair a generator with a retriever that pulls relevant text at run time, keeping knowledge fresh and updatable. It’s the architectural home of RAG. The hard parts are retrieving the right chunks and blending them cleanly into generation — bad retrieval quietly poisons good generation.', 'How you keep a model current and grounded without retraining it.', 'An architecture coupling a parametric generator with a non-parametric retrieval component at inference.', 'Architectures', 80, ARRAY['seed','architectures']::text[]),
  ('memoryaugmentednetwork', 'Memory-Augmented Network', '', '', ARRAY['memoryaugmentednetwork','memory-augmented network','memory augmented network']::text[], 'Fading', 'A network bolted onto an external memory it can read from and write to, like a scratchpad it controls.', 'Like giving someone a notebook they can jot into and flip back through, instead of forcing them to hold everything in their head.', 'Early “Neural Turing Machine” research let a network store and recall sequences using a differentiable memory bank.', '[{"text":"The modern, practical descendant of the idea.","id":"retrievalaugmentedarchitecture"}]'::jsonb, 'These architectures separate computation from storage: the network learns to write facts into an addressable memory and read them back later, in principle handling tasks that need long-term recall. They were influential research but tricky to train and were largely overtaken by big transformers with long context and retrieval. The idea of external memory lives on in RAG-style systems.', 'Mostly a research lineage now; its spirit survives in retrieval-based systems.', 'A network with a differentiable external memory supporting learned read/write operations.', 'Architectures', 30, ARRAY['seed','architectures']::text[]),
  ('pointernetwork', 'Pointer Network', '', '', ARRAY['pointernetwork','pointer network','pointer net']::text[], 'Fading', 'A network that answers by pointing back at positions in its input rather than generating brand-new words.', 'Like answering “which of these do you want?” by pointing at items on the table instead of describing them from scratch.', 'For extractive summarization, a pointer network selects which input sentences to copy verbatim.', '[{"text":"The mechanism it repurposes to point.","id":"attention"}]'::jsonb, 'Instead of producing tokens from a fixed vocabulary, it uses attention to point at input elements, which is perfect when the answer is a selection or reordering of the input — sorting, routing, copying exact names. Modern LLMs with copy mechanisms and attention absorbed much of this capability, so pointer networks are now more of a specialized or historical tool.', 'A niche design for tasks that are really about selecting from the input.', 'A seq2seq model whose output distribution is attention over input positions.', 'Architectures', 30, ARRAY['seed','architectures']::text[]),
  ('graphneuralnetwork', 'Graph Neural Network', 'GNN', '', ARRAY['graphneuralnetwork','graph neural network','gnn','gnns']::text[], 'Core', 'A network built for data shaped like a network — nodes and connections — that learns by passing messages between neighbors.', 'Like gossip spreading through a friend group: each person updates their view based on what their direct friends say.', 'Fraud detection systems use GNNs over transaction graphs to spot rings of accounts that look normal alone but suspicious together.', '[{"text":"The sequence-oriented alternative.","id":"transformer"}]'::jsonb, 'Where transformers assume a sequence and CNNs assume a grid, GNNs assume an arbitrary graph, and each node updates itself by aggregating messages from its neighbors over several rounds. That fits molecules, social networks, and recommendation graphs naturally. They’re powerful on relational data but can struggle to pass information across very distant nodes.', 'The right tool when your data is fundamentally about connections, not sequences.', 'A network operating on graph-structured data via iterative neighborhood message passing.', 'Architectures', 80, ARRAY['seed','architectures']::text[]),
  ('embeddinglayer', 'Embedding Layer', '', '', ARRAY['embeddinglayer','embedding layer']::text[], 'Core', 'The first layer that turns each token ID into a vector the rest of the network can actually work with.', 'Like a coat check that swaps your ticket number for the actual coat — the number meant nothing until it fetched the real thing.', 'When token #4021 for “dog” enters a model, the embedding layer looks up its learned 4,096-number vector.', '[{"text":"The vectors it produces.","id":"embeddings"},{"text":"What feeds into it.","id":"tokenization"}]'::jsonb, 'It’s essentially a big lookup table: one learned vector per vocabulary entry, trained alongside everything else. Raw token IDs are meaningless integers; the embedding layer gives each a rich numeric meaning that captures similarity and usage. Everything downstream operates on these vectors, so this humble table is where language first becomes math.', 'The unglamorous doorway where words become numbers the model can reason over.', 'A learned lookup table mapping token IDs to dense vectors, trained jointly with the model.', 'Architectures', 80, ARRAY['seed','architectures']::text[]),
  ('outputhead', 'Output Head', '', '', ARRAY['outputhead','output head','head']::text[], 'Core', 'The final layer that converts the model’s internal thinking into the actual answer — a word, a score, a label.', 'Like the last station on an assembly line that stamps the finished product into its shippable form.', 'A language model’s output head turns its final hidden vector into a probability for every possible next word.', '[{"text":"The next-word variant of it.","id":"languagemodelinghead"},{"text":"The classification variant.","id":"classificationhead"}]'::jsonb, 'The body of the network produces a rich internal representation; the head is the task-specific piece that maps that representation to the output you want. Swap the head and you repurpose the same backbone — one head for next-word prediction, another for classification, another for a numeric score. It’s the interface between general understanding and a specific job.', 'The swappable tip that adapts one pretrained backbone to many tasks.', 'The final projection mapping hidden states to task-specific outputs (logits, labels, scalars).', 'Architectures', 80, ARRAY['seed','architectures']::text[]),
  ('languagemodelinghead', 'Language Modeling Head', 'LM Head', '', ARRAY['languagemodelinghead','language modeling head','lm head']::text[], 'Core', 'The output layer that turns the model’s final state into a probability for every possible next token.', 'Like a spinner over the whole dictionary, weighted so likely next words get the biggest slices.', 'When a chatbot picks its next word, the LM head produced the odds over the vocabulary that the sampler then draws from.', '[{"text":"The general concept it’s a version of.","id":"outputhead"},{"text":"What it produces.","id":"logits"}]'::jsonb, 'It projects the last hidden vector onto the full vocabulary, producing one raw score (logit) per possible token, which softmax turns into probabilities. In many models it shares weights with the embedding layer to save parameters. This head is what makes a model “generative” — everything else builds the state, this turns it into a next-word bet.', 'The component that literally decides the odds behind every generated word.', 'A linear projection from hidden state to vocabulary logits, often tied to the embedding matrix.', 'Architectures', 80, ARRAY['seed','architectures']::text[]),
  ('classificationhead', 'Classification Head', '', '', ARRAY['classificationhead','classification head']::text[], 'Core', 'A small output layer that maps the model’s understanding to a choice among fixed categories.', 'Like the final judge at a science fair who takes all the deliberation and stamps one ribbon: first, second, or third.', 'A spam filter puts a classification head on a text encoder to output “spam” or “not spam.”', '[{"text":"The general concept it’s a version of.","id":"outputhead"},{"text":"How the input gets summarized for it.","id":"pooling"}]'::jsonb, 'It takes a pooled representation of the input and projects it to one score per class, with the highest score winning. You can bolt it onto a frozen or fine-tuned backbone to specialize a general model for a specific labeling task. It’s the standard way to turn an understanding model into a decision-maker.', 'The cheap add-on that turns a language model into a categorizer.', 'A projection from a pooled representation to per-class logits for a fixed label set.', 'Architectures', 80, ARRAY['seed','architectures']::text[]),
  ('pooling', 'Pooling', '', '', ARRAY['pooling']::text[], 'Core', 'Squashing a whole sequence of vectors into a single vector that stands for the entire input.', 'Like summarizing a long meeting into one sentence — you collapse many points into one takeaway.', 'To classify a review, a model pools the per-word vectors into one “whole-review” vector before the classification head.', '[{"text":"The most common averaging variant.","id":"meanpooling"},{"text":"A dedicated summary-token approach.","id":"clstoken"}]'::jsonb, 'Networks produce one vector per token, but many tasks need a single representation of the entire input. Pooling combines them — by averaging, taking the max, or reading a special summary token. The method matters: averaging is robust but blurry, while a dedicated summary token can learn to focus on what counts. It’s the bridge from per-token detail to one whole-input meaning.', 'The step that turns “many word-vectors” into one thing you can score or search on.', 'An aggregation over token representations (mean/max/CLS) producing a fixed-size vector.', 'Architectures', 80, ARRAY['seed','architectures']::text[]),
  ('meanpooling', 'Mean Pooling', '', '', ARRAY['meanpooling','mean pooling','average pooling']::text[], 'Core', 'The simplest way to summarize a sequence: just average all the token vectors together.', 'Like taking the average grade of a class to represent how the class did overall.', 'Many sentence-embedding models mean-pool a sentence’s word vectors to get one vector for search.', '[{"text":"The general operation it’s a case of.","id":"pooling"},{"text":"What it’s commonly used to build.","id":"sentenceembedding"}]'::jsonb, 'You add up every token’s vector and divide by the count, giving equal weight to each. It’s cheap, stable, and surprisingly effective for embeddings, though it can wash out a crucial word by drowning it in the average. When every token matters roughly equally, mean pooling is hard to beat for its simplicity.', 'A dependable default for turning text into one searchable vector.', 'Elementwise averaging of token vectors, often masked to ignore padding.', 'Architectures', 80, ARRAY['seed','architectures']::text[]),
  ('clstoken', 'CLS Token', 'Classification Token', '', ARRAY['clstoken','cls token','classification token','[cls]']::text[], 'Fading', 'A special slot added to the front of the input whose final vector is trained to summarize the whole thing.', 'Like a designated note-taker who sits in on the whole meeting so you can just read their one summary afterward.', 'BERT prepends a [CLS] token and uses its output vector as the sentence representation for classification.', '[{"text":"The model that made it famous.","id":"bert"},{"text":"The broader operation it competes with.","id":"pooling"}]'::jsonb, 'You prepend a dummy token that carries no word meaning; because attention lets it look at everything, it learns during training to gather a useful summary of the whole sequence into its final vector. It’s the classic trick in encoder models like BERT. Newer decoder-only models often rely on the last token or pooling instead, so it’s fading from the spotlight.', 'A tidy way older models produced one “whole-input” vector; less common now.', 'A prepended token whose final hidden state serves as an aggregate sequence representation.', 'Architectures', 30, ARRAY['seed','architectures']::text[]),
  ('contextparallelism', 'Context Parallelism', '', '', ARRAY['contextparallelism','context parallelism','sequence parallelism']::text[], 'Rising', 'Splitting one very long input across multiple GPUs so no single chip has to hold the whole sequence.', 'Like several people each reading a different third of a huge document, then comparing notes to understand the whole.', 'Training a model on a 1-million-token context often splits that sequence across many GPUs via context parallelism.', '[{"text":"The sibling that splits the math within a layer.","id":"tensorparallelism"},{"text":"The sibling that splits layers across devices.","id":"pipelineparallelism"}]'::jsonb, 'Attention over very long sequences needs enormous memory, more than one GPU has. Context parallelism shards the sequence dimension across devices, so each holds part of the tokens, and they exchange the pieces of attention that cross boundaries. It’s one of several parallelism strategies that make long-context and large-model training possible at all.', 'Part of the plumbing that makes million-token context windows feasible to train.', 'Sharding the sequence dimension across devices, with communication for cross-shard attention.', 'Architectures', 60, ARRAY['seed','architectures']::text[]),
  ('tensorparallelism', 'Tensor Parallelism', '', '', ARRAY['tensorparallelism','tensor parallelism']::text[], 'Core', 'Splitting a single layer’s math across several GPUs so they compute one big matrix multiply together.', 'Like four cashiers ringing up different halves of one giant order at the same time, then combining the totals.', 'Serving a model too big for one GPU often splits each layer’s weight matrices across 4 or 8 GPUs.', '[{"text":"The broader family of splitting techniques.","id":"modelparallelism"},{"text":"The sibling that splits layers instead.","id":"pipelineparallelism"}]'::jsonb, 'Within a layer, the big weight matrices are chopped into pieces spread across GPUs; each computes its slice and the results are combined with fast interconnect communication. It lets a model whose weights don’t fit on one chip run across several as if it were one. The cost is heavy inter-GPU chatter, so it wants very fast links between the chips.', 'A core reason big models need tightly-networked multi-GPU servers to run.', 'Partitioning weight matrices within layers across devices, with all-reduce/all-gather to combine.', 'Architectures', 80, ARRAY['seed','architectures']::text[]),
  ('pipelineparallelism', 'Pipeline Parallelism', '', '', ARRAY['pipelineparallelism','pipeline parallelism']::text[], 'Core', 'Putting different layers of the model on different GPUs, like stations on an assembly line.', 'Like a car factory where each station adds one part — the car moves down the line and every station stays busy on a different vehicle.', 'A 100-layer model might put layers 1–25 on GPU A, 26–50 on GPU B, and so on, passing activations along.', '[{"text":"The broader family it belongs to.","id":"modelparallelism"},{"text":"The sibling that splits within a layer.","id":"tensorparallelism"}]'::jsonb, 'The model is cut into consecutive stages, each on its own device, and data flows through them in sequence. To keep every stage busy rather than idle-waiting, batches are split into micro-batches that flow through in a staggered pipeline. The tricky bit is the “bubble” of idle time at the start and end, which good scheduling minimizes.', 'One of the standard ways to spread a model too large for a single GPU.', 'Partitioning layers into sequential stages across devices, overlapped via micro-batching.', 'Architectures', 80, ARRAY['seed','architectures']::text[]),
  ('modelparallelism', 'Model Parallelism', '', '', ARRAY['modelparallelism','model parallelism']::text[], 'Core', 'Spreading one model across many GPUs when it’s simply too big to fit on a single chip.', 'Like a mural too large for one wall, painted across several walls that together make the whole picture.', 'A frontier model with hundreds of billions of parameters can’t fit on one GPU, so it’s split with model parallelism.', '[{"text":"A within-layer form.","id":"tensorparallelism"},{"text":"An across-layer form.","id":"pipelineparallelism"}]'::jsonb, 'It’s the umbrella term for dividing a model’s parameters and computation across devices, whether by splitting within layers (tensor), across layers (pipeline), or across the sequence (context). It contrasts with data parallelism, where each GPU holds a full copy and just processes different examples. Modern training stacks combine several of these at once.', 'The general reason frontier models demand racks of interconnected GPUs.', 'Distributing model parameters/compute across devices; contrast with data parallelism.', 'Architectures', 80, ARRAY['seed','architectures']::text[]),
  ('attentionsink', 'Attention Sink', '', '', ARRAY['attentionsink','attention sink','attention sinks']::text[], 'Rising', 'The odd habit models have of dumping spare attention onto the very first token, using it as a parking spot.', 'Like a conversation where everyone reflexively glances at the person at the head of the table, whether or not they’re relevant.', 'Researchers found that keeping the first few tokens in the cache preserves quality in long streaming generation — because they’re acting as sinks.', '[{"text":"The mechanism where it emerges.","id":"attention"},{"text":"The cache these tokens must stay in.","id":"kvcache"}]'::jsonb, 'Attention weights must sum to one, so when a token has nothing important to focus on, the model learns to offload that leftover attention somewhere harmless — usually the first token. Understanding this fixed a real bug: naively dropping early tokens in long conversations wrecked models until people realized those tokens were load-bearing sinks. It’s a small quirk with outsized practical impact.', 'An obscure detail that quietly governs whether long, streaming chats stay coherent.', 'The tendency of softmax attention to allocate residual mass to initial tokens, aiding long-context stability.', 'Architectures', 60, ARRAY['seed','architectures']::text[]),
  ('longcontextarchitecture', 'Long-Context Architecture', '', '', ARRAY['longcontextarchitecture','long-context architecture','long context model']::text[], 'Rising', 'Design choices that let a model read hundreds of thousands of tokens without its cost or memory exploding.', 'Like redesigning a library so you can pull from a whole wing at once, not just the shelf beside your desk.', 'Models that accept an entire codebase or a long book in one prompt rely on long-context architecture tricks.', '[{"text":"The failure it fights against.","id":"lostinthemiddle"},{"text":"A cheaper attention pattern it may use.","id":"slidingwindowattention"}]'::jsonb, 'Plain attention cost grows with the square of the sequence length, so naively long contexts become impossibly expensive. Long-context designs use sparse or windowed attention, better positional schemes, cheaper layer types, and specialized caching to keep it tractable. The hard part isn’t just fitting the tokens — it’s making the model actually use information buried in the middle.', 'What lets your product paste in whole documents instead of chunking everything.', 'Architectural techniques (sparse attention, position schemes, caching) mitigating quadratic attention cost.', 'Architectures', 60, ARRAY['seed','architectures']::text[]),
  ('sparsemixture', 'Sparse Mixture', 'Sparse Mixture of Experts', '', ARRAY['sparsemixture','sparse mixture','sparse moe']::text[], 'Rising', 'A mixture-of-experts model where only a few experts fire per token, keeping a giant model cheap to run.', 'Like a huge consulting firm where any one question only pulls in two specialists, not the entire staff.', 'A model with 100 billion total parameters but only 12 billion active per token is a sparse mixture.', '[{"text":"The general model class.","id":"mixtureofexperts"},{"text":"The always-on opposite.","id":"densetransformer"}]'::jsonb, '“Sparse” means each token activates just a small subset of the experts, so total capacity can be enormous while per-token compute stays modest. This decouples a model’s knowledge (total params) from its running cost (active params). The trade-offs are memory to hold all the experts and the routing quality that decides which few actually run.', 'How a model can be “huge” in capability yet still affordable per token.', 'An MoE with top-k expert activation, decoupling total from active parameters.', 'Architectures', 60, ARRAY['seed','architectures']::text[]),
  ('densetransformer', 'Dense Transformer', '', '', ARRAY['densetransformer','dense transformer','dense architecture']::text[], 'Core', 'The classic transformer where every token passes through every parameter — no experts, no skipping.', 'Like a restaurant where every dish goes through the entire kitchen staff, not a specialized station.', 'Most well-known models before the mixture-of-experts wave were dense transformers.', '[{"text":"The sparse alternative.","id":"sparsemixture"},{"text":"The architecture it’s a form of.","id":"transformer"}]'::jsonb, 'In a dense model, all weights are active for every token, so compute per token scales directly with model size. It’s simpler to train and reason about than sparse mixtures, with no routing to get wrong, but it can’t grow its knowledge without paying full price on every token. It’s the baseline against which sparse designs are measured.', 'The straightforward, predictable model shape — capability and cost rise together.', 'A transformer with all parameters active per token; contrast with sparse MoE.', 'Architectures', 80, ARRAY['seed','architectures']::text[]),
  ('encoderonly', 'Encoder-Only', '', '', ARRAY['encoderonly','encoder-only','encoder only']::text[], 'Fading', 'A transformer that only reads and understands text — no generation half at all.', 'Like a book reviewer who deeply understands a manuscript but was never hired to write one.', 'BERT is the poster child: brilliant at classification and search, incapable of writing a paragraph.', '[{"text":"The canonical example.","id":"bert"},{"text":"The generation-focused opposite.","id":"gptarchitecture"}]'::jsonb, 'It keeps only the encoder stack, reading the whole input at once (bidirectionally) to build rich representations, and is trained by predicting masked-out words. That makes it strong and cheap for understanding tasks but unable to generate freely. As generative chat models took over, encoder-only fell out of fashion, though it still powers plenty of search and embedding work.', 'A lean, fast choice when you only need to understand or classify, not generate.', 'A transformer using only the encoder stack, trained bidirectionally for representation tasks.', 'Architectures', 30, ARRAY['seed','architectures']::text[]),
  ('bidirectionalmodel', 'Bidirectional Model', '', '', ARRAY['bidirectionalmodel','bidirectional model','bidirectional']::text[], 'Fading', 'A model that reads each word using context from both its left and its right at the same time.', 'Like understanding a pun only after you’ve read the whole sentence, not word by word as it arrives.', 'To fill in “the ___ barked,” a bidirectional model uses “barked” on the right to guess “dog.”', '[{"text":"The one-directional counterpart.","id":"causallanguagemodel"},{"text":"The task it’s trained with.","id":"maskedlanguagemodel"}]'::jsonb, 'Because it sees the full sentence at once, it can use future words to interpret earlier ones, which is great for understanding but incompatible with left-to-right generation. That’s why bidirectional models like BERT dominate comprehension tasks while generative chatbots use one-directional (causal) attention. The direction of attention is the whole difference.', 'Superb for understanding tasks; structurally unable to generate text on its own.', 'A model with unmasked attention, conditioning each position on the full sequence.', 'Architectures', 30, ARRAY['seed','architectures']::text[]),
  ('causallanguagemodel', 'Causal Language Model', '', '', ARRAY['causallanguagemodel','causal language model','causal lm']::text[], 'Core', 'A model that can only look leftward — predicting each word from the words before it, never after.', 'Like writing a story with a card covering everything you haven’t written yet — you decide the next word from what’s already on the page.', 'Every generative chatbot is a causal LM: it produces text one token at a time, each based only on what came before.', '[{"text":"The masking that enforces it.","id":"causalattention"},{"text":"The both-directions opposite.","id":"bidirectionalmodel"}]'::jsonb, '“Causal” means the attention is masked so a token can attend to earlier positions but not future ones, which is exactly what lets the model generate text left to right. It’s the standard setup for GPT-style models. The constraint is also its power: by never peeking ahead, it can be trained on plain text and then generate coherently.', 'The default shape of any model that writes, chats, or completes text.', 'A model with causal (left-to-right) attention masking, trained on next-token prediction.', 'Architectures', 80, ARRAY['seed','architectures']::text[]),
  ('maskedlanguagemodel', 'Masked Language Model', 'MLM', '', ARRAY['maskedlanguagemodel','masked language model','mlm']::text[], 'Fading', 'A training trick where you hide random words and make the model guess them from the words around them.', 'Like a fill-in-the-blank exercise — “The cat sat on the ___” — where you deduce the answer from the rest.', 'BERT was trained by masking about 15% of words in each sentence and predicting each one.', '[{"text":"The model type it trains.","id":"bert"},{"text":"The generative training objective it contrasts with.","id":"nexttokenprediction"}]'::jsonb, 'By blanking out tokens and asking the model to recover them using both left and right context, MLM teaches deep bidirectional understanding without needing labeled data. It’s the training objective behind encoder models, but it doesn’t naturally produce a text generator. Next-token prediction won out for generative models precisely because it does.', 'The learning recipe behind understanding-focused models, not chatbots.', 'A self-supervised objective predicting masked tokens from bidirectional context.', 'Architectures', 30, ARRAY['seed','architectures']::text[]),
  ('prefixlm', 'Prefix LM', 'Prefix Language Model', '', ARRAY['prefixlm','prefix lm','prefix language model']::text[], 'Fading', 'A hybrid that reads the prompt with full both-directions attention but then generates the answer left to right.', 'Like studying a question from every angle before you start writing your essay strictly top to bottom.', 'Some instruction-tuned models let the whole prompt attend freely, then switch to causal mode for the response.', '[{"text":"The generate-only counterpart.","id":"causallanguagemodel"},{"text":"The understand-only counterpart.","id":"bidirectionalmodel"}]'::jsonb, 'It splits the sequence: the prefix (input) uses bidirectional attention so the model understands it fully, while the continuation (output) uses causal attention so it can be generated. This aims to combine strong comprehension of the prompt with the ability to generate. It sits between pure encoder-decoder and pure decoder-only designs, and stayed a niche as decoder-only models dominated.', 'A middle-ground design; most products just use plain decoder-only models instead.', 'A model applying bidirectional attention over the prefix and causal attention over the continuation.', 'Architectures', 30, ARRAY['seed','architectures']::text[]),
  ('speculativearchitecture', 'Speculative Architecture', 'Speculative Decoding', '', ARRAY['speculativearchitecture','speculative architecture','speculative decoding']::text[], 'Rising', 'A speed trick where a tiny fast model guesses several next words and a big model just checks them in one pass.', 'Like a junior drafts a few sentences and the senior editor approves or fixes them in a single quick read — faster than the senior writing every word.', 'A serving stack might use a small draft model to propose 4 tokens, then have the big model verify all 4 at once.', '[{"text":"The small model doing the guessing.","id":"draftmodel"}]'::jsonb, 'The big model normally makes tokens one slow step at a time. Here a cheap draft model proposes a short run of tokens, and the big model verifies them in parallel, accepting the ones it agrees with and correcting at the first disagreement. Output is identical to the big model alone, just produced faster — pure latency savings with no quality loss.', 'A way to make responses noticeably faster and cheaper with no drop in answer quality.', 'Parallel verification of a small draft model’s proposed tokens by the target model, preserving its distribution.', 'Architectures', 60, ARRAY['seed','architectures']::text[]),
  ('draftmodel', 'Draft Model', '', '', ARRAY['draftmodel','draft model','drafter']::text[], 'Rising', 'The small, fast model that proposes candidate next words for a bigger model to check.', 'Like an intern who quickly sketches the next few lines so the expert only has to review, not write from scratch.', 'In speculative decoding, a 1-billion-parameter draft model guesses tokens that a 70-billion-parameter model then verifies.', '[{"text":"The technique it powers.","id":"speculativearchitecture"}]'::jsonb, 'It needs to be fast and roughly agree with the big model, since every token the big model rejects is wasted draft work. The closer the draft’s guesses match the target, the more speedup you get. Choosing or training a good draft model — fast enough to help, aligned enough to be accepted — is the core engineering knob of speculative decoding.', 'The cheap helper that makes the expensive model respond faster.', 'A lightweight model proposing tokens for parallel verification by the target model.', 'Architectures', 60, ARRAY['seed','architectures']::text[]),
  ('moerouting', 'MoE Routing', '', '', ARRAY['moerouting','moe routing','mixture-of-experts routing']::text[], 'Rising', 'The overall strategy for deciding which experts each token visits and keeping the load balanced across them.', 'Like a dispatcher assigning delivery jobs to drivers — route by expertise, but don’t leave some drivers idle and others swamped.', 'A model card might report “top-2 routing with a load-balancing loss” to describe its MoE routing scheme.', '[{"text":"The component that executes it.","id":"routernetwork"},{"text":"The model class it serves.","id":"sparsemixture"}]'::jsonb, 'Routing covers both the per-token choice (which top-k experts) and the system-level concern of spreading tokens evenly so no expert is overwhelmed or neglected. Poor routing causes wasted capacity, unstable training, and “dead” experts. Techniques like auxiliary balancing losses and capacity limits exist mostly to keep routing healthy at scale.', 'The design detail that decides whether a sparse model’s promised efficiency actually materializes.', 'The policy and losses governing top-k expert selection and load balancing in MoE layers.', 'Architectures', 60, ARRAY['seed','architectures']::text[])
